{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "modnet": {
    "contentType": "health",
    "structure": "steps",
    "mechanics": ["track", "chart"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber'

export type MealEntry = {
  id: string
  name: string
  calories: number
  categories: FoodCategory[]
  timestamp: string // ISO 8601
}

export type DailyLog = {
  date: string // YYYY-MM-DD
  meals: MealEntry[]
}

export type UserSettings = {
  dailyCalorieGoal: number
}

export type DaySummary = {
  date: string
  totalCalories: number
  goalCalories: number
  meals: MealEntry[]
}

export type WeekSummary = {
  days: {
    date: string
    label: string
    totalCalories: number
  }[]
  goalCalories: number
  maxCalories: number
}

export type AppView = 'log' | 'daily' | 'weekly'

import type { MealEntry, DailyLog, UserSettings } from './types'

const DATA_DIR = import.meta.dir + '/data'
const MEALS_FILE = `${DATA_DIR}/meals.json`
const SETTINGS_FILE = `${DATA_DIR}/settings.json`

const DEFAULT_SETTINGS: UserSettings = {
  dailyCalorieGoal: 2000,
}

// --- Settings ---

export const loadSettings = async (): Promise<UserSettings> => {
  const file = Bun.file(SETTINGS_FILE)
  if (await file.exists()) {
    return file.json()
  }
  return { ...DEFAULT_SETTINGS }
}

export const saveSettings = async (settings: UserSettings): Promise<void> => {
  await Bun.write(SETTINGS_FILE, JSON.stringify(settings, null, 2))
}

// --- Meals ---

export const loadAllMeals = async (): Promise<MealEntry[]> => {
  const file = Bun.file(MEALS_FILE)
  if (await file.exists()) {
    return file.json()
  }
  return []
}

export const saveAllMeals = async (meals: MealEntry[]): Promise<void> => {
  await Bun.write(MEALS_FILE, JSON.stringify(meals, null, 2))
}

export const addMeal = async (meal: MealEntry): Promise<void> => {
  const meals = await loadAllMeals()
  meals.push(meal)
  await saveAllMeals(meals)
}

export const deleteMeal = async (id: string): Promise<void> => {
  const meals = await loadAllMeals()
  const filtered = meals.filter((m) => m.id !== id)
  await saveAllMeals(filtered)
}

// --- Queries ---

export const getMealsForDate = async (date: string): Promise<MealEntry[]> => {
  const meals = await loadAllMeals()
  return meals.filter((m) => m.timestamp.startsWith(date))
}

export const getDailyLogs = async (dates: string[]): Promise<DailyLog[]> => {
  const meals = await loadAllMeals()
  return dates.map((date) => ({
    date,
    meals: meals.filter((m) => m.timestamp.startsWith(date)),
  }))
}

import type { MealEntry, DaySummary, WeekSummary } from './types'
import { getMealsForDate, getDailyLogs, loadSettings } from './data'

const toDateString = (d: Date): string =>
  d.toISOString().split('T')[0]

const getDayLabel = (dateStr: string): string => {
  const d = new Date(dateStr + 'T12:00:00')
  return d.toLocaleDateString('en-US', { weekday: 'short' })
}

export const getTodayString = (): string => toDateString(new Date())

export const getDaySummary = async (date: string): Promise<DaySummary> => {
  const [meals, settings] = await Promise.all([
    getMealsForDate(date),
    loadSettings(),
  ])
  const totalCalories = meals.reduce((sum, m) => sum + m.calories, 0)
  return {
    date,
    totalCalories,
    goalCalories: settings.dailyCalorieGoal,
    meals,
  }
}

export const getWeekSummary = async (): Promise<WeekSummary> => {
  const today = new Date()
  const dates: string[] = []
  for (let i = 6; i >= 0; i--) {
    const d = new Date(today)
    d.setDate(d.getDate() - i)
    dates.push(toDateString(d))
  }

  const [logs, settings] = await Promise.all([
    getDailyLogs(dates),
    loadSettings(),
  ])

  const days = logs.map((log) => {
    const totalCalories = log.meals.reduce((sum, m) => sum + m.calories, 0)
    return {
      date: log.date,
      label: getDayLabel(log.date),
      totalCalories,
    }
  })

  const maxCalories = Math.max(
    settings.dailyCalorieGoal,
    ...days.map((d) => d.totalCalories),
  )

  return {
    days,
    goalCalories: settings.dailyCalorieGoal,
    maxCalories,
  }
}

export const generateMealId = (): string =>
  crypto.randomUUID()

import { h, Fragment } from 'plaited'
import type { FoodCategory, MealEntry, DaySummary, WeekSummary, AppView } from './types'

