const CATEGORY_COLORS: Record<FoodCategory, string> = {
  protein: '#e74c3c',
  carbs: '#f39c12',
  fat: '#9b59b6',
  fiber: '#27ae60',
}

// --- Components ---

const renderCategoryTag = (cat: FoodCategory, selected: boolean) =>
  h('span', {
    style: {
      ...styles.categoryTag,
      backgroundColor: selected ? CATEGORY_COLORS[cat] : '#fff',
      color: selected ? '#fff' : CATEGORY_COLORS[cat],
      borderColor: CATEGORY_COLORS[cat],
    },
    'p-trigger': `toggle-category:${cat}`,
  }, cat)

const renderMealItem = (meal: MealEntry) =>
  h('div', { style: styles.mealItem },
    h('div', {},
      h('div', { style: { fontWeight: '600', fontSize: '14px' } }, meal.name),
      h('div', { style: { fontSize: '12px', color: '#666', marginTop: '2px' } },
        meal.categories.map((cat) =>
          h('span', {
            style: {
              ...styles.categoryTag,
              backgroundColor: CATEGORY_COLORS[cat],
              color: '#fff',
              cursor: 'default',
              fontSize: '10px',
              padding: '1px 8px',
            },
          }, cat),
        ),
      ),
      h('div', { style: { fontSize: '11px', color: '#999', marginTop: '2px' } },
        new Date(meal.timestamp).toLocaleTimeString('en-US', {
          hour: 'numeric',
          minute: '2-digit',
        }),
      ),
    ),
    h('div', { style: { display: 'flex', alignItems: 'center', gap: '8px' } },
      h('span', { style: { fontWeight: '700', fontSize: '14px' } }, `${meal.calories} cal`),
      h('button', { style: styles.deleteBtn, 'p-trigger': `delete-meal:${meal.id}` }, '\u00d7'),
    ),
  )

const renderProgressBar = (current: number, goal: number) => {
  const pct = Math.min((current / goal) * 100, 100)
  const color = current > goal ? '#e74c3c' : current > goal * 0.8 ? '#f39c12' : '#4361ee'
  return h('div', {},
    h('div', { style: { display: 'flex', justifyContent: 'space-between', fontSize: '13px', marginBottom: '4px' } },
      h('span', {}, `${current} cal`),
      h('span', { style: { color: '#999' } }, `Goal: ${goal} cal`),
    ),
    h('div', { style: styles.progressBar },
      h('div', {
        style: {
          width: `${pct}%`,
          height: '100%',
          backgroundColor: color,
          borderRadius: '6px',
          transition: 'width 0.3s ease',
        },
      }),
    ),
  )
}

// --- Views ---

export const renderLogView = (categories: FoodCategory[]) =>
  h('div', { style: styles.card },
    h('h3', { style: styles.sectionTitle }, 'Log a Meal'),
    h('input', {
      style: styles.input,
      type: 'text',
      placeholder: 'Food name (e.g., Grilled Chicken)',
      'p-target': 'food-name',
    }),
    h('input', {
      style: { ...styles.input, width: '100%' },
      type: 'number',
      placeholder: 'Calories',
      min: '0',
      'p-target': 'food-calories',
