    h('div', { style: { marginBottom: '12px' } },
      h('div', { style: { fontSize: '13px', color: '#666', marginBottom: '6px' } }, 'Categories:'),
      ...(['protein', 'carbs', 'fat', 'fiber'] as FoodCategory[]).map((cat) =>
        renderCategoryTag(cat, categories.includes(cat)),
      ),
    ),
    h('button', { style: styles.submitBtn, 'p-trigger': 'submit-meal' }, 'Add Meal'),
  )

export const renderDailyView = (summary: DaySummary) =>
  h('div', {},
    h('div', { style: styles.card },
      h('h3', { style: styles.sectionTitle }, `Today \u2014 ${summary.date}`),
      renderProgressBar(summary.totalCalories, summary.goalCalories),
    ),
    h('div', { style: styles.card },
      h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' } },
        h('h3', { style: { ...styles.sectionTitle, margin: '0' } }, 'Meals'),
        h('span', { style: { fontSize: '13px', color: '#999' } }, `${summary.meals.length} entries`),
      ),
      summary.meals.length === 0
        ? h('p', { style: { color: '#999', fontSize: '14px', textAlign: 'center', padding: '16px 0' } },
            'No meals logged yet today.',
          )
        : h(Fragment, {},
            ...summary.meals
              .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())
              .map(renderMealItem),
          ),
    ),
  )

export const renderWeeklyChart = (week: WeekSummary) => {
  const barMaxHeight = 160
  return h('div', { style: styles.card },
    h('h3', { style: styles.sectionTitle }, 'Weekly Overview'),
    h('div', { style: { ...styles.chartContainer, position: 'relative' } },
      // Goal line
      week.maxCalories > 0
        ? h('div', {
            style: {
              position: 'absolute',
              bottom: `${(week.goalCalories / week.maxCalories) * barMaxHeight + 22}px`,
              left: '0',
              right: '0',
              borderTop: '2px dashed #e74c3c',
              opacity: '0.5',
            },
          })
        : null,
      ...week.days.map((day) => {
        const barHeight =
          week.maxCalories > 0
            ? Math.max((day.totalCalories / week.maxCalories) * barMaxHeight, 2)
            : 2
        const isOverGoal = day.totalCalories > week.goalCalories
        return h('div', { style: styles.chartDay },
          h('span', { style: styles.chartValue },
            day.totalCalories > 0 ? `${day.totalCalories}` : '',
          ),
          h('div', {
            style: {
              width: '100%',
              maxWidth: '48px',
              height: `${barHeight}px`,
              backgroundColor: isOverGoal ? '#e74c3c' : '#4361ee',
              borderRadius: '4px 4px 0 0',
              transition: 'height 0.3s ease',
              minHeight: '2px',
            },
          }),
          h('span', { style: styles.chartLabel }, day.label),
        )
      }),
    ),
    h('div', {
      style: {
        display: 'flex',
        justifyContent: 'center',
        gap: '16px',
        fontSize: '11px',
        color: '#999',
        marginTop: '4px',
      },
    },
      h('span', {},
        h('span', { style: { display: 'inline-block', width: '10px', height: '10px', backgroundColor: '#4361ee', borderRadius: '2px', marginRight: '4px' } }),
        'Under goal',
      ),
      h('span', {},
        h('span', { style: { display: 'inline-block', width: '10px', height: '10px', backgroundColor: '#e74c3c', borderRadius: '2px', marginRight: '4px' } }),
        'Over goal',
      ),
      h('span', {},
        h('span', { style: { display: 'inline-block', width: '10px', height: '2px', borderTop: '2px dashed #e74c3c', marginRight: '4px', verticalAlign: 'middle' } }),
        `Goal (${week.goalCalories})`,
      ),
    ),
  )
}

export const renderGoalSetting = (currentGoal: number) =>
  h('div', { style: styles.card },
    h('h3', { style: styles.sectionTitle }, 'Daily Calorie Goal'),
    h('div', { style: styles.goalInput },
      h('input', {
        style: { ...styles.input, marginBottom: '0', flex: '1' },
        type: 'number',
        min: '0',
        step: '100',
        value: String(currentGoal),
        'p-target': 'goal-input',
      }),
      h('span', { style: { fontSize: '14px', color: '#666' } }, 'cal/day'),
    ),
    h('button', {
      style: { ...styles.submitBtn, marginTop: '8px' },
      'p-trigger': 'update-goal',
    }, 'Update Goal'),
  )

export const renderApp = (
  view: AppView,
  content: ReturnType<typeof h>,
) =>
  h('div', { style: styles.container },
    h('div', { style: styles.header },
      h('h1', { style: styles.title }, 'Diet Tracker'),
      h('div', { style: styles.nav },
        h('button', {
          style: view === 'log' ? styles.navBtnActive : styles.navBtn,
          'p-trigger': 'nav:log',
        }, 'Log'),
        h('button', {
          style: view === 'daily' ? styles.navBtnActive : styles.navBtn,
          'p-trigger': 'nav:daily',
        }, 'Today'),
        h('button', {
          style: view === 'weekly' ? styles.navBtnActive : styles.navBtn,
          'p-trigger': 'nav:weekly',
        }, 'Week'),
      ),
    ),
    content,
  )

import { h, Fragment } from 'plaited'
import type { FoodCategory, MealEntry, AppView } from './types'
import { loadSettings, saveSettings, addMeal, deleteMeal } from './data'
import { getDaySummary, getWeekSummary, getTodayString, generateMealId } from './calories'
import {
  renderApp,
  renderLogView,
  renderDailyView,
  renderWeeklyChart,
  renderGoalSetting,
} from './render'

// --- State ---

type AppState = {
  view: AppView
  selectedCategories: FoodCategory[]
}

const state: AppState = {
  view: 'log',
  selectedCategories: [],
}

// --- Handlers ---

export const handleNavigation = (view: AppView): void => {
  state.view = view
}

export const handleToggleCategory = (category: FoodCategory): void => {
  const idx = state.selectedCategories.indexOf(category)
  if (idx >= 0) {
    state.selectedCategories.splice(idx, 1)
  } else {
    state.selectedCategories.push(category)
  }
}

export const handleSubmitMeal = async (name: string, calories: number): Promise<MealEntry> => {
  const meal: MealEntry = {
    id: generateMealId(),
    name,
    calories,
    categories: [...state.selectedCategories],
    timestamp: new Date().toISOString(),
  }
  await addMeal(meal)
  state.selectedCategories = []
  return meal
}

export const handleDeleteMeal = async (id: string): Promise<void> => {
  await deleteMeal(id)
}

export const handleUpdateGoal = async (goal: number): Promise<void> => {
  const settings = await loadSettings()
  settings.dailyCalorieGoal = goal
  await saveSettings(settings)
}

// --- Render ---

export const render = async (): Promise<ReturnType<typeof h>> => {
  const today = getTodayString()

  switch (state.view) {
    case 'log': {
      const settings = await loadSettings()
      const content = h(Fragment, {},
        renderLogView(state.selectedCategories),
        renderGoalSetting(settings.dailyCalorieGoal),
      )
      return renderApp('log', content)
    }
    case 'daily': {
      const summary = await getDaySummary(today)
      return renderApp('daily', renderDailyView(summary))
    }
    case 'weekly': {
      const week = await getWeekSummary()
      return renderApp('weekly', renderWeeklyChart(week))
    }
  }
}

// --- Route handler ---

export const handleTrigger = async (trigger: string, payload?: Record<string, string>): Promise<void> => {
  const [action, value] = trigger.split(':')

  switch (action) {
    case 'nav':
      handleNavigation(value as AppView)
      break
    case 'toggle-category':
      handleToggleCategory(value as FoodCategory)
      break
    case 'submit-meal':
      if (payload?.['food-name'] && payload?.['food-calories']) {
        await handleSubmitMeal(
          payload['food-name'],
          parseInt(payload['food-calories'], 10),
        )
      }
      break
    case 'delete-meal':
      if (value) {
        await handleDeleteMeal(value)
      }
      break
    case 'update-goal':
      if (payload?.['goal-input']) {
        await handleUpdateGoal(parseInt(payload['goal-input'], 10))
      }
      break
  }
}

export { state }

import { createSSR } from 'plaited'
import { render, handleTrigger } from './index'

const ssr = createSSR()

const toHtml = async (): Promise<string> => {
  const tree = await render()
  return ssr(tree)
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (req.method === 'GET' && url.pathname === '/') {
      const html = await toHtml()
      return new Response(
        `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Diet Tracker</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #f0f0f5; padding: 24px; min-height: 100vh; }
  </style>
</head>
<body>
  ${html}
</body>
</html>`,
        { headers: { 'Content-Type': 'text/html' } },
      )
    }

    if (req.method === 'POST' && url.pathname === '/api/trigger') {
      const body = await req.json() as { trigger: string; payload?: Record<string, string> }
      await handleTrigger(body.trigger, body.payload)
      const html = await toHtml()
      return Response.json({ html })
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Diet Tracker running at http://localhost:${server.port}`)

{
  "name": "@node/expense-logger",
  "version": "1.0.0",
  "description": "Track expenses by category with monthly summaries, pie charts, filtering, and CSV export",
  "modnet": {
    "contentType": "finance",
    "structure": "collection",
    "mechanics": ["filter", "chart", "track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import type { Expense, ExpenseFilter, MonthlySummary, Category, CategorySummary } from './types'
import { CATEGORIES } from './types'

const DATA_PATH = './data/expenses.jsonl'

const generateId = (): string => crypto.randomUUID()

export const readExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Expense)
}

export const addExpense = async (
  amount: number,
  category: Category,
  date: string,
  notes: string = ''
): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(amount * 100) / 100,
    category,
    date,
    notes,
    createdAt: new Date().toISOString(),
  }
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + JSON.stringify(expense) + '\n')
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (expenses: Expense[], filter: ExpenseFilter): Expense[] => {
  return expenses.filter((e) => {
    if (filter.startDate && e.date < filter.startDate) return false
    if (filter.endDate && e.date > filter.endDate) return false
    if (filter.category && e.category !== filter.category) return false
    return true
  })
}

export const getMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))
  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0)

  const categories: CategorySummary[] = CATEGORIES.map((cat) => {
    const catExpenses = monthExpenses.filter((e) => e.category === cat)
    const catTotal = catExpenses.reduce((sum, e) => sum + e.amount, 0)
    return {
      category: cat,
      total: Math.round(catTotal * 100) / 100,
      percentage: total > 0 ? Math.round((catTotal / total) * 1000) / 10 : 0,
      count: catExpenses.length,
    }
  }).filter((c) => c.count > 0)

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  }
}

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.substring(0, 7)))
  return [...months].sort().reverse()
}

import { h } from 'plaited'
import type { CategorySummary } from './types'
import { CATEGORY_COLORS, CATEGORY_LABELS } from './types'

type PieSlice = {
  category: CategorySummary['category']
  percentage: number
  startAngle: number
  endAngle: number
  color: string
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y} Z`
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  }
}

const computeSlices = (categories: CategorySummary[]): PieSlice[] => {
  let currentAngle = 0
  return categories.map((cat) => {
    const sweep = (cat.percentage / 100) * 360
    const slice: PieSlice = {
      category: cat.category,
      percentage: cat.percentage,
      startAngle: currentAngle,
      endAngle: currentAngle + sweep,
      color: CATEGORY_COLORS[cat.category],
    }
    currentAngle += sweep
    return slice
  })
}

export const renderPieChart = (categories: CategorySummary[]) => {
  if (categories.length === 0) {
    return h('p', { style: { color: '#9ca3af', textAlign: 'center', padding: '2rem 0' } }, 'No expenses to chart')
  }

  const cx = 100
  const cy = 100
  const r = 90
  const slices = computeSlices(categories)

  const paths =
    slices.length === 1
      ? [h('circle', { cx: `${cx}`, cy: `${cy}`, r: `${r}`, fill: slices[0].color })]
      : slices.map((slice) =>
          h('path', {
            d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
            fill: slice.color,
          })
        )

  const svg = h(
    'svg',
    {
      viewBox: '0 0 200 200',
      style: { width: '200px', height: '200px', display: 'block', margin: '0 auto' },
    },
    ...paths
  )

  const legend = h(
    'div',
    { style: { display: 'flex', flexWrap: 'wrap', gap: '0.5rem', justifyContent: 'center', marginTop: '1rem' } },
    ...categories.map((cat) =>
      h(
        'div',
        { style: { display: 'flex', alignItems: 'center', gap: '0.25rem', fontSize: '0.8rem' } },
        h('span', {
          style: {
            width: '12px',
            height: '12px',
            borderRadius: '2px',
            backgroundColor: CATEGORY_COLORS[cat.category],
            display: 'inline-block',
          },
        }),
        h('span', {}, `${CATEGORY_LABELS[cat.category]} $${cat.total.toFixed(2)} (${cat.percentage}%)`)
      )
    )
  )

  return h('div', {}, svg, legend)
}

import type { Expense } from './types'
import { CATEGORY_LABELS } from './types'

const escapeCSV = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const exportToCSV = (expenses: Expense[]): string => {
  const header = 'Date,Category,Amount,Notes'
  const rows = expenses
    .sort((a, b) => a.date.localeCompare(b.date))
    .map(
      (e) =>
        `${e.date},${CATEGORY_LABELS[e.category]},${e.amount.toFixed(2)},${escapeCSV(e.notes)}`
    )
  return [header, ...rows].join('\n')
}

