import { createSSR } from 'plaited'
import type { Category, ExpenseFilter } from './types'
import { CATEGORIES } from './types'
import { readExpenses, addExpense, deleteExpense, filterExpenses, getMonthlySummary, getAvailableMonths } from './store'
import { exportToCSV } from './csv'
import {
  renderPage,
  renderAddExpenseForm,
  renderFilterBar,
  renderExpenseList,
  renderMonthlySummary,
  renderMonthSelector,
} from './views'

const ssr = createSSR()

const parseFilter = (url: URL): ExpenseFilter => {
  const filter: ExpenseFilter = {}
  const startDate = url.searchParams.get('startDate')
  const endDate = url.searchParams.get('endDate')
  const category = url.searchParams.get('category')
  if (startDate) filter.startDate = startDate
  if (endDate) filter.endDate = endDate
  if (category && CATEGORIES.includes(category as Category)) {
    filter.category = category as Category
  }
  return filter
}

const handleIndex = async (url: URL) => {
  const allExpenses = await readExpenses()
  const filter = parseFilter(url)
  const filtered = filterExpenses(allExpenses, filter)
  const months = getAvailableMonths(allExpenses)
  const currentMonth = url.searchParams.get('month') ?? months[0] ?? new Date().toISOString().substring(0, 7)
  const summary = getMonthlySummary(allExpenses, currentMonth)

  const content = [
    renderPage([
      { tag: 'h1', attrs: { style: { fontSize: '1.5rem', fontWeight: '700', marginBottom: '1.5rem', color: '#111827' } }, children: ['Expense Logger'] },
      renderAddExpenseForm(),
      renderMonthSelector(months, currentMonth),
      renderMonthlySummary(summary),
      renderFilterBar(filter),
      renderExpenseList(filtered),
    ]),
  ]

  return new Response(ssr(content), {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const handleAddExpense = async (req: Request) => {
  const formData = await req.formData()
  const amount = parseFloat(formData.get('amount') as string)
  const category = formData.get('category') as Category
  const date = formData.get('date') as string
  const notes = (formData.get('notes') as string) ?? ''

  if (isNaN(amount) || amount <= 0 || !CATEGORIES.includes(category) || !date) {
    return new Response('Invalid input', { status: 400 })
  }

  await addExpense(amount, category, date, notes)
  return new Response(null, { status: 303, headers: { Location: '/' } })
}

const handleDelete = async (id: string) => {
  await deleteExpense(id)
  return new Response(null, { status: 303, headers: { Location: '/' } })
}

const handleExportCSV = async (url: URL) => {
  const allExpenses = await readExpenses()
  const filter = parseFilter(url)
  const filtered = filterExpenses(allExpenses, filter)
  const csv = exportToCSV(filtered.length > 0 ? filtered : allExpenses)
  const filename = `expenses-${new Date().toISOString().substring(0, 10)}.csv`

  return new Response(csv, {
    headers: {
      'Content-Type': 'text/csv; charset=utf-8',
      'Content-Disposition': `attachment; filename="${filename}"`,
    },
  })
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    if (path === '/' && req.method === 'GET') {
      return handleIndex(url)
    }

    if (path === '/add' && req.method === 'POST') {
      return handleAddExpense(req)
    }

    if (path.startsWith('/delete/') && req.method === 'POST') {
      const id = path.substring('/delete/'.length)
      return handleDelete(id)
    }

    if (path === '/export/csv') {
      return handleExportCSV(url)
    }

    return new Response('Not found', { status: 404 })
  },
})

console.log(`Expense Logger running at http://localhost:${server.port}`)

