import type { InventoryItem, NewItemInput, UpdateItemInput, BulkImportResult } from './types'

const DATA_PATH = `${import.meta.dir}/data/items.json`

const readItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

const generateId = (): string => crypto.randomUUID()

export const getAllItems = async (): Promise<InventoryItem[]> => {
  return readItems()
}

export const searchItems = async (query: string): Promise<InventoryItem[]> => {
  const items = await readItems()
  const q = query.toLowerCase()
  return items.filter(
    (item) => item.name.toLowerCase().includes(q) || item.sku.toLowerCase().includes(q),
  )
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.sku === sku)
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await readItems()
  return items.filter((item) => item.quantity <= item.reorderThreshold)
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const existing = items.find((item) => item.sku === input.sku)
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }
  const now = new Date().toISOString()
  const newItem: InventoryItem = {
    id: generateId(),
    ...input,
    createdAt: now,
    updatedAt: now,
  }
  items.push(newItem)
  await writeItems(items)
  return newItem
}

export const updateItem = async (id: string, input: UpdateItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  const updated: InventoryItem = {
    ...items[index],
    ...input,
    updatedAt: new Date().toISOString(),
  }
  items[index] = updated
  await writeItems(items)
  return updated
}

export const deleteItem = async (id: string): Promise<void> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  items.splice(index, 1)
  await writeItems(items)
}

export const bulkImport = async (inputItems: NewItemInput[]): Promise<BulkImportResult> => {
  const items = await readItems()
  const existingSkus = new Set(items.map((item) => item.sku))
  const result: BulkImportResult = { imported: 0, skipped: 0, errors: [] }
  const now = new Date().toISOString()

  for (const input of inputItems) {
    if (!input.name || !input.sku || input.quantity == null || !input.category || input.reorderThreshold == null) {
      result.errors.push(`Invalid item data for SKU "${input.sku || 'unknown'}" — missing required fields`)
      continue
    }
    if (existingSkus.has(input.sku)) {
      result.skipped++
      continue
    }
    const newItem: InventoryItem = {
      id: generateId(),
      name: input.name,
      sku: input.sku,
      quantity: Number(input.quantity),
      category: input.category,
      reorderThreshold: Number(input.reorderThreshold),
      createdAt: now,
      updatedAt: now,
    }
    items.push(newItem)
    existingSkus.add(input.sku)
    result.imported++
  }

  await writeItems(items)
  return result
}

