import {
  getAllItems,
  searchItems,
  getLowStockItems,
  addItem,
  updateItem,
  deleteItem,
  bulkImport,
  getItemBySku,
} from './store'
import { renderDashboard, renderSearchResults, renderBulkResult } from './ui'
import type { DashboardData, NewItemInput } from './types'

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (url: string) =>
  new Response(null, { status: 303, headers: { Location: url } })

const parseFormData = async (request: Request): Promise<Record<string, string>> => {
  const formData = await request.formData()
  const data: Record<string, string> = {}
  formData.forEach((value, key) => {
    data[key] = value.toString()
  })
  return data
}

export const handleRequest = async (request: Request): Promise<Response> => {
  const url = new URL(request.url)
  const { pathname } = url
  const method = request.method

  // GET / — Dashboard
  if (pathname === '/' && method === 'GET') {
    const items = await getAllItems()
    const lowStockItems = await getLowStockItems()
    const categoryMap = new Map<string, number>()
    for (const item of items) {
      categoryMap.set(item.category, (categoryMap.get(item.category) ?? 0) + 1)
    }
    const data: DashboardData = {
      totalItems: items.length,
      totalQuantity: items.reduce((sum, item) => sum + item.quantity, 0),
      lowStockItems,
      categories: Array.from(categoryMap.entries()).map(([name, count]) => ({ name, count })),
      items,
    }
    return htmlResponse(renderDashboard(data))
  }

  // GET /items — Search or list all
  if (pathname === '/items' && method === 'GET') {
    const query = url.searchParams.get('q') || url.searchParams.get('barcode') || ''
    if (query) {
      const items = await searchItems(query)
      return htmlResponse(renderSearchResults(items, query))
    }
    const items = await getAllItems()
    return jsonResponse(items)
  }

  // POST /items — Add item (form or JSON)
  if (pathname === '/items' && method === 'POST') {
    const contentType = request.headers.get('Content-Type') || ''
    let input: NewItemInput

    if (contentType.includes('application/json')) {
      input = await request.json() as NewItemInput
    } else {
      const form = await parseFormData(request)
      input = {
        name: form.name,
        sku: form.sku,
        quantity: Number(form.quantity),
        category: form.category,
        reorderThreshold: Number(form.reorderThreshold),
      }
    }

    try {
      const item = await addItem(input)
      if (contentType.includes('application/json')) {
        return jsonResponse(item, 201)
      }
      return redirect('/')
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error'
      if (contentType.includes('application/json')) {
        return jsonResponse({ error: message }, 400)
      }
      return redirect('/?error=' + encodeURIComponent(message))
    }
  }

  // PUT /items/:id — Update item
  const updateMatch = pathname.match(/^\/items\/([^/]+)$/)
  if (updateMatch && method === 'PUT') {
    const id = updateMatch[1]
    try {
      const body = await request.json()
      const item = await updateItem(id, body)
      return jsonResponse(item)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error'
      return jsonResponse({ error: message }, 400)
    }
  }

  // DELETE /items/:id — Delete item (JSON API)
  const deleteMatch = pathname.match(/^\/items\/([^/]+)$/)
  if (deleteMatch && method === 'DELETE') {
    const id = deleteMatch[1]
    try {
      await deleteItem(id)
      return jsonResponse({ success: true })
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error'
      return jsonResponse({ error: message }, 404)
    }
  }

  // POST /items/:id/delete — Delete item (form submit)
  const formDeleteMatch = pathname.match(/^\/items\/([^/]+)\/delete$/)
  if (formDeleteMatch && method === 'POST') {
    const id = formDeleteMatch[1]
    try {
      await deleteItem(id)
    } catch {
      // Item already deleted, just redirect
    }
    return redirect('/')
  }

  // POST /items/bulk — Bulk import
  if (pathname === '/items/bulk' && method === 'POST') {
    const contentType = request.headers.get('Content-Type') || ''
    let inputItems: NewItemInput[]

    if (contentType.includes('application/json')) {
      inputItems = await request.json() as NewItemInput[]
    } else {
      const form = await parseFormData(request)
      try {
        inputItems = JSON.parse(form.jsonData)
      } catch {
        return htmlResponse(renderBulkResult({ imported: 0, skipped: 0, errors: ['Invalid JSON data'] }), 400)
      }
    }

    const result = await bulkImport(inputItems)
    if (contentType.includes('application/json')) {
      return jsonResponse(result)
    }
    return htmlResponse(renderBulkResult(result))
  }

  // GET /items/low-stock — Low stock items
  if (pathname === '/items/low-stock' && method === 'GET') {
    const items = await getLowStockItems()
    return jsonResponse(items)
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

