import type { Book, ReadingStats, FilterOptions, ReadingStatus } from './types'

const DATA_PATH = './data/books.json'

const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2))
}

const generateId = (): string =>
  `book_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`

export const addBook = async (input: {
  title: string
  author: string
  genre: string
  pageCount: number
  coverUrl?: string
  status?: ReadingStatus
}): Promise<Book> => {
  const books = await loadBooks()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    status: input.status ?? 'want-to-read',
    coverUrl: input.coverUrl ?? '',
    dateAdded: new Date().toISOString(),
  }
  books.push(book)
  await saveBooks(books)
  return book
}

export const updateProgress = async (
  bookId: string,
  currentPage: number,
): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === bookId)
  if (!book) return null
  book.currentPage = Math.min(Math.max(0, currentPage), book.pageCount)
  if (book.currentPage === book.pageCount) {
    book.status = 'completed'
  } else if (book.currentPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading'
  }
  await saveBooks(books)
  return book
}

export const updateStatus = async (
  bookId: string,
  status: ReadingStatus,
): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === bookId)
  if (!book) return null
  book.status = status
  if (status === 'completed') {
    book.currentPage = book.pageCount
  }
  await saveBooks(books)
  return book
}

export const removeBook = async (bookId: string): Promise<boolean> => {
  const books = await loadBooks()
  const idx = books.findIndex((b) => b.id === bookId)
  if (idx === -1) return false
  books.splice(idx, 1)
  await saveBooks(books)
  return true
}

export const getBooks = async (filters?: FilterOptions): Promise<Book[]> => {
  const books = await loadBooks()
  return books.filter((book) => {
    if (filters?.status && filters.status !== 'all' && book.status !== filters.status) {
      return false
    }
    if (filters?.genre && filters.genre !== 'all' && book.genre !== filters.genre) {
      return false
    }
    return true
  })
}

export const getBook = async (bookId: string): Promise<Book | null> => {
  const books = await loadBooks()
  return books.find((b) => b.id === bookId) ?? null
}

export const getGenres = async (): Promise<string[]> => {
  const books = await loadBooks()
  const genres = new Set(books.map((b) => b.genre))
  return [...genres].sort()
}

export const getStats = async (): Promise<ReadingStats> => {
  const books = await loadBooks()
  const totalBooks = books.length
  const booksCompleted = books.filter((b) => b.status === 'completed').length
  const booksReading = books.filter((b) => b.status === 'reading').length
  const booksWantToRead = books.filter((b) => b.status === 'want-to-read').length
  const totalPages = books.reduce((sum, b) => sum + b.pageCount, 0)
  const pagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const averageProgress =
    totalBooks > 0
      ? Math.round(
          books.reduce(
            (sum, b) => sum + (b.pageCount > 0 ? (b.currentPage / b.pageCount) * 100 : 0),
            0,
          ) / totalBooks,
        )
      : 0

  return {
    totalBooks,
    booksCompleted,
    booksReading,
    booksWantToRead,
    totalPages,
    pagesRead,
    averageProgress,
  }
}

