import { createSSR } from 'plaited'
import { renderPage } from './render'
import {
  addBook,
  getBooks,
  getBook,
  getGenres,
  getStats,
  updateProgress,
  updateStatus,
  removeBook,
} from './data'
import type { ReadingStatus, FilterOptions } from './types'

const ssr = createSSR()

const renderFullPage = async (filters?: FilterOptions) => {
  const statusFilter = filters?.status ?? 'all'
  const genreFilter = filters?.genre ?? 'all'
  const [books, stats, genres] = await Promise.all([
    getBooks(filters),
    getStats(),
    getGenres(),
  ])
  const template = renderPage(books, stats, genres, statusFilter, genreFilter)
  return ssr(template)
}

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? ''
  if (contentType.includes('application/json')) {
    return req.json()
  }
  if (contentType.includes('application/x-www-form-urlencoded')) {
    const text = await req.text()
    const params = new URLSearchParams(text)
    return Object.fromEntries(params.entries())
  }
  return {}
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // GET / — render the full page
  if (method === 'GET' && path === '/') {
    const status = (url.searchParams.get('status') as ReadingStatus | 'all') ?? 'all'
    const genre = url.searchParams.get('genre') ?? 'all'
    const html = await renderFullPage({ status, genre })
    return htmlResponse(html)
  }

  // GET /api/books — list books with optional filters
  if (method === 'GET' && path === '/api/books') {
    const status = (url.searchParams.get('status') as ReadingStatus | 'all') ?? undefined
    const genre = url.searchParams.get('genre') ?? undefined
    const books = await getBooks({ status, genre })
    return jsonResponse(books)
  }

  // GET /api/books/:id — get single book
  if (method === 'GET' && path.startsWith('/api/books/')) {
    const id = path.split('/').pop()!
    const book = await getBook(id)
    return book ? jsonResponse(book) : jsonResponse({ error: 'Book not found' }, 404)
  }

  // POST /api/books — add a book
  if (method === 'POST' && path === '/api/books') {
    const data = await parseFormData(req)
    const pageCount = parseInt(data.pageCount, 10)
    if (!data.title || !data.author || !data.genre || isNaN(pageCount) || pageCount < 1) {
      return jsonResponse({ error: 'Missing required fields: title, author, genre, pageCount' }, 400)
    }
    const book = await addBook({
      title: data.title,
      author: data.author,
      genre: data.genre,
      pageCount,
      coverUrl: data.coverUrl || undefined,
      status: (data.status as ReadingStatus) || undefined,
    })
    return jsonResponse(book, 201)
  }

  // PATCH /api/books/:id/progress — update reading progress
  if (method === 'PATCH' && path.match(/^\/api\/books\/[^/]+\/progress$/)) {
    const id = path.split('/')[3]
    const data = await parseFormData(req)
    const currentPage = parseInt(data.currentPage, 10)
    if (isNaN(currentPage) || currentPage < 0) {
      return jsonResponse({ error: 'Invalid currentPage' }, 400)
    }
    const book = await updateProgress(id, currentPage)
    return book ? jsonResponse(book) : jsonResponse({ error: 'Book not found' }, 404)
  }

  // PATCH /api/books/:id/status — update status
  if (method === 'PATCH' && path.match(/^\/api\/books\/[^/]+\/status$/)) {
    const id = path.split('/')[3]
    const data = await parseFormData(req)
    const validStatuses: ReadingStatus[] = ['want-to-read', 'reading', 'completed']
    if (!validStatuses.includes(data.status as ReadingStatus)) {
      return jsonResponse({ error: 'Invalid status' }, 400)
    }
    const book = await updateStatus(id, data.status as ReadingStatus)
    return book ? jsonResponse(book) : jsonResponse({ error: 'Book not found' }, 404)
  }

  // DELETE /api/books/:id — remove a book
  if (method === 'DELETE' && path.match(/^\/api\/books\/[^/]+$/)) {
    const id = path.split('/').pop()!
    const removed = await removeBook(id)
    return removed
      ? jsonResponse({ success: true })
      : jsonResponse({ error: 'Book not found' }, 404)
  }

  // GET /api/stats — reading statistics
  if (method === 'GET' && path === '/api/stats') {
    const stats = await getStats()
    return jsonResponse(stats)
  }

  // GET /api/genres — list of genres
  if (method === 'GET' && path === '/api/genres') {
    const genres = await getGenres()
    return jsonResponse(genres)
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

const server = Bun.serve({
  port: parseInt(process.env.PORT ?? '3000', 10),
  fetch: handleRequest,
})

console.log(`Reading List running at http://localhost:${server.port}`)

