export const getTimeline = async (cursor?: string, limit = 30): Promise<TimelineResponse> => {
  const agent = getAgent()
  const response = await agent.getTimeline({ cursor, limit })

  const feed: FeedItem[] = response.data.feed.map((item) => ({
    post: {
      uri: item.post.uri,
      cid: item.post.cid,
      author: {
        did: item.post.author.did,
        handle: item.post.author.handle,
        displayName: item.post.author.displayName,
        avatar: item.post.author.avatar,
      },
      record: item.post.record as { text: string; createdAt: string },
      likeCount: item.post.likeCount ?? 0,
      repostCount: item.post.repostCount ?? 0,
      replyCount: item.post.replyCount ?? 0,
      viewer: {
        like: item.post.viewer?.like,
      },
      indexedAt: item.post.indexedAt,
    },
    reason: item.reason as FeedItem['reason'],
  }))

  return { feed, cursor: response.data.cursor }
}

export const getAuthorFeed = async (
  actor: string,
  cursor?: string,
  limit = 30,
): Promise<TimelineResponse> => {
  const agent = getAgent()
  const response = await agent.getAuthorFeed({ actor, cursor, limit })

  const feed: FeedItem[] = response.data.feed.map((item) => ({
    post: {
      uri: item.post.uri,
      cid: item.post.cid,
      author: {
        did: item.post.author.did,
        handle: item.post.author.handle,
        displayName: item.post.author.displayName,
        avatar: item.post.author.avatar,
      },
      record: item.post.record as { text: string; createdAt: string },
      likeCount: item.post.likeCount ?? 0,
      repostCount: item.post.repostCount ?? 0,
      replyCount: item.post.replyCount ?? 0,
      viewer: {
        like: item.post.viewer?.like,
      },
      indexedAt: item.post.indexedAt,
    },
    reason: item.reason as FeedItem['reason'],
  }))

  return { feed, cursor: response.data.cursor }
}

