  try {
    const session = await login({ identifier, password })
    state.handle = session.handle
    return await handleRefreshTimeline()
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Login failed'
    return renderError(message)
  }
}

export const handleResume = async (): Promise<string> => {
  const session = await resumeSession()
  if (!session) return renderLoginForm()

  state.handle = session.handle
  return await handleRefreshTimeline()
}

export const handleLogout = async (): Promise<string> => {
  await logout()
  state.feedItems = []
  state.cursor = undefined
  state.handle = ''
  return renderLoginForm()
}

export const handleRefreshTimeline = async (): Promise<string> => {
  try {
    const response = await getTimeline()
    state.feedItems = response.feed
    state.cursor = response.cursor
    return renderTimeline(state.feedItems, state.handle)
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to load timeline'
    return renderError(message)
  }
}

export const handleLoadMore = async (): Promise<string> => {
  try {
    const response = await getTimeline(state.cursor)
    state.feedItems = [...state.feedItems, ...response.feed]
    state.cursor = response.cursor
    return renderTimeline(state.feedItems, state.handle)
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to load more posts'
    return renderError(message)
  }
}

export const handleSubmitPost = async (text: string): Promise<string> => {
  if (!text.trim() || text.length > 300) {
    return renderError('Post must be between 1 and 300 characters')
  }

  try {
    await createPost(text)
    return await handleRefreshTimeline()
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to create post'
    return renderError(message)
  }
}

export const handleToggleLike = async (
  uri: string,
  cid: string,
  likeUri?: string,
): Promise<string> => {
  try {
    if (likeUri) {
      await unlikePost(likeUri)
    } else {
      await likePost(uri, cid)
    }
    return await handleRefreshTimeline()
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to toggle like'
    return renderError(message)
  }
}

export const handleViewProfile = async (actor: string): Promise<string> => {
  try {
    const profile = await getProfile(actor)
    return renderProfile(profile)
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to load profile'
    return renderError(message)
  }
}

export const handleToggleFollow = async (did: string, followUri?: string): Promise<string> => {
  try {
    if (followUri) {
      await unfollowUser(followUri)
    } else {
      await followUser(did)
    }
    const profile = await getProfile(did)
    return renderProfile(profile)
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to toggle follow'
    return renderError(message)
  }
}

