/**
 * Converts markdown-style bold and italic syntax to HTML.
 * Supports **bold**, *italic*, and combined ***bold italic***.
 */
export const formatMessageText = (text: string): string => {
  let result = escapeHtml(text)

  // Bold + italic: ***text***
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')

  // Bold: **text**
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')

  // Italic: *text*
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')

  return result
}

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

import type { Room, Message, RoomState } from './types'

const DATA_DIR = './data'
const ROOMS_FILE = `${DATA_DIR}/rooms.json`

const ensureDataDir = async (): Promise<void> => {
  const dir = Bun.file(DATA_DIR)
  if (!(await dir.exists())) {
    await Bun.$`mkdir -p ${DATA_DIR}`
  }
}

// --- Room persistence ---

export const loadRooms = async (): Promise<Room[]> => {
  await ensureDataDir()
  const file = Bun.file(ROOMS_FILE)
  if (await file.exists()) {
    return file.json()
  }
  return []
}

export const saveRooms = async (rooms: Room[]): Promise<void> => {
  await ensureDataDir()
  await Bun.write(ROOMS_FILE, JSON.stringify(rooms, null, 2))
}

// --- Message persistence (JSONL per room) ---

const messagesPath = (roomId: string): string =>
  `${DATA_DIR}/messages-${roomId}.jsonl`

export const loadMessages = async (roomId: string): Promise<Message[]> => {
  await ensureDataDir()
  const file = Bun.file(messagesPath(roomId))
  if (!(await file.exists())) {
    return []
  }
  const content = await file.text()
  return content
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message)
}

export const appendMessage = async (message: Message): Promise<void> => {
  await ensureDataDir()
  const path = messagesPath(message.roomId)
  const file = Bun.file(path)
  const existing = (await file.exists()) ? await file.text() : ''
  const line = JSON.stringify(message) + '\n'
  await Bun.write(path, existing + line)
}

// --- Room state persistence (unread tracking) ---

const ROOM_STATES_FILE = `${DATA_DIR}/room-states.json`

export const loadRoomStates = async (): Promise<Record<string, RoomState>> => {
  await ensureDataDir()
  const file = Bun.file(ROOM_STATES_FILE)
  if (await file.exists()) {
    return file.json()
  }
  return {}
}

export const saveRoomStates = async (
  states: Record<string, RoomState>,
): Promise<void> => {
  await ensureDataDir()
  await Bun.write(ROOM_STATES_FILE, JSON.stringify(states, null, 2))
}

import type { Room } from './types'
import { loadRooms, saveRooms, loadRoomStates, saveRoomStates } from './store'

const generateId = (): string =>
  Math.random().toString(36).slice(2, 10) + Date.now().toString(36)

export const createRoom = async (name: string): Promise<Room> => {
  const rooms = await loadRooms()
  const now = new Date().toISOString()
  const room: Room = {
    id: generateId(),
    name: name.trim(),
    createdAt: now,
    lastActivity: now,
  }
  rooms.push(room)
  await saveRooms(rooms)

  // Initialize room state for unread tracking
  const states = await loadRoomStates()
  states[room.id] = {
    roomId: room.id,
    lastReadTimestamp: now,
    unreadCount: 0,
  }
  await saveRoomStates(states)

  return room
}

export const listRooms = async (): Promise<Room[]> => {
  const rooms = await loadRooms()
  return rooms.sort(
    (a, b) => new Date(b.lastActivity).getTime() - new Date(a.lastActivity).getTime(),
  )
}

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const rooms = await loadRooms()
  return rooms.find((r) => r.id === roomId)
}

export const markRoomRead = async (roomId: string): Promise<void> => {
  const states = await loadRoomStates()
  const now = new Date().toISOString()
  states[roomId] = {
    roomId,
    lastReadTimestamp: now,
    unreadCount: 0,
  }
  await saveRoomStates(states)
}

export const getUnreadCount = async (roomId: string): Promise<number> => {
  const states = await loadRoomStates()
  return states[roomId]?.unreadCount ?? 0
}

import type { Message } from './types'
import {
  loadMessages,
  appendMessage,
  loadRooms,
  saveRooms,
  loadRoomStates,
  saveRoomStates,
} from './store'

const generateId = (): string =>
  Math.random().toString(36).slice(2, 10) + Date.now().toString(36)

export const postMessage = async (
  roomId: string,
  sender: string,
  text: string,
): Promise<Message> => {
  const now = new Date().toISOString()
  const message: Message = {
    id: generateId(),
    roomId,
    sender: sender.trim(),
    text: text.trim(),
    timestamp: now,
  }

  await appendMessage(message)

  // Update room lastActivity
  const rooms = await loadRooms()
  const room = rooms.find((r) => r.id === roomId)
  if (room) {
    room.lastActivity = now
    await saveRooms(rooms)
  }

  // Increment unread count for users not currently viewing this room
  const states = await loadRoomStates()
  if (states[roomId]) {
    states[roomId].unreadCount += 1
  } else {
    states[roomId] = {
      roomId,
      lastReadTimestamp: now,
      unreadCount: 1,
    }
  }
  await saveRoomStates(states)

  return message
}

export const getRoomMessages = async (
  roomId: string,
  limit = 50,
): Promise<Message[]> => {
  const messages = await loadMessages(roomId)
  return messages.slice(-limit)
}

