import type { ChatState, TypingState } from './types'
import { createRoom, listRooms, getRoom, markRoomRead, getUnreadCount } from './rooms'
import { postMessage, getRoomMessages } from './messages'
import { renderChat } from './render'
import { loadRoomStates } from './store'

export const createChatState = (): ChatState => ({
  rooms: [],
  activeRoomId: null,
  roomStates: {},
  typingIndicators: {},
})

export const handleCreateRoom = async (name: string): Promise<ChatState> => {
  const room = await createRoom(name)
  const rooms = await listRooms()
  const roomStates = await loadRoomStates()
  return {
    rooms,
    activeRoomId: room.id,
    roomStates,
    typingIndicators: {},
  }
}

export const handleJoinRoom = async (roomId: string): Promise<ChatState> => {
  await markRoomRead(roomId)
  const rooms = await listRooms()
  const roomStates = await loadRoomStates()
  return {
    rooms,
    activeRoomId: roomId,
    roomStates,
    typingIndicators: {},
  }
}

export const handleSendMessage = async (
  state: ChatState,
  sender: string,
  text: string,
): Promise<ChatState> => {
  if (!state.activeRoomId || !text.trim()) return state

  await postMessage(state.activeRoomId, sender, text)
  await markRoomRead(state.activeRoomId)
  const rooms = await listRooms()
  const roomStates = await loadRoomStates()

  return {
    ...state,
    rooms,
    roomStates,
  }
}

export const handleTypingUpdate = (
  state: ChatState,
  roomId: string,
  sender: string,
  isTyping: boolean,
): ChatState => {
  const roomTyping = state.typingIndicators[roomId] ?? []
  const filtered = roomTyping.filter((t) => t.sender !== sender)
  const updated: TypingState[] = isTyping
    ? [...filtered, { roomId, sender, isTyping: true }]
    : filtered

  return {
    ...state,
    typingIndicators: {
      ...state.typingIndicators,
      [roomId]: updated,
    },
  }
}

export const renderChatView = async (state: ChatState): Promise<ReturnType<typeof renderChat>> => {
  const activeRoom = state.activeRoomId
    ? await getRoom(state.activeRoomId)
    : undefined

  const messages = state.activeRoomId
    ? await getRoomMessages(state.activeRoomId)
    : []

  const typing = state.activeRoomId
    ? state.typingIndicators[state.activeRoomId] ?? []
    : []

  return renderChat(
    state.rooms,
    state.activeRoomId,
    activeRoom?.name ?? '',
    messages,
    state.roomStates,
    typing,
  )
}

