{
  "name": "@node/discussion-forum",
  "version": "1.0.0",
  "type": "module",
  "main": "server.ts",
  "modnet": {
    "contentType": "social",
    "structure": "thread",
    "mechanics": ["post", "reply", "vote", "sort", "filter"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type Vote = {
  userId: string
  value: 1 | -1
}

export type Reply = {
  id: string
  threadId: string
  body: string
  author: string
  createdAt: string
  votes: Vote[]
}

export type Thread = {
  id: string
  title: string
  body: string
  author: string
  createdAt: string
  votes: Vote[]
  replies: Reply[]
}

export type SortMode = 'newest' | 'top' | 'active'

export type ForumData = {
  threads: Thread[]
}

import type { ForumData, Thread, Reply, Vote, SortMode } from './types'

const DATA_PATH = './data/forum.json'

const loadData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return { threads: [] }
}

const saveData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`

const getVoteScore = (votes: Vote[]): number =>
  votes.reduce((sum, v) => sum + v.value, 0)

export const getThreads = async (sort: SortMode = 'newest', search?: string): Promise<Thread[]> => {
  const data = await loadData()
  let threads = data.threads

  if (search) {
    const query = search.toLowerCase()
    threads = threads.filter(t =>
      t.title.toLowerCase().includes(query) ||
      t.body.toLowerCase().includes(query)
    )
  }

  switch (sort) {
    case 'newest':
      return threads.sort((a, b) =>
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      )
    case 'top':
      return threads.sort((a, b) =>
        getVoteScore(b.votes) - getVoteScore(a.votes)
      )
    case 'active':
      return threads.sort((a, b) => {
        const aLatest = a.replies.length
          ? Math.max(...a.replies.map(r => new Date(r.createdAt).getTime()))
          : new Date(a.createdAt).getTime()
        const bLatest = b.replies.length
          ? Math.max(...b.replies.map(r => new Date(r.createdAt).getTime()))
          : new Date(b.createdAt).getTime()
        return bLatest - aLatest
      })
    default:
      return threads
  }
}

export const getThread = async (id: string): Promise<Thread | undefined> => {
  const data = await loadData()
  return data.threads.find(t => t.id === id)
}

export const createThread = async (title: string, body: string, author: string): Promise<Thread> => {
  const data = await loadData()
  const thread: Thread = {
    id: generateId(),
    title,
    body,
    author,
    createdAt: new Date().toISOString(),
    votes: [],
    replies: [],
  }
  data.threads.push(thread)
  await saveData(data)
  return thread
}

export const createReply = async (
  threadId: string,
  body: string,
  author: string
): Promise<Reply | null> => {
  const data = await loadData()
  const thread = data.threads.find(t => t.id === threadId)
  if (!thread) return null

  const reply: Reply = {
    id: generateId(),
    threadId,
    body,
    author,
    createdAt: new Date().toISOString(),
    votes: [],
  }
  thread.replies.push(reply)
  await saveData(data)
  return reply
}

export const voteThread = async (
  threadId: string,
  userId: string,
  value: 1 | -1
): Promise<number | null> => {
  const data = await loadData()
  const thread = data.threads.find(t => t.id === threadId)
  if (!thread) return null

  const existing = thread.votes.findIndex(v => v.userId === userId)
  if (existing !== -1) {
    if (thread.votes[existing].value === value) {
      thread.votes.splice(existing, 1)
    } else {
      thread.votes[existing].value = value
    }
  } else {
    thread.votes.push({ userId, value })
  }
  await saveData(data)
  return getVoteScore(thread.votes)
}

export const voteReply = async (
  threadId: string,
  replyId: string,
  userId: string,
  value: 1 | -1
): Promise<number | null> => {
  const data = await loadData()
  const thread = data.threads.find(t => t.id === threadId)
  if (!thread) return null

  const reply = thread.replies.find(r => r.id === replyId)
  if (!reply) return null

  const existing = reply.votes.findIndex(v => v.userId === userId)
  if (existing !== -1) {
    if (reply.votes[existing].value === value) {
      reply.votes.splice(existing, 1)
    } else {
      reply.votes[existing].value = value
    }
  } else {
    reply.votes.push({ userId, value })
  }
  await saveData(data)
  return getVoteScore(reply.votes)
}

