const styleStr = (s: Record<string, string | number | undefined>): string =>
  Object.entries(s)
    .filter(([, v]) => v !== undefined)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, m => `-${m.toLowerCase()}`)}:${v}`)
    .join(';')

const VoteControls = (entityType: string, entityId: string, votes: Vote[], threadId?: string) => {
  const score = getScore(votes)
  const upAction = threadId
    ? `/api/threads/${threadId}/replies/${entityId}/vote`
    : `/api/threads/${entityId}/vote`
  const downAction = upAction

  return h('div', { style: styleStr(styles.voteCol) },
    h('form', { method: 'POST', action: upAction },
      h('input', { type: 'hidden', name: 'value', value: '1' }),
      h('input', { type: 'hidden', name: 'userId', value: 'anon' }),
      h('button', { type: 'submit', style: styleStr(styles.voteBtn), title: 'Upvote' }, '\u25B2'),
    ),
    h('span', { style: styleStr(styles.voteScore) }, String(score)),
    h('form', { method: 'POST', action: downAction },
