    { value: 'newest', label: 'Newest' },
    { value: 'top', label: 'Most Upvoted' },
    { value: 'active', label: 'Most Active' },
  ]

  return h('div', { style: styleStr(styles.page) },
    h('div', { style: styleStr(styles.header) },
      h('h1', { style: styleStr(styles.title) }, 'Discussion Forum'),
      h('a', { href: '/new', style: styleStr({ ...styles.btn, textDecoration: 'none' }) }, '+ New Thread'),
    ),
    h('form', { method: 'GET', action: '/', style: styleStr(styles.searchBar) },
      h('input', {
        type: 'text',
        name: 'search',
        placeholder: 'Search threads...',
        value: search,
        style: styleStr(styles.searchInput),
      }),
      sort !== 'newest'
        ? h('input', { type: 'hidden', name: 'sort', value: sort })
        : null,
      h('button', { type: 'submit', style: styleStr(styles.btn) }, 'Search'),
    ),
    h('div', { style: styleStr(styles.sortBar) },
      ...sortOptions.map(opt =>
        h('a', {
