            : 'No threads yet. Start a discussion!',
        )
      : h(Fragment, {},
          ...threads.map(thread =>
            h('div', { style: styleStr(styles.threadCard) },
              VoteControls('thread', thread.id, thread.votes),
              h('div', { style: styleStr(styles.threadContent) },
