import type { SortMode } from './types'
import {
  getThreads,
  getThread,
  createThread,
  createReply,
  voteThread,
  voteReply,
} from './store'
import {
  renderThreadList,
  renderNewThreadForm,
  renderThreadDetail,
  renderPage,
} from './views'

const parseForm = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  params.forEach((value, key) => {
    result[key] = value
  })
  return result
}

const html = (content: string) =>
  new Response(content, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (path: string) =>
  new Response(null, {
    status: 302,
    headers: { Location: path },
  })

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Thread list page
    if (pathname === '/' && method === 'GET') {
      const sort = (url.searchParams.get('sort') || 'newest') as SortMode
      const search = url.searchParams.get('search') || ''
      const threads = await getThreads(sort, search || undefined)
      return html(renderPage(renderThreadList(threads, sort, search)))
    }

    // New thread form
    if (pathname === '/new' && method === 'GET') {
      return html(renderPage(renderNewThreadForm()))
    }

    // Thread detail page
    if (pathname.startsWith('/thread/') && method === 'GET') {
      const id = pathname.slice('/thread/'.length)
      const thread = await getThread(id)
      if (!thread) return html(renderPage(renderThreadList([], 'newest', '')))
      return html(renderPage(renderThreadDetail(thread)))
    }

    // API: Create thread
    if (pathname === '/api/threads' && method === 'POST') {
      const form = await parseForm(req)
      const { title, body, author } = form
      if (!title || !body || !author) {
        return json({ error: 'Missing required fields' }, 400)
      }
      const thread = await createThread(title.trim(), body.trim(), author.trim())
      return redirect(`/thread/${thread.id}`)
    }

    // API: Create reply
    const replyMatch = pathname.match(/^\/api\/threads\/([^/]+)\/replies$/)
    if (replyMatch && method === 'POST') {
      const threadId = replyMatch[1]
      const form = await parseForm(req)
      const { body, author } = form
      if (!body || !author) {
        return json({ error: 'Missing required fields' }, 400)
      }
      const reply = await createReply(threadId, body.trim(), author.trim())
      if (!reply) return json({ error: 'Thread not found' }, 404)
      return redirect(`/thread/${threadId}`)
    }

    // API: Vote on thread
    const threadVoteMatch = pathname.match(/^\/api\/threads\/([^/]+)\/vote$/)
    if (threadVoteMatch && method === 'POST') {
      const threadId = threadVoteMatch[1]
      const form = await parseForm(req)
      const value = parseInt(form.value) as 1 | -1
      const userId = form.userId || 'anon'
      if (value !== 1 && value !== -1) {
        return json({ error: 'Invalid vote value' }, 400)
      }
      const score = await voteThread(threadId, userId, value)
      if (score === null) return json({ error: 'Thread not found' }, 404)
      const referer = req.headers.get('referer') || '/'
      return redirect(referer)
    }

    // API: Vote on reply
    const replyVoteMatch = pathname.match(
      /^\/api\/threads\/([^/]+)\/replies\/([^/]+)\/vote$/
    )
    if (replyVoteMatch && method === 'POST') {
      const [, threadId, replyId] = replyVoteMatch
      const form = await parseForm(req)
      const value = parseInt(form.value) as 1 | -1
      const userId = form.userId || 'anon'
      if (value !== 1 && value !== -1) {
        return json({ error: 'Invalid vote value' }, 400)
      }
      const score = await voteReply(threadId, replyId, userId, value)
      if (score === null) return json({ error: 'Not found' }, 404)
      const referer = req.headers.get('referer') || '/'
      return redirect(referer)
    }

    return json({ error: 'Not found' }, 404)
  },
})

console.log(`Discussion Forum running at http://localhost:${server.port}`)

