const generatePlaceholderForecast = (city: string): ForecastResponse => {
  const now = new Date()
  now.setHours(12, 0, 0, 0)
  const baseTemp = 15 + Math.random() * 10
  const list = Array.from({ length: 40 }, (_, i) => {
    const dt = new Date(now.getTime() + i * 3 * 3600 * 1000)
    const hourOffset = (dt.getHours() - 12) / 12
    const dayOffset = Math.floor(i / 8)
    const temp = baseTemp + dayOffset * 0.5 + Math.sin(hourOffset * Math.PI) * 5 + (Math.random() - 0.5) * 3
    const condition = FORECAST_CONDITIONS[Math.floor(Math.random() * FORECAST_CONDITIONS.length)]
    return {
      dt: Math.floor(dt.getTime() / 1000),
      main: {
        temp: Math.round(temp * 10) / 10,
        feels_like: Math.round((temp - 2) * 10) / 10,
        temp_min: Math.round((temp - 2) * 10) / 10,
        temp_max: Math.round((temp + 2) * 10) / 10,
        pressure: 1010 + Math.floor(Math.random() * 10),
        humidity: 50 + Math.floor(Math.random() * 35),
      },
      weather: [condition],
      wind: { speed: 2 + Math.round(Math.random() * 7 * 10) / 10, deg: Math.floor(Math.random() * 360) },
      dt_txt: dt.toISOString().replace('T', ' ').slice(0, 19),
    }
  })

  return {
    city: { name: city, country: 'GB' },
    list,
  }
}

export const aggregateDailyForecasts = (forecast: ForecastResponse): DailyForecast[] => {
  const dailyMap = new Map<string, { temps: number[]; entries: ForecastResponse['list'] }>()

  for (const entry of forecast.list) {
    const dateKey = entry.dt_txt.split(' ')[0]
    const existing = dailyMap.get(dateKey)
    if (existing) {
      existing.temps.push(entry.main.temp)
      existing.entries.push(entry)
    } else {
      dailyMap.set(dateKey, { temps: [entry.main.temp], entries: [entry] })
    }
  }

  const dailies: DailyForecast[] = []
  for (const [dateStr, { temps, entries }] of dailyMap) {
    const date = new Date(dateStr)
    const midday = entries.reduce((closest, e) => {
      const h = new Date(e.dt * 1000).getHours()
      const closestH = new Date(closest.dt * 1000).getHours()
      return Math.abs(h - 12) < Math.abs(closestH - 12) ? e : closest
    }, entries[0])

    dailies.push({
      date: dateStr,
      dayName: DAY_NAMES[date.getDay()],
      tempMin: Math.round(Math.min(...temps) * 10) / 10,
      tempMax: Math.round(Math.max(...temps) * 10) / 10,
      description: midday.weather[0].description,
      icon: midday.weather[0].icon,
      humidity: midday.main.humidity,
      windSpeed: midday.wind.speed,
    })
  }

  return dailies.slice(0, 5)
}

export const getWeatherData = (city: string) => {
  const current = generatePlaceholderCurrent(city)
  const forecast = generatePlaceholderForecast(city)
  const daily = aggregateDailyForecasts(forecast)
  return { current, forecast, daily }
}

import { h } from 'plaited'
import type { DailyForecast } from './types'
import { celsiusToFahrenheit } from './data'

const CHART_WIDTH = 600
const CHART_HEIGHT = 200
const PADDING = { top: 30, right: 40, bottom: 40, left: 50 }

const plotWidth = CHART_WIDTH - PADDING.left - PADDING.right
const plotHeight = CHART_HEIGHT - PADDING.top - PADDING.bottom

export const renderTemperatureChart = (days: DailyForecast[]) => {
  if (days.length === 0) return h('div', {}, 'No forecast data')

  const allTemps = days.flatMap((d) => [d.tempMin, d.tempMax])
  const minTemp = Math.floor(Math.min(...allTemps)) - 2
  const maxTemp = Math.ceil(Math.max(...allTemps)) + 2
  const tempRange = maxTemp - minTemp || 1

  const scaleX = (i: number) => PADDING.left + (i / (days.length - 1 || 1)) * plotWidth
  const scaleY = (temp: number) => PADDING.top + plotHeight - ((temp - minTemp) / tempRange) * plotHeight

  const highPoints = days.map((d, i) => `${scaleX(i)},${scaleY(d.tempMax)}`)
  const lowPoints = days.map((d, i) => `${scaleX(i)},${scaleY(d.tempMin)}`)

  const gridLines = Array.from({ length: 5 }, (_, i) => {
    const temp = minTemp + (tempRange * i) / 4
    const y = scaleY(temp)
    return h('g', { key: `grid-${i}` },
      h('line', {
        x1: String(PADDING.left),
        y1: String(y),
        x2: String(CHART_WIDTH - PADDING.right),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-dasharray': '4,4',
      }),
      h('text', {
        x: String(PADDING.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        fill: '#888',
        'font-size': '11',
      }, `${Math.round(temp)}°`),
    )
  })

  const xLabels = days.map((d, i) =>
    h('text', {
      key: `label-${i}`,
      x: String(scaleX(i)),
      y: String(CHART_HEIGHT - 8),
      'text-anchor': 'middle',
      fill: '#888',
      'font-size': '11',
    }, d.dayName),
  )

  const highDots = days.map((d, i) =>
    h('g', { key: `high-${i}` },
      h('circle', {
        cx: String(scaleX(i)),
        cy: String(scaleY(d.tempMax)),
        r: '4',
        fill: '#e74c3c',
      }),
      h('text', {
        x: String(scaleX(i)),
        y: String(scaleY(d.tempMax) - 10),
        'text-anchor': 'middle',
        fill: '#e74c3c',
        'font-size': '10',
        'font-weight': 'bold',
      }, `${Math.round(d.tempMax)}°`),
    ),
  )

  const lowDots = days.map((d, i) =>
    h('g', { key: `low-${i}` },
      h('circle', {
        cx: String(scaleX(i)),
        cy: String(scaleY(d.tempMin)),
        r: '4',
        fill: '#3498db',
      }),
      h('text', {
        x: String(scaleX(i)),
        y: String(scaleY(d.tempMin) + 16),
        'text-anchor': 'middle',
        fill: '#3498db',
        'font-size': '10',
        'font-weight': 'bold',
      }, `${Math.round(d.tempMin)}°`),
    ),
  )

  return h('svg', {
    viewBox: `0 0 ${CHART_WIDTH} ${CHART_HEIGHT}`,
    style: 'width:100%;max-width:600px;height:auto;background:#fafafa;border-radius:8px;',
  },
    ...gridLines,
    h('polyline', {
      points: highPoints.join(' '),
      fill: 'none',
      stroke: '#e74c3c',
      'stroke-width': '2',
      'stroke-linejoin': 'round',
    }),
    h('polyline', {
      points: lowPoints.join(' '),
      fill: 'none',
      stroke: '#3498db',
      'stroke-width': '2',
      'stroke-linejoin': 'round',
    }),
    ...highDots,
    ...lowDots,
    ...xLabels,
    h('text', {
      x: String(CHART_WIDTH - PADDING.right + 5),
      y: String(scaleY(days[days.length - 1].tempMax) + 4),
      fill: '#e74c3c',
      'font-size': '10',
    }, 'High'),
    h('text', {
      x: String(CHART_WIDTH - PADDING.right + 5),
      y: String(scaleY(days[days.length - 1].tempMin) + 4),
      fill: '#3498db',
      'font-size': '10',
    }, 'Low'),
  )
}

import { getWeatherData } from './data'
import { renderDashboard, renderToHTML } from './render'
