const DEFAULT_CITY = 'London'

const loadDefaultCity = async (): Promise<string> => {
  try {
    const file = Bun.file('./data/default-city.json')
    const json = await file.json()
    return json.city ?? DEFAULT_CITY
  } catch {
    return DEFAULT_CITY
  }
}

const saveDefaultCity = async (city: string): Promise<void> => {
  await Bun.write('./data/default-city.json', JSON.stringify({ city }, null, 2))
}

export const getWeatherDashboard = (city: string) => {
  const { current, forecast, daily } = getWeatherData(city)
  return { current, daily, city }
}

export const renderWeatherDashboard = (city: string): string => {
  const { current, daily } = getWeatherDashboard(city)
  return renderToHTML(current, daily, city)
}

const serve = () => {
  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)
      const city = url.searchParams.get('city') ?? await loadDefaultCity()

      if (req.method === 'POST') {
        const formData = await req.formData()
        const newCity = formData.get('city')?.toString().trim()
        if (newCity) {
          await saveDefaultCity(newCity)
          return Response.redirect(`/?city=${encodeURIComponent(newCity)}`, 303)
        }
      }

      const { current, daily } = getWeatherDashboard(city)
      const html = renderToHTML(current, daily, city)

      const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard — ${current.name}</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f5f5f5; min-height: 100vh; padding: 20px; }
  </style>
</head>
<body>
  ${html}
</body>
</html>`

      return new Response(page, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    },
  })

  console.log('Weather Dashboard running at http://localhost:3000')
}

// Run server when executed directly
const isMain = import.meta.main
if (isMain) {
  serve()
}

