const MARKERS_PATH = './data/markers.json';
const CIRCLES_PATH = './data/circles.json';

const readJson = async <T>(path: string): Promise<T[]> => {
  const file = Bun.file(path);
  const exists = await file.exists();
  if (!exists) return [];
  const text = await file.text();
  return JSON.parse(text) as T[];
};

const writeJson = async <T>(path: string, data: T[]): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2));
};

export const getMarkers = (): Promise<Marker[]> => readJson<Marker>(MARKERS_PATH);

export const addMarker = async (marker: Marker): Promise<void> => {
  const markers = await getMarkers();
  markers.push(marker);
  await writeJson(MARKERS_PATH, markers);
};

export const deleteMarker = async (id: string): Promise<boolean> => {
  const markers = await getMarkers();
  const filtered = markers.filter((m) => m.id !== id);
  if (filtered.length === markers.length) return false;
  await writeJson(MARKERS_PATH, filtered);
  return true;
};

export const getCircles = (): Promise<Circle[]> => readJson<Circle>(CIRCLES_PATH);

export const addCircle = async (circle: Circle): Promise<void> => {
  const circles = await getCircles();
  circles.push(circle);
  await writeJson(CIRCLES_PATH, circles);
};

export const deleteCircle = async (id: string): Promise<boolean> => {
  const circles = await getCircles();
  const filtered = circles.filter((c) => c.id !== id);
  if (filtered.length === circles.length) return false;
  await writeJson(CIRCLES_PATH, filtered);
  return true;
};

import type { Marker, Circle, MarkerCategory, SearchResult } from './types';
import { getMarkers, addMarker, deleteMarker, getCircles, addCircle, deleteCircle } from './store';

const generateId = (): string => crypto.randomUUID();

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const parseBody = async <T>(req: Request): Promise<T> => {
  const text = await req.text();
  return JSON.parse(text) as T;
};

export const handleApiRequest = async (req: Request, pathname: string): Promise<Response | null> => {
  const method = req.method;

  // GET /api/markers
  if (pathname === '/api/markers' && method === 'GET') {
    const markers = await getMarkers();
    return jsonResponse(markers);
  }

  // POST /api/markers
  if (pathname === '/api/markers' && method === 'POST') {
    const body = await parseBody<{
      title: string;
      description: string;
      lat: number;
      lng: number;
      category?: MarkerCategory;
    }>(req);

    if (!body.title || body.lat == null || body.lng == null) {
      return jsonResponse({ error: 'title, lat, and lng are required' }, 400);
    }

    const marker: Marker = {
      id: generateId(),
      title: body.title,
      description: body.description || '',
      lat: body.lat,
      lng: body.lng,
      category: body.category || 'default',
      createdAt: new Date().toISOString(),
    };

    await addMarker(marker);
    return jsonResponse(marker, 201);
  }

  // DELETE /api/markers/:id
  if (pathname.startsWith('/api/markers/') && method === 'DELETE') {
    const id = pathname.slice('/api/markers/'.length);
    const deleted = await deleteMarker(id);
    if (!deleted) return jsonResponse({ error: 'Marker not found' }, 404);
    return jsonResponse({ ok: true });
  }

  // GET /api/circles
  if (pathname === '/api/circles' && method === 'GET') {
    const circles = await getCircles();
    return jsonResponse(circles);
  }

  // POST /api/circles
  if (pathname === '/api/circles' && method === 'POST') {
    const body = await parseBody<{
      lat: number;
      lng: number;
      radius: number;
      color?: string;
      label?: string;
    }>(req);

    if (body.lat == null || body.lng == null || body.radius == null) {
      return jsonResponse({ error: 'lat, lng, and radius are required' }, 400);
    }

    const circle: Circle = {
      id: generateId(),
      lat: body.lat,
      lng: body.lng,
      radius: body.radius,
      color: body.color || '#3b82f6',
      label: body.label || '',
      createdAt: new Date().toISOString(),
    };

    await addCircle(circle);
    return jsonResponse(circle, 201);
  }

  // DELETE /api/circles/:id
  if (pathname.startsWith('/api/circles/') && method === 'DELETE') {
    const id = pathname.slice('/api/circles/'.length);
    const deleted = await deleteCircle(id);
    if (!deleted) return jsonResponse({ error: 'Circle not found' }, 404);
    return jsonResponse({ ok: true });
  }

  // GET /api/search?q=...
  if (pathname === '/api/search' && method === 'GET') {
    const url = new URL(req.url);
    const query = url.searchParams.get('q');
    if (!query) return jsonResponse({ error: 'q parameter required' }, 400);

    const nominatimUrl = `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=5`;
    const response = await fetch(nominatimUrl, {
      headers: { 'User-Agent': 'InteractiveMapModule/1.0' },
    });
    const results = (await response.json()) as Array<{ display_name: string; lat: string; lon: string }>;

    const searchResults: SearchResult[] = results.map((r) => ({
      displayName: r.display_name,
      lat: parseFloat(r.lat),
      lng: parseFloat(r.lon),
    }));

    return jsonResponse(searchResults);
  }

  return null;
};

