const clientScript = (): string => `
const CATEGORY_COLORS = ${JSON.stringify(CATEGORY_COLORS)};

let map;
let leafletMarkers = {};
let leafletCircles = {};
let activeModal = null;
let pendingClickTarget = null;
let searchTimeout = null;

const init = () => {
  map = L.map('map').setView([40.7128, -74.006], 12);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; OpenStreetMap contributors',
    maxZoom: 19,
  }).addTo(map);

  map.on('click', (e) => {
    if (pendingClickTarget) {
      document.getElementById(pendingClickTarget + '-lat').value = e.latlng.lat.toFixed(6);
      document.getElementById(pendingClickTarget + '-lng').value = e.latlng.lng.toFixed(6);
    }
  });

  const searchInput = document.getElementById('search-input');
  searchInput.addEventListener('input', (e) => {
    clearTimeout(searchTimeout);
    const q = e.target.value.trim();
    if (q.length < 2) {
      hideSearchResults();
      return;
    }
    searchTimeout = setTimeout(() => searchLocation(q), 400);
  });

  searchInput.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') {
      clearTimeout(searchTimeout);
      const q = e.target.value.trim();
      if (q.length >= 2) searchLocation(q);
    }
  });

  loadData();
};

const searchLocation = async (q) => {
  const res = await fetch('/api/search?q=' + encodeURIComponent(q));
  const results = await res.json();
  const container = document.getElementById('search-results');
  container.innerHTML = '';
  if (results.length === 0) {
    container.style.display = 'none';
    return;
  }
  container.style.display = 'block';
  results.forEach((r) => {
    const div = document.createElement('div');
    div.className = 'search-result-item';
    div.style.cssText = 'padding:8px 12px;font-size:13px;cursor:pointer;border-bottom:1px solid #1e293b;color:#cbd5e1;';
    div.textContent = r.displayName;
    div.onclick = () => {
      map.flyTo([r.lat, r.lng], 14);
      hideSearchResults();
      document.getElementById('search-input').value = '';
    };
    container.appendChild(div);
  });
};

const hideSearchResults = () => {
  document.getElementById('search-results').style.display = 'none';
};

const loadData = async () => {
  const [markersRes, circlesRes] = await Promise.all([
    fetch('/api/markers'),
    fetch('/api/circles'),
  ]);
  const markers = await markersRes.json();
  const circles = await circlesRes.json();

  Object.values(leafletMarkers).forEach((m) => map.removeLayer(m));
  Object.values(leafletCircles).forEach((c) => map.removeLayer(c));
  leafletMarkers = {};
  leafletCircles = {};

  markers.forEach(addMarkerToMap);
  circles.forEach(addCircleToMap);
  renderSidebar(markers);
};

const createColoredIcon = (color) => {
  return L.divIcon({
    className: '',
    html: '<div style="width:28px;height:28px;border-radius:50% 50% 50% 0;background:' + color + ';transform:rotate(-45deg);border:2px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.3);"><div style="width:10px;height:10px;border-radius:50%;background:#fff;position:absolute;top:50%;left:50%;transform:translate(-50%,-50%) rotate(45deg);"></div></div>',
    iconSize: [28, 28],
    iconAnchor: [14, 28],
    popupAnchor: [0, -28],
  });
};

const addMarkerToMap = (marker) => {
  const color = CATEGORY_COLORS[marker.category] || CATEGORY_COLORS['default'];
  const icon = createColoredIcon(color);
  const lm = L.marker([marker.lat, marker.lng], { icon }).addTo(map);
  const popupContent = '<b>' + escapeHtml(marker.title) + '</b>' +
    (marker.description ? '<br>' + escapeHtml(marker.description) : '') +
    '<br><small style="color:#888">' + marker.category + '</small>';
  lm.bindPopup(popupContent);
  leafletMarkers[marker.id] = lm;
};

const addCircleToMap = (circle) => {
  const lc = L.circle([circle.lat, circle.lng], {
    radius: circle.radius,
    color: circle.color,
    fillColor: circle.color,
    fillOpacity: 0.15,
    weight: 2,
  }).addTo(map);
  if (circle.label) lc.bindPopup(escapeHtml(circle.label));
  leafletCircles[circle.id] = lc;
};

const renderSidebar = (markers) => {
  const container = document.getElementById('marker-list');
  const grouped = {};
  markers.forEach((m) => {
    if (!grouped[m.category]) grouped[m.category] = [];
    grouped[m.category].push(m);
  });

  let html = '';
  Object.entries(CATEGORY_COLORS).forEach(([cat, color]) => {
    if (!grouped[cat] || grouped[cat].length === 0) return;
    html += '<div style="margin-bottom:12px;">';
    html += '<div style="display:flex;align-items:center;gap:8px;padding:6px 8px;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:0.05em;color:#94a3b8;">';
    html += '<span style="width:10px;height:10px;border-radius:50%;background:' + color + ';display:inline-block;"></span>';
    html += cat + ' (' + grouped[cat].length + ')';
    html += '</div>';
    grouped[cat].forEach((m) => {
      html += '<div class="marker-item" style="padding:10px 12px;border-radius:6px;cursor:pointer;margin-bottom:4px;background:#273548;" onclick="flyToMarker(\\''+m.id+'\\')">';
      html += '<button style="float:right;background:none;border:none;color:#ef4444;cursor:pointer;font-size:14px;padding:0 4px;" onclick="event.stopPropagation();removeMarker(\\''+m.id+'\\')">x</button>';
      html += '<div style="font-size:14px;font-weight:500;color:#f1f5f9;">' + escapeHtml(m.title) + '</div>';
      html += '<div style="font-size:12px;color:#64748b;margin-top:2px;">' + m.lat.toFixed(4) + ', ' + m.lng.toFixed(4) + '</div>';
      html += '</div>';
    });
    html += '</div>';
  });

  if (html === '') {
    html = '<div style="padding:20px;text-align:center;color:#64748b;font-size:14px;">No markers yet. Click "+ Marker" to add one.</div>';
  }
  container.innerHTML = html;
};

const flyToMarker = (id) => {
  const lm = leafletMarkers[id];
  if (lm) {
    map.flyTo(lm.getLatLng(), 15);
    lm.openPopup();
  }
};

const removeMarker = async (id) => {
  await fetch('/api/markers/' + id, { method: 'DELETE' });
  loadData();
};

const openMarkerModal = () => {
  pendingClickTarget = 'marker';
  const center = map.getCenter();
  document.getElementById('marker-lat').value = center.lat.toFixed(6);
  document.getElementById('marker-lng').value = center.lng.toFixed(6);
  document.getElementById('marker-title').value = '';
  document.getElementById('marker-desc').value = '';
  document.getElementById('marker-category').value = 'default';
  const modal = document.getElementById('marker-modal');
  modal.style.display = 'flex';
  activeModal = modal;
  document.getElementById('marker-title').focus();
};

const openCircleModal = () => {
  pendingClickTarget = 'circle';
  const center = map.getCenter();
  document.getElementById('circle-lat').value = center.lat.toFixed(6);
  document.getElementById('circle-lng').value = center.lng.toFixed(6);
  document.getElementById('circle-label').value = '';
  document.getElementById('circle-color').value = '#3b82f6';
  document.getElementById('circle-radius').value = '500';
  const modal = document.getElementById('circle-modal');
  modal.style.display = 'flex';
  activeModal = modal;
  document.getElementById('circle-label').focus();
};

const closeModals = () => {
  document.getElementById('marker-modal').style.display = 'none';
  document.getElementById('circle-modal').style.display = 'none';
  pendingClickTarget = null;
  activeModal = null;
};

const submitMarker = async () => {
  const title = document.getElementById('marker-title').value.trim();
  if (!title) { alert('Title is required'); return; }
  const body = {
    title,
    description: document.getElementById('marker-desc').value.trim(),
    category: document.getElementById('marker-category').value,
    lat: parseFloat(document.getElementById('marker-lat').value),
    lng: parseFloat(document.getElementById('marker-lng').value),
  };
  await fetch('/api/markers', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });
  closeModals();
  loadData();
};

const submitCircle = async () => {
  const body = {
    label: document.getElementById('circle-label').value.trim(),
    color: document.getElementById('circle-color').value,
    radius: parseFloat(document.getElementById('circle-radius').value),
    lat: parseFloat(document.getElementById('circle-lat').value),
    lng: parseFloat(document.getElementById('circle-lng').value),
  };
  await fetch('/api/circles', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });
  closeModals();
  loadData();
};

const escapeHtml = (str) => {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
};

document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') closeModals();
});

document.addEventListener('DOMContentLoaded', init);
`;

import { handleApiRequest } from './routes';
import { renderPage } from './render';

const PORT = 3000;

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url);
    const pathname = url.pathname;

    // API routes
    if (pathname.startsWith('/api/')) {
      const response = await handleApiRequest(req, pathname);
      if (response) return response;
      return new Response(JSON.stringify({ error: 'Not found' }), {
        status: 404,
        headers: { 'Content-Type': 'application/json' },
      });
    }

    // Serve the map page
    if (pathname === '/' || pathname === '/index.html') {
      const html = renderPage();
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    return new Response('Not found', { status: 404 });
  },
});

