export type Category = "Length" | "Weight" | "Temperature" | "Volume" | "Time";

export type UnitDef = {
  symbol: string;
  name: string;
  toBase: (v: number) => number;
  fromBase: (v: number) => number;
  formulaToBase: string;
  formulaFromBase: string;
};

export type CategoryDef = {
  baseUnit: string;
  units: Record<string, UnitDef>;
};

export type ConversionResult = {
  result: number;
  formula: string;
};

const linear = (factor: number, symbol: string, name: string): UnitDef => ({
  symbol,
  name,
  toBase: (v) => v * factor,
  fromBase: (v) => v / factor,
  formulaToBase: `× ${factor}`,
  formulaFromBase: `÷ ${factor}`,
});

const categories: Record<Category, CategoryDef> = {
  Length: {
    baseUnit: "m",
    units: {
      mm: linear(0.001, "mm", "Millimeter"),
      cm: linear(0.01, "cm", "Centimeter"),
      m: linear(1, "m", "Meter"),
      km: linear(1000, "km", "Kilometer"),
      in: linear(0.0254, "in", "Inch"),
      ft: linear(0.3048, "ft", "Foot"),
      yd: linear(0.9144, "yd", "Yard"),
      mi: linear(1609.344, "mi", "Mile"),
    },
  },
  Weight: {
    baseUnit: "g",
    units: {
      mg: linear(0.001, "mg", "Milligram"),
      g: linear(1, "g", "Gram"),
      kg: linear(1000, "kg", "Kilogram"),
      lb: linear(453.592, "lb", "Pound"),
      oz: linear(28.3495, "oz", "Ounce"),
    },
  },
  Temperature: {
    baseUnit: "K",
    units: {
      C: {
        symbol: "°C",
        name: "Celsius",
        toBase: (v) => v + 273.15,
        fromBase: (v) => v - 273.15,
        formulaToBase: "+ 273.15",
        formulaFromBase: "− 273.15",
      },
      F: {
        symbol: "°F",
        name: "Fahrenheit",
        toBase: (v) => (v - 32) * (5 / 9) + 273.15,
        fromBase: (v) => (v - 273.15) * (9 / 5) + 32,
        formulaToBase: "(v − 32) × 5/9 + 273.15",
        formulaFromBase: "(v − 273.15) × 9/5 + 32",
      },
      K: {
        symbol: "K",
        name: "Kelvin",
        toBase: (v) => v,
        fromBase: (v) => v,
        formulaToBase: "v",
        formulaFromBase: "v",
      },
    },
  },
  Volume: {
    baseUnit: "ml",
    units: {
      ml: linear(1, "ml", "Milliliter"),
      l: linear(1000, "l", "Liter"),
      gal: linear(3785.41, "gal", "Gallon"),
      qt: linear(946.353, "qt", "Quart"),
      pt: linear(473.176, "pt", "Pint"),
      cup: linear(236.588, "cup", "Cup"),
      tbsp: linear(14.7868, "tbsp", "Tablespoon"),
      tsp: linear(4.92892, "tsp", "Teaspoon"),
    },
  },
  Time: {
    baseUnit: "s",
    units: {
      ms: linear(0.001, "ms", "Millisecond"),
      s: linear(1, "s", "Second"),
      min: linear(60, "min", "Minute"),
      hr: linear(3600, "hr", "Hour"),
      day: linear(86400, "day", "Day"),
      week: linear(604800, "week", "Week"),
    },
  },
};

export const getCategories = (): Category[] =>
  Object.keys(categories) as Category[];

export const getUnits = (category: Category): UnitDef[] =>
  Object.values(categories[category].units);

export const getUnitKeys = (category: Category): string[] =>
  Object.keys(categories[category].units);

const buildFormula = (
  value: number,
  from: string,
  to: string,
  category: Category,
): string => {
  const cat = categories[category];
  const fromDef = cat.units[from];
  const toDef = cat.units[to];

  if (from === to) return `${value} ${fromDef.symbol} = ${value} ${toDef.symbol} (same unit)`;

  if (category === "Temperature") {
    return buildTemperatureFormula(value, from, to, fromDef, toDef);
  }

  const fromFactor = fromDef.toBase(1);
  const toFactor = toDef.toBase(1);
  const ratio = fromFactor / toFactor;

  return `${value} ${fromDef.symbol} × (${fromFactor} ${cat.baseUnit}/${fromDef.symbol}) ÷ (${toFactor} ${cat.baseUnit}/${toDef.symbol}) = ${value} × ${roundSmart(ratio)} = ${roundSmart(value * ratio)} ${toDef.symbol}`;
};

const buildTemperatureFormula = (
  value: number,
  from: string,
  to: string,
  fromDef: UnitDef,
  toDef: UnitDef,
): string => {
  const steps: string[] = [];

  if (from === "C" && to === "F") {
    const result = value * (9 / 5) + 32;
    steps.push(`${value} °C × 9/5 + 32 = ${roundSmart(result)} °F`);
  } else if (from === "F" && to === "C") {
    const result = (value - 32) * (5 / 9);
    steps.push(`(${value} °F − 32) × 5/9 = ${roundSmart(result)} °C`);
  } else if (from === "C" && to === "K") {
    const result = value + 273.15;
    steps.push(`${value} °C + 273.15 = ${roundSmart(result)} K`);
  } else if (from === "K" && to === "C") {
    const result = value - 273.15;
    steps.push(`${value} K − 273.15 = ${roundSmart(result)} °C`);
  } else if (from === "F" && to === "K") {
    const result = (value - 32) * (5 / 9) + 273.15;
    steps.push(`(${value} °F − 32) × 5/9 + 273.15 = ${roundSmart(result)} K`);
  } else if (from === "K" && to === "F") {
    const result = (value - 273.15) * (9 / 5) + 32;
    steps.push(`(${value} K − 273.15) × 9/5 + 32 = ${roundSmart(result)} °F`);
  }

  return steps.join("");
};

const roundSmart = (n: number): string => {
  if (Number.isInteger(n)) return n.toString();
  const rounded = Math.round(n * 1e8) / 1e8;
  return rounded.toString();
};

export const convert = (
  value: number,
  fromUnit: string,
  toUnit: string,
  category: Category,
): ConversionResult => {
  const cat = categories[category];
  const fromDef = cat.units[fromUnit];
  const toDef = cat.units[toUnit];

  if (!fromDef || !toDef) {
    throw new Error(`Unknown unit: ${fromUnit} or ${toUnit} in ${category}`);
  }

  const baseValue = fromDef.toBase(value);
  const result = toDef.fromBase(baseValue);

  return {
    result: Math.round(result * 1e8) / 1e8,
    formula: buildFormula(value, fromUnit, toUnit, category),
  };
};

