export const renderConverter = (
  activeCategory: Category = "Length",
  value: number = 1,
  fromUnit?: string,
  toUnit?: string,
): string => {
  const allCategories = getCategories();
  const unitKeys = getUnitKeys(activeCategory);

  const from = fromUnit && unitKeys.includes(fromUnit) ? fromUnit : unitKeys[0];
  const to = toUnit && unitKeys.includes(toUnit) ? toUnit : unitKeys[1] ?? unitKeys[0];

  let conversionResult: ConversionResult;
  try {
    conversionResult = convert(value, from, to, activeCategory);
  } catch {
    conversionResult = { result: 0, formula: "Invalid conversion" };
  }

  const units = getUnits(activeCategory);
  const fromDef = units[unitKeys.indexOf(from)];
  const toDef = units[unitKeys.indexOf(to)];

  const template = h(
    "div",
    { style: styleToString(styles.container) },
    h("div", { style: styleToString(styles.title) }, "Unit Converter"),
    h(
      "div",
      { style: styleToString(styles.tabs), "p-target": "tabs" },
      ...allCategories.map((cat) =>
        h(
          "button",
          {
            style: styleToString(
              cat === activeCategory ? styles.tabActive : styles.tab
            ),
            "p-trigger": `category-select:${cat}`,
          },
          cat
        )
      )
    ),
    h(
      "div",
      { style: styleToString(styles.formRow) },
      h(
        "div",
        { style: styleToString(styles.inputGroup) },
        h("label", { style: styleToString(styles.label) }, "Value"),
        h("input", {
          type: "number",
          value: String(value),
          style: styleToString(styles.input),
          "p-trigger": "value-input",
          "p-target": "value-input",
          step: "any",
        })
      ),
      h(
        "div",
        { style: styleToString(styles.inputGroup) },
        h("label", { style: styleToString(styles.label) }, "From"),
        h(
          "select",
          {
            style: styleToString(styles.select),
            "p-trigger": "from-change",
            "p-target": "from-select",
          },
          ...unitKeys.map((key, i) =>
            h(
              "option",
              {
                value: key,
                ...(key === from ? { selected: "selected" } : {}),
              },
              `${units[i].symbol} — ${units[i].name}`
            )
          )
        )
      ),
      h("div", { style: styleToString(styles.arrow) }, "→"),
      h(
        "div",
        { style: styleToString(styles.inputGroup) },
        h("label", { style: styleToString(styles.label) }, "To"),
        h(
          "select",
          {
            style: styleToString(styles.select),
            "p-trigger": "to-change",
            "p-target": "to-select",
          },
          ...unitKeys.map((key, i) =>
            h(
              "option",
              {
                value: key,
                ...(key === to ? { selected: "selected" } : {}),
              },
              `${units[i].symbol} — ${units[i].name}`
            )
          )
        )
      )
    ),
    h(
      "div",
      { style: styleToString(styles.resultBox), "p-target": "result" },
      h(
        "div",
        { style: styleToString(styles.resultValue) },
        `${value} ${fromDef.symbol} = ${conversionResult.result} ${toDef.symbol}`
      ),
      h(
        "div",
        {},
        h("div", { style: styleToString(styles.formulaLabel) }, "Formula"),
        h(
          "div",
          { style: styleToString(styles.formulaBox) },
          conversionResult.formula
        )
      )
    )
  );

  return template;
};

import { type Category, convert, getCategories, getUnitKeys, getUnits } from "./converter.ts";
import { renderConverter } from "./ui.ts";

export {
  convert,
  getCategories,
  getUnitKeys,
  getUnits,
  renderConverter,
};

export type { Category };

const main = () => {
  const args = process.argv.slice(2);

  if (args.length === 0) {
    console.log(renderConverter());
    return;
  }

  if (args.length < 4) {
    console.log("Usage: unit-converter <value> <fromUnit> <toUnit> <category>");
    console.log("Categories:", getCategories().join(", "));
    return;
  }

  const [rawValue, fromUnit, toUnit, category] = args;
  const value = parseFloat(rawValue);

  if (isNaN(value)) {
    console.error("Error: value must be a number");
    process.exit(1);
  }

  const validCategories = getCategories();
  if (!validCategories.includes(category as Category)) {
    console.error(`Error: unknown category "${category}". Valid: ${validCategories.join(", ")}`);
    process.exit(1);
  }

  const result = convert(value, fromUnit, toUnit, category as Category);
  console.log(`${value} ${fromUnit} = ${result.result} ${toUnit}`);
  console.log(`Formula: ${result.formula}`);
};

main();

