import type { CalendarEvent } from './types';

const DATA_PATH = `${import.meta.dir}/data/events.jsonl`;

const generateId = (): string => {
  const timestamp = Date.now().toString(36);
  const random = Math.random().toString(36).slice(2, 8);
  return `${timestamp}-${random}`;
};

const readAllEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) return [];

  const text = await file.text();
  if (!text.trim()) return [];

  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as CalendarEvent);
};

const writeAllEvents = async (events: CalendarEvent[]): Promise<void> => {
  const content = events.map((e) => JSON.stringify(e)).join('\n');
  await Bun.write(DATA_PATH, content ? content + '\n' : '');
};

export const getEvents = async (): Promise<CalendarEvent[]> => {
  return readAllEvents();
};

export const getEventById = async (id: string): Promise<CalendarEvent | undefined> => {
  const events = await readAllEvents();
  return events.find((e) => e.id === id);
};

export const createEvent = async (
  data: Omit<CalendarEvent, 'id' | 'createdAt'>
): Promise<CalendarEvent> => {
  const event: CalendarEvent = {
    ...data,
    id: generateId(),
    createdAt: new Date().toISOString(),
  };
  const events = await readAllEvents();
  events.push(event);
  await writeAllEvents(events);
  return event;
};

export const updateEvent = async (
  id: string,
  data: Partial<Omit<CalendarEvent, 'id' | 'createdAt'>>
): Promise<CalendarEvent | null> => {
  const events = await readAllEvents();
  const index = events.findIndex((e) => e.id === id);
  if (index === -1) return null;

  events[index] = { ...events[index], ...data };
  await writeAllEvents(events);
  return events[index];
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await readAllEvents();
  const filtered = events.filter((e) => e.id !== id);
  if (filtered.length === events.length) return false;
  await writeAllEvents(filtered);
  return true;
};

import type { CalendarEvent, CalendarDay, MonthGrid, RecurrenceRule, EventCategory } from './types';

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

const formatDate = (year: number, month: number, day: number): string => {
  const m = String(month + 1).padStart(2, '0');
  const d = String(day).padStart(2, '0');
  return `${year}-${m}-${d}`;
};

const parseDate = (dateStr: string): { year: number; month: number; day: number } => {
  const [year, month, day] = dateStr.split('-').map(Number);
  return { year, month: month - 1, day };
};

const todayString = (): string => {
  const now = new Date();
  return formatDate(now.getFullYear(), now.getMonth(), now.getDate());
};

const matchesRecurrence = (event: CalendarEvent, targetDate: string): boolean => {
  if (event.recurrence === 'none') return event.date === targetDate;

  const origin = parseDate(event.date);
  const target = parseDate(targetDate);
  const originD = new Date(origin.year, origin.month, origin.day);
  const targetD = new Date(target.year, target.month, target.day);

  // Recurrence only applies on or after the original date
  if (targetD < originD) return false;

  switch (event.recurrence) {
    case 'daily':
      return true;
    case 'weekly': {
      return originD.getDay() === targetD.getDay();
    }
    case 'monthly': {
      return origin.day === target.day;
    }
    default:
      return false;
  }
};

export const getEventsForDate = (
  events: CalendarEvent[],
  date: string,
  categoryFilter?: Set<EventCategory>
): CalendarEvent[] => {
  return events
    .filter((e) => {
      if (categoryFilter && categoryFilter.size > 0 && !categoryFilter.has(e.category)) {
        return false;
      }
      return matchesRecurrence(e, date);
    })
    .sort((a, b) => a.startTime.localeCompare(b.startTime));
};

export const buildMonthGrid = (
  year: number,
  month: number,
  events: CalendarEvent[],
  categoryFilter?: Set<EventCategory>
): MonthGrid => {
  const today = todayString();
  const firstDay = new Date(year, month, 1);
  const startDow = firstDay.getDay(); // 0=Sun
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  // Previous month fill
  const prevMonthDays = new Date(year, month, 0).getDate();

  const weeks: CalendarDay[][] = [];
  let currentWeek: CalendarDay[] = [];

  // Fill leading days from previous month
  for (let i = startDow - 1; i >= 0; i--) {
    const day = prevMonthDays - i;
    const prevMonth = month === 0 ? 11 : month - 1;
    const prevYear = month === 0 ? year - 1 : year;
    const date = formatDate(prevYear, prevMonth, day);
    currentWeek.push({
      date,
      dayOfMonth: day,
      isCurrentMonth: false,
      isToday: date === today,
      events: getEventsForDate(events, date, categoryFilter),
    });
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const date = formatDate(year, month, day);
    currentWeek.push({
      date,
      dayOfMonth: day,
      isCurrentMonth: true,
      isToday: date === today,
      events: getEventsForDate(events, date, categoryFilter),
    });

    if (currentWeek.length === 7) {
      weeks.push(currentWeek);
      currentWeek = [];
    }
  }

  // Fill trailing days from next month
  if (currentWeek.length > 0) {
    let nextDay = 1;
    const nextMonth = month === 11 ? 0 : month + 1;
    const nextYear = month === 11 ? year + 1 : year;
    while (currentWeek.length < 7) {
      const date = formatDate(nextYear, nextMonth, nextDay);
      currentWeek.push({
        date,
        dayOfMonth: nextDay,
        isCurrentMonth: false,
        isToday: date === today,
        events: getEventsForDate(events, date, categoryFilter),
      });
      nextDay++;
    }
    weeks.push(currentWeek);
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  };
};

