const renderEventPreviews = (events: CalendarEvent[]) => {
  const shown = events.slice(0, 2);
  const remaining = events.length - shown.length;

  return h(Fragment, {},
    ...shown.map((evt) =>
      h('div', {
        style: {
          ...styles.eventPreview,
          backgroundColor: CATEGORY_COLORS[evt.category],
