    ),
    ...(remaining > 0
      ? [h('div', { style: { fontSize: '0.65rem', color: '#6b7280' } }, `+${remaining} more`)]
      : [])
  );
};

const renderDayCell = (day: CalendarDay) => {
  const cellStyle = {
    ...styles.dayCell,
    ...(!day.isCurrentMonth ? styles.dayCellOther : {}),
