import { createSSR } from 'plaited';
import type { CalendarEvent, EventCategory, EventFormData, ViewState } from './types';
import { ALL_CATEGORIES } from './types';
import { getEvents, createEvent, updateEvent, deleteEvent, getEventById } from './store';
import { buildMonthGrid, getEventsForDate, todayString } from './calendar';
import { renderMonthView, renderDayView } from './views';

// --- State ---

const state: ViewState = (() => {
  const now = new Date();
  return {
    view: 'month' as const,
    year: now.getFullYear(),
    month: now.getMonth(),
    selectedDate: null,
    categoryFilter: new Set<EventCategory>(),
  };
})();

let showForm = false;
let editingEvent: CalendarEvent | null = null;

// --- Actions ---

export const navigateMonth = (direction: -1 | 1): void => {
  state.month += direction;
  if (state.month < 0) {
    state.month = 11;
    state.year -= 1;
  } else if (state.month > 11) {
    state.month = 0;
    state.year += 1;
  }
};

export const selectDay = (date: string): void => {
  state.view = 'day';
  state.selectedDate = date;
  showForm = false;
  editingEvent = null;
};

export const backToMonth = (): void => {
  state.view = 'month';
  state.selectedDate = null;
  showForm = false;
  editingEvent = null;
};

export const toggleCategory = (category: EventCategory): void => {
  if (state.categoryFilter.has(category)) {
    state.categoryFilter.delete(category);
  } else {
    state.categoryFilter.add(category);
  }
};

export const showAddForm = (): void => {
  showForm = true;
  editingEvent = null;
};

export const hideForm = (): void => {
  showForm = false;
  editingEvent = null;
};

export const startEditEvent = async (eventId: string): Promise<void> => {
  const event = await getEventById(eventId);
  if (event) {
    editingEvent = event;
    showForm = true;
  }
};

export const handleCreateEvent = async (formData: EventFormData): Promise<CalendarEvent> => {
  const event = await createEvent({
    title: formData.title,
    date: formData.date,
    startTime: formData.startTime,
    endTime: formData.endTime,
    description: formData.description,
    category: formData.category,
    recurrence: formData.recurrence,
  });
  showForm = false;
  editingEvent = null;
  return event;
};

export const handleUpdateEvent = async (
  eventId: string,
  formData: EventFormData
): Promise<CalendarEvent | null> => {
  const updated = await updateEvent(eventId, {
    title: formData.title,
    date: formData.date,
    startTime: formData.startTime,
    endTime: formData.endTime,
    description: formData.description,
    category: formData.category,
    recurrence: formData.recurrence,
  });
  showForm = false;
  editingEvent = null;
  return updated;
};

export const handleDeleteEvent = async (eventId: string): Promise<boolean> => {
  return deleteEvent(eventId);
};

// --- Render ---

export const render = async (): Promise<string> => {
  const ssr = createSSR();
  const events = await getEvents();

  if (state.view === 'month') {
    const grid = buildMonthGrid(
      state.year,
      state.month,
      events,
      state.categoryFilter.size > 0 ? state.categoryFilter : undefined
    );
    const template = renderMonthView(grid, state.categoryFilter);
    return ssr(template);
  }

  // Day view
  const dayEvents = getEventsForDate(
    events,
    state.selectedDate!,
    state.categoryFilter.size > 0 ? state.categoryFilter : undefined
  );
  const template = renderDayView(state.selectedDate!, dayEvents, showForm, editingEvent);
  return ssr(template);
};

// --- Route handler ---

export const handleAction = async (
  action: string,
  payload?: Record<string, string>
): Promise<string> => {
  switch (action) {
    case 'prevMonth':
      navigateMonth(-1);
      break;
    case 'nextMonth':
      navigateMonth(1);
      break;
    case 'selectDay':
      selectDay(payload?.date ?? todayString());
      break;
    case 'backToMonth':
      backToMonth();
      break;
    case 'toggleCategory':
      toggleCategory(payload?.category as EventCategory);
      break;
    case 'showAddForm':
      showAddForm();
      break;
    case 'hideForm':
      hideForm();
      break;
    case 'editEvent':
      await startEditEvent(payload?.id ?? '');
      break;
    case 'createEvent':
      await handleCreateEvent(payload as unknown as EventFormData);
      break;
    case 'updateEvent':
      await handleUpdateEvent(payload?.id ?? '', payload as unknown as EventFormData);
      break;
    case 'deleteEvent':
      await handleDeleteEvent(payload?.id ?? '');
      break;
    default:
      break;
  }
  return render();
};

// Default export for module entry
export default {
  render,
  handleAction,
  navigateMonth,
  selectDay,
  backToMonth,
  toggleCategory,
  showAddForm,
  hideForm,
  startEditEvent,
  handleCreateEvent,
  handleUpdateEvent,
  handleDeleteEvent,
};

{
  "name": "@node/markdown-editor",
  "version": "1.0.0",
  "description": "A markdown editor with live preview, toolbar, and document management",
  "main": "index.ts",
  "modnet": {
    "contentType": "tools",
    "structure": "form",
    "mechanics": ["sort", "filter"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // Images (before links so ![...](...) isn't caught by link regex)
  result = result.replace(
    /!\[([^\]]*)\]\(([^)]+)\)/g,
    '<img src="$2" alt="$1" style="max-width:100%;" />'
  )
  // Links
  result = result.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    '<a href="$2" target="_blank" rel="noopener">$1</a>'
  )
  // Bold + Italic
  result = result.replace(
    /\*\*\*(.+?)\*\*\*/g,
    '<strong><em>$1</em></strong>'
  )
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  return result
}

const parseTable = (lines: string[]): { html: string; consumed: number } => {
  if (lines.length < 2) return { html: '', consumed: 0 }

  const parseCells = (row: string): string[] =>
    row
      .replace(/^\|/, '')
      .replace(/\|$/, '')
      .split('|')
      .map((c) => c.trim())

  const headerCells = parseCells(lines[0])
  const separatorLine = lines[1].trim()

  if (!/^\|?[\s-:|]+\|?$/.test(separatorLine)) {
    return { html: '', consumed: 0 }
  }

  const alignments = parseCells(separatorLine).map((sep) => {
    const left = sep.startsWith(':')
    const right = sep.endsWith(':')
    if (left && right) return 'center'
    if (right) return 'right'
    if (left) return 'left'
    return ''
  })

  const styleFor = (i: number): string => {
    const a = alignments[i]
    return a ? ` style="text-align:${a}"` : ''
  }

  let html = '<table><thead><tr>'
  headerCells.forEach((cell, i) => {
    html += `<th${styleFor(i)}>${parseInline(escapeHtml(cell))}</th>`
  })
  html += '</tr></thead><tbody>'

  let consumed = 2
  for (let i = 2; i < lines.length; i++) {
    const line = lines[i].trim()
    if (!line.includes('|')) break
    const cells = parseCells(line)
    html += '<tr>'
    cells.forEach((cell, ci) => {
      html += `<td${styleFor(ci)}>${parseInline(escapeHtml(cell))}</td>`
    })
    html += '</tr>'
    consumed++
  }

  html += '</tbody></table>'
  return { html, consumed }
}

export const parseMarkdown = (source: string): string => {
  const lines = source.split('\n')
  const output: string[] = []
  let i = 0

  const flushParagraph = (text: string) => {
    if (text.trim()) {
      output.push(`<p>${parseInline(escapeHtml(text.trim()))}</p>`)
    }
  }

  let paragraphBuffer = ''

  const flushBuffer = () => {
    if (paragraphBuffer) {
      flushParagraph(paragraphBuffer)
      paragraphBuffer = ''
    }
  }

  while (i < lines.length) {
    const line = lines[i]
    const trimmed = line.trim()

    // Empty line
    if (!trimmed) {
      flushBuffer()
      i++
      continue
    }

    // Fenced code block
    if (trimmed.startsWith('```')) {
      flushBuffer()
      const lang = trimmed.slice(3).trim()
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].trim().startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      i++ // skip closing ```
      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : ''
      output.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      continue
    }

    // Headings
    const headingMatch = trimmed.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      flushBuffer()
      const level = headingMatch[1].length
      const text = headingMatch[2]
      output.push(
        `<h${level}>${parseInline(escapeHtml(text))}</h${level}>`
      )
      i++
      continue
    }

    // Horizontal rule
    if (/^(-{3,}|\*{3,}|_{3,})$/.test(trimmed)) {
      flushBuffer()
      output.push('<hr />')
      i++
      continue
    }

    // Table
    if (trimmed.includes('|') && i + 1 < lines.length && lines[i + 1].includes('|')) {
      const tableResult = parseTable(lines.slice(i))
      if (tableResult.consumed > 0) {
        flushBuffer()
        output.push(tableResult.html)
        i += tableResult.consumed
        continue
      }
    }

    // Blockquote
    if (trimmed.startsWith('> ') || trimmed === '>') {
      flushBuffer()
      const quoteLines: string[] = []
      while (i < lines.length) {
        const ql = lines[i].trim()
        if (ql.startsWith('> ')) {
          quoteLines.push(ql.slice(2))
        } else if (ql === '>') {
          quoteLines.push('')
        } else {
          break
        }
        i++
      }
      output.push(`<blockquote>${parseMarkdown(quoteLines.join('\n'))}</blockquote>`)
      continue
    }

    // Unordered list
    if (/^[-*+]\s+/.test(trimmed)) {
      flushBuffer()
      const items: string[] = []
      while (i < lines.length) {
        const ulMatch = lines[i].trim().match(/^[-*+]\s+(.+)$/)
        if (ulMatch) {
          items.push(ulMatch[1])
          i++
        } else {
          break
        }
      }
      output.push(
        `<ul>${items.map((item) => `<li>${parseInline(escapeHtml(item))}</li>`).join('')}</ul>`
      )
      continue
    }

    // Ordered list
    if (/^\d+\.\s+/.test(trimmed)) {
      flushBuffer()
      const items: string[] = []
      while (i < lines.length) {
        const olMatch = lines[i].trim().match(/^\d+\.\s+(.+)$/)
        if (olMatch) {
          items.push(olMatch[1])
          i++
        } else {
          break
        }
      }
      output.push(
        `<ol>${items.map((item) => `<li>${parseInline(escapeHtml(item))}</li>`).join('')}</ol>`
      )
      continue
    }

    // Regular text — accumulate into paragraph
    paragraphBuffer += (paragraphBuffer ? ' ' : '') + trimmed
    i++
  }

  flushBuffer()
  return output.join('\n')
}

import type { Document } from './types'

const DATA_PATH = `${import.meta.dir}/data/documents.json`

export const loadDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Document[]
}

export const saveDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

export const createDocument = async (
  title: string,
  content: string
): Promise<Document> => {
  const docs = await loadDocuments()
  const now = new Date().toISOString()
  const doc: Document = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await saveDocuments(docs)
  return doc
}

export const updateDocument = async (
  id: string,
  title: string,
  content: string
): Promise<Document | null> => {
  const docs = await loadDocuments()
  const idx = docs.findIndex((d) => d.id === id)
  if (idx === -1) return null
  docs[idx] = {
    ...docs[idx],
    title,
    content,
    updatedAt: new Date().toISOString(),
  }
  await saveDocuments(docs)
  return docs[idx]
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await loadDocuments()
  const filtered = docs.filter((d) => d.id !== id)
  if (filtered.length === docs.length) return false
  await saveDocuments(filtered)
  return true
}

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await loadDocuments()
  return docs.find((d) => d.id === id) ?? null
}

export const listDocuments = async (
  sortBy: 'title' | 'updatedAt' = 'updatedAt',
  filterText?: string
): Promise<Document[]> => {
  let docs = await loadDocuments()
  if (filterText) {
    const lower = filterText.toLowerCase()
    docs = docs.filter(
      (d) =>
        d.title.toLowerCase().includes(lower) ||
        d.content.toLowerCase().includes(lower)
    )
  }
  docs.sort((a, b) => {
    if (sortBy === 'title') return a.title.localeCompare(b.title)
    return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
  })
  return docs
}

