          `
          (() => {
            const editor = document.querySelector('[p-target="editor"]');
            const preview = document.querySelector('[p-target="preview"]');
            const titleInput = document.querySelector('[p-target="title-input"]');

            ${/* Inline the markdown parser for client-side use */ ''}
            const escapeHtml = (t) => t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

            const parseInline = (t) => {
              let r = t;
              r = r.replace(/!\\[([^\\]]*)\\]\\(([^)]+)\\)/g, '<img src="$2" alt="$1" style="max-width:100%" />');
              r = r.replace(/\\[([^\\]]+)\\]\\(([^)]+)\\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>');
              r = r.replace(/\\*\\*\\*(.+?)\\*\\*\\*/g, '<strong><em>$1</em></strong>');
              r = r.replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>');
              r = r.replace(/\\*(.+?)\\*/g, '<em>$1</em>');
              r = r.replace(/~~(.+?)~~/g, '<del>$1</del>');
              r = r.replace(/\`([^\`]+)\`/g, '<code>$1</code>');
              return r;
            };

            const parseTable = (lines) => {
              if (lines.length < 2) return { html: '', consumed: 0 };
              const parseCells = (row) => row.replace(/^\\|/,'').replace(/\\|$/,'').split('|').map(c => c.trim());
              const hCells = parseCells(lines[0]);
              if (!/^\\|?[\\s\\-:|]+\\|?$/.test(lines[1].trim())) return { html: '', consumed: 0 };
              const aligns = parseCells(lines[1]).map(s => { const l=s.startsWith(':'),r=s.endsWith(':'); if(l&&r)return'center';if(r)return'right';if(l)return'left';return''; });
              const sf = (i) => { const a=aligns[i]; return a ? ' style="text-align:'+a+'"':''; };
              let h = '<table><thead><tr>';
              hCells.forEach((c,i) => { h += '<th'+sf(i)+'>'+parseInline(escapeHtml(c))+'</th>'; });
              h += '</tr></thead><tbody>';
              let consumed = 2;
              for (let i=2;i<lines.length;i++) { const ln=lines[i].trim(); if(!ln.includes('|'))break; const cells=parseCells(ln); h+='<tr>'; cells.forEach((c,ci)=>{h+='<td'+sf(ci)+'>'+parseInline(escapeHtml(c))+'</td>';}); h+='</tr>'; consumed++; }
              h += '</tbody></table>';
              return { html: h, consumed };
            };

            const parseMd = (src) => {
              const lines = src.split('\\n');
              const out = [];
              let i = 0, buf = '';
              const flush = () => { if(buf){out.push('<p>'+parseInline(escapeHtml(buf.trim()))+'</p>');buf='';} };
              while (i < lines.length) {
                const line = lines[i], tr = line.trim();
                if (!tr) { flush(); i++; continue; }
                if (tr.startsWith('\`\`\`')) { flush(); const lang=tr.slice(3).trim(); const cl=[]; i++; while(i<lines.length&&!lines[i].trim().startsWith('\`\`\`')){cl.push(escapeHtml(lines[i]));i++;} i++; const la=lang?' class="language-'+escapeHtml(lang)+'"':''; out.push('<pre><code'+la+'>'+cl.join('\\n')+'</code></pre>'); continue; }
                const hm = tr.match(/^(#{1,6})\\s+(.+)$/);
                if (hm) { flush(); const lv=hm[1].length; out.push('<h'+lv+'>'+parseInline(escapeHtml(hm[2]))+'</h'+lv+'>'); i++; continue; }
                if (/^(-{3,}|\\*{3,}|_{3,})$/.test(tr)) { flush(); out.push('<hr />'); i++; continue; }
                if (tr.includes('|') && i+1<lines.length && lines[i+1].includes('|')) { const r=parseTable(lines.slice(i)); if(r.consumed>0){flush();out.push(r.html);i+=r.consumed;continue;} }
                if (tr.startsWith('> ')||tr==='>') { flush(); const ql=[]; while(i<lines.length){const q=lines[i].trim();if(q.startsWith('> ')){ql.push(q.slice(2));}else if(q==='>'){ql.push('');}else break;i++;} out.push('<blockquote>'+parseMd(ql.join('\\n'))+'</blockquote>'); continue; }
                if (/^[-*+]\\s+/.test(tr)) { flush(); const items=[]; while(i<lines.length){const m=lines[i].trim().match(/^[-*+]\\s+(.+)$/);if(m){items.push(m[1]);i++;}else break;} out.push('<ul>'+items.map(x=>'<li>'+parseInline(escapeHtml(x))+'</li>').join('')+'</ul>'); continue; }
                if (/^\\d+\\.\\s+/.test(tr)) { flush(); const items=[]; while(i<lines.length){const m=lines[i].trim().match(/^\\d+\\.\\s+(.+)$/);if(m){items.push(m[1]);i++;}else break;} out.push('<ol>'+items.map(x=>'<li>'+parseInline(escapeHtml(x))+'</li>').join('')+'</ol>'); continue; }
                buf += (buf?' ':'')+tr; i++;
              }
              flush();
              return out.join('\\n');
            };

            // Live preview
            if (editor && preview) {
              editor.addEventListener('input', () => {
                preview.innerHTML = parseMd(editor.value);
              });
            }

            // Toolbar actions
            const actions = ${JSON.stringify(
              Object.fromEntries(
                Object.entries({
                  h1: { before: '# ', after: '', placeholder: 'Heading 1' },
                  h2: { before: '## ', after: '', placeholder: 'Heading 2' },
                  h3: { before: '### ', after: '', placeholder: 'Heading 3' },
                  bold: { before: '**', after: '**', placeholder: 'bold text' },
                  italic: { before: '*', after: '*', placeholder: 'italic text' },
                  strikethrough: { before: '~~', after: '~~', placeholder: 'strikethrough' },
                  link: { before: '[', after: '](url)', placeholder: 'link text' },
                  image: { before: '![', after: '](url)', placeholder: 'alt text' },
                  code: { before: '`', after: '`', placeholder: 'code' },
                  codeblock: { before: '\`\`\`\\n', after: '\\n\`\`\`', placeholder: 'code here' },
                  ul: { before: '- ', after: '', placeholder: 'list item' },
                  ol: { before: '1. ', after: '', placeholder: 'list item' },
                  blockquote: { before: '> ', after: '', placeholder: 'quote' },
                  hr: { before: '\\n---\\n', after: '', placeholder: '' },
                  table: {
                    before:
                      '| Header 1 | Header 2 | Header 3 |\\n| -------- | -------- | -------- |\\n| Cell 1   | Cell 2   | Cell 3   |',
                    after: '',
                    placeholder: '',
                  },
                })
              )
            )};

            document.querySelectorAll('[p-trigger^="toolbar:"]').forEach(btn => {
              btn.addEventListener('click', () => {
                const action = btn.getAttribute('p-trigger').split(':')[1];
                const a = actions[action];
                if (!a || !editor) return;
                const start = editor.selectionStart;
                const end = editor.selectionEnd;
                const sel = editor.value.substring(start, end);
                const insert = a.before + (sel || a.placeholder) + a.after;
                editor.setRangeText(insert, start, end, 'end');
                editor.focus();
                editor.dispatchEvent(new Event('input'));
              });
            });

            // Save
            document.querySelector('[p-trigger="save:click"]')?.addEventListener('click', async () => {
              const title = titleInput?.value || 'Untitled';
              const content = editor?.value || '';
              const activeId = document.body.dataset.activeId || '';
              const url = activeId ? '/api/documents/' + activeId : '/api/documents';
              const method = activeId ? 'PUT' : 'POST';
              await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ title, content }),
              });
              location.reload();
            });

            // New document
            document.querySelector('[p-trigger="new:click"]')?.addEventListener('click', () => {
              document.body.dataset.activeId = '';
              if (titleInput) titleInput.value = '';
              if (editor) { editor.value = ''; editor.dispatchEvent(new Event('input')); }
            });

            // Delete
            document.querySelectorAll('[p-trigger^="delete:"]').forEach(btn => {
              btn.addEventListener('click', async () => {
                const id = btn.getAttribute('p-trigger').split(':')[1];
                if (!confirm('Delete this document?')) return;
                await fetch('/api/documents/' + id, { method: 'DELETE' });
                location.reload();
              });
            });

            // Load
            document.querySelectorAll('[p-trigger^="load:"]').forEach(item => {
              item.addEventListener('click', async () => {
                const id = item.getAttribute('p-trigger').split(':')[1];
                const res = await fetch('/api/documents/' + id);
                const doc = await res.json();
                document.body.dataset.activeId = doc.id;
                if (titleInput) titleInput.value = doc.title;
                if (editor) { editor.value = doc.content; editor.dispatchEvent(new Event('input')); }
                document.querySelectorAll('.doc-item').forEach(d => d.style.backgroundColor = '');
                item.style.backgroundColor = '#e7f5ff';
              });
            });

            // Search
            document.querySelector('[p-trigger="search:input"]')?.addEventListener('input', async (e) => {
              const q = e.target.value;
              const res = await fetch('/api/documents?filter=' + encodeURIComponent(q));
              const docs = await res.json();
              const list = document.querySelector('[p-target="doc-list"]') || document.querySelector('[style*="overflow"]');
              // Simple reload approach
              clearTimeout(window._searchTimer);
              window._searchTimer = setTimeout(() => {
                const url = new URL(location.href);
                url.searchParams.set('filter', q);
                location.href = url.toString();
              }, 500);
            });

            // Set active ID
            ${activeDoc ? `document.body.dataset.activeId = '${activeDoc.id}';` : ''}
          })();
        `
        )
      )
    )
  )
}

import { renderEditor } from './render'
import {
  listDocuments,
  getDocument,
  createDocument,
  updateDocument,
  deleteDocument,
} from './documents'

const PORT = Number(process.env.PORT) || 3000

const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  return JSON.parse(text)
}

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // API routes
    if (pathname === '/api/documents' && method === 'GET') {
      const filter = url.searchParams.get('filter') ?? undefined
      const sort = (url.searchParams.get('sort') as 'title' | 'updatedAt') ?? 'updatedAt'
      const docs = await listDocuments(sort, filter)
      return Response.json(docs)
    }

    if (pathname === '/api/documents' && method === 'POST') {
      const body = await parseBody(req)
      const doc = await createDocument(body.title ?? 'Untitled', body.content ?? '')
      return Response.json(doc, { status: 201 })
    }

    if (pathname.startsWith('/api/documents/') && method === 'GET') {
      const id = pathname.split('/').pop()!
      const doc = await getDocument(id)
      if (!doc) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json(doc)
    }

    if (pathname.startsWith('/api/documents/') && method === 'PUT') {
      const id = pathname.split('/').pop()!
      const body = await parseBody(req)
      const doc = await updateDocument(id, body.title ?? 'Untitled', body.content ?? '')
      if (!doc) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json(doc)
    }

    if (pathname.startsWith('/api/documents/') && method === 'DELETE') {
      const id = pathname.split('/').pop()!
      const ok = await deleteDocument(id)
      if (!ok) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json({ success: true })
    }

    // Main page
    const filter = url.searchParams.get('filter') ?? undefined
    const activeId = url.searchParams.get('doc') ?? undefined
    const docs = await listDocuments('updatedAt', filter)
    const activeDoc = activeId ? await getDocument(activeId) : null
    const html = renderEditor(docs, activeDoc, filter)

    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

console.log(`Markdown Editor running at http://localhost:${PORT}`)

