import { createColor, isValidHex, type Color } from './color'
import { generatePalette, type HarmonyType, type Palette, allHarmonyTypes } from './palette'
import { checkContrast, type ContrastResult } from './contrast'
import { renderPage } from './ui'

type AppState = {
  baseHex: string
  harmony: HarmonyType
  palette: Palette
  selectedIndices: number[]
  contrastColor1: Color | null
  contrastColor2: Color | null
  contrastResult: ContrastResult | null
}

const DEFAULT_BASE_HEX = '#3a86ff'

const createState = (baseHex: string, harmony: HarmonyType): AppState => {
  const base = createColor(baseHex)
  const palette = generatePalette(base, harmony)
  return {
    baseHex: base.hex,
    harmony,
    palette,
    selectedIndices: [],
    contrastColor1: null,
    contrastColor2: null,
    contrastResult: null,
  }
}

const updateContrast = (state: AppState): AppState => {
  if (state.selectedIndices.length < 2) {
    return { ...state, contrastColor1: null, contrastColor2: null, contrastResult: null }
  }
  const [i1, i2] = state.selectedIndices
  const color1 = state.palette.colors[i1]
  const color2 = state.palette.colors[i2]
  const result = checkContrast(color1, color2)
  return { ...state, contrastColor1: color1, contrastColor2: color2, contrastResult: result }
}

const toggleSwatchSelection = (state: AppState, index: number): AppState => {
  const current = state.selectedIndices
  let next: number[]
  if (current.includes(index)) {
    next = current.filter((i) => i !== index)
  } else if (current.length >= 2) {
    next = [current[1], index]
  } else {
    next = [...current, index]
  }
  return updateContrast({ ...state, selectedIndices: next })
}

const changeBaseColor = (state: AppState, hex: string): AppState => {
  if (!isValidHex(hex)) return state
  const base = createColor(hex)
  const palette = generatePalette(base, state.harmony)
  return updateContrast({
    ...state,
    baseHex: base.hex,
    palette,
    selectedIndices: state.selectedIndices.filter((i) => i < palette.colors.length),
  })
}

const changeHarmony = (state: AppState, harmony: HarmonyType): AppState => {
  if (!allHarmonyTypes.includes(harmony)) return state
  const palette = generatePalette(state.palette.base, harmony)
  return updateContrast({
    ...state,
    harmony,
    palette,
    selectedIndices: state.selectedIndices.filter((i) => i < palette.colors.length),
  })
}

export const handleAction = (
  state: AppState,
  action: string,
  payload: Record<string, string>,
): AppState => {
  switch (action) {
    case 'changeColor':
      return changeBaseColor(state, payload.hex ?? '')
    case 'changeHarmony':
      return changeHarmony(state, payload.harmony as HarmonyType)
    case 'selectSwatch':
      return toggleSwatchSelection(state, parseInt(payload.index ?? '0', 10))
    default:
      return state
  }
}

export const render = (state: AppState): string =>
  renderPage(
    state.palette,
    state.selectedIndices,
    state.contrastColor1,
    state.contrastColor2,
    state.contrastResult,
  )

export const init = (baseHex?: string, harmony?: HarmonyType): AppState =>
  createState(baseHex ?? DEFAULT_BASE_HEX, harmony ?? 'complementary')

export { createColor, isValidHex } from './color'
export { generatePalette, allHarmonyTypes, harmonyDescriptions } from './palette'
export { checkContrast, contrastRatio, relativeLuminance } from './contrast'
export type { Color, RGB, HSL } from './color'
export type { HarmonyType, Palette } from './palette'
export type { ContrastResult, WcagLevel } from './contrast'
export type { AppState }

import { init, handleAction, render, type AppState } from './index'

const DATA_PATH = './data/palettes.json'

type SavedPalette = {
  baseHex: string
  harmony: string
  createdAt: string
}

const loadSavedPalettes = async (): Promise<SavedPalette[]> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return []
}

const savePalette = async (state: AppState): Promise<void> => {
  const existing = await loadSavedPalettes()
  const entry: SavedPalette = {
    baseHex: state.baseHex,
    harmony: state.harmony,
    createdAt: new Date().toISOString(),
  }
  existing.push(entry)
  await Bun.write(DATA_PATH, JSON.stringify(existing, null, 2))
}

let currentState: AppState = init()

const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? ''
  if (contentType.includes('application/json')) {
    return req.json()
  }
  if (contentType.includes('application/x-www-form-urlencoded')) {
    const text = await req.text()
    return Object.fromEntries(new URLSearchParams(text))
  }
  return {}
}

const htmlShell = (body: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Color Palette Generator</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #1a1a2e; }
    button:hover { opacity: 0.85; }
    [p-trigger="copyValue"]:hover { background-color: rgba(255,255,255,0.05); }
    [p-trigger="selectSwatch"]:hover { border-color: #e94560 !important; }
  </style>
  <script>
    const postAction = async (action, payload) => {
      const res = await fetch('/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, ...payload }),
      });
      const html = await res.text();
      document.getElementById('app').innerHTML = html;
      attachListeners();
    };

    const copyToClipboard = async (text) => {
      try {
        await navigator.clipboard.writeText(text);
        const toast = document.createElement('div');
        toast.textContent = 'Copied: ' + text;
        toast.style.cssText = 'position:fixed;bottom:24px;right:24px;background:#2d6a4f;color:#fff;padding:10px 20px;border-radius:8px;font-size:14px;z-index:1000;animation:fadeOut 1.5s forwards';
        document.body.appendChild(toast);
        setTimeout(() => toast.remove(), 1500);
      } catch {}
    };

    const attachListeners = () => {
      document.querySelectorAll('[p-trigger="colorPickerChange"]').forEach(el => {
        el.addEventListener('input', (e) => postAction('changeColor', { hex: e.target.value }));
      });
      document.querySelectorAll('[p-trigger="hexInputChange"]').forEach(el => {
        el.addEventListener('change', (e) => {
          let val = e.target.value.trim();
          if (!val.startsWith('#')) val = '#' + val;
          postAction('changeColor', { hex: val });
        });
      });
      document.querySelectorAll('[p-trigger="selectHarmony"]').forEach(el => {
        el.addEventListener('click', () => postAction('changeHarmony', { harmony: el.dataset.harmony }));
      });
      document.querySelectorAll('[p-trigger="selectSwatch"]').forEach(el => {
        el.addEventListener('click', () => postAction('selectSwatch', { index: el.dataset.index }));
      });
      document.querySelectorAll('[p-trigger="copyValue"]').forEach(el => {
        el.addEventListener('click', (e) => {
          e.stopPropagation();
          copyToClipboard(el.dataset.value);
        });
      });
    };

    document.addEventListener('DOMContentLoaded', attachListeners);
  </script>
</head>
<body>
  <div id="app">${body}</div>
</body>
</html>`

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' && req.method === 'GET') {
      const hex = url.searchParams.get('color')
      const harmony = url.searchParams.get('harmony')
      if (hex || harmony) {
        currentState = init(hex ?? undefined, (harmony as any) ?? undefined)
      }
      return new Response(htmlShell(render(currentState)), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    if (url.pathname === '/action' && req.method === 'POST') {
      const body = await parseBody(req)
      const { action, ...payload } = body
      currentState = handleAction(currentState, action, payload)
      return new Response(render(currentState), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    if (url.pathname === '/save' && req.method === 'POST') {
      await savePalette(currentState)
      return new Response(JSON.stringify({ ok: true }), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    if (url.pathname === '/api/palette' && req.method === 'GET') {
      return new Response(JSON.stringify(currentState.palette, null, 2), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

