const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const text = await file.text()
  return JSON.parse(text) as Project[]
}

const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

const createInitialState = (projects: Project[]): GalleryState => ({
  projects,
  filterTag: null,
  searchQuery: '',
  sortBy: 'date',
  selectedProjectId: null,
  lightboxIndex: 0,
})

const sortProjects = (projects: Project[], sortBy: SortKey): Project[] => {
  const sorted = [...projects]
  if (sortBy === 'date') {
    sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
  } else {
    sorted.sort((a, b) => a.title.localeCompare(b.title))
  }
  return sorted
}

const filterProjects = (
  projects: Project[],
  filterTag: string | null,
  searchQuery: string,
): Project[] => {
  let filtered = projects
  if (filterTag) {
    filtered = filtered.filter((p) => p.tags.includes(filterTag))
  }
  if (searchQuery.trim()) {
    const q = searchQuery.toLowerCase()
    filtered = filtered.filter((p) => p.title.toLowerCase().includes(q))
  }
  return filtered
}

const getAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

const getVisibleProjects = (state: GalleryState): Project[] => {
  const filtered = filterProjects(state.projects, state.filterTag, state.searchQuery)
  return sortProjects(filtered, state.sortBy)
}

const getSelectedProject = (state: GalleryState): Project | null => {
  if (!state.selectedProjectId) return null
  return state.projects.find((p) => p.id === state.selectedProjectId) ?? null
}

export {
  loadProjects,
  saveProjects,
  createInitialState,
  sortProjects,
  filterProjects,
  getAllTags,
  getVisibleProjects,
  getSelectedProject,
}

