import type { GalleryState, SortKey } from './types'

type Action =
  | { type: 'filterTag'; tag: string }
  | { type: 'clearFilter' }
  | { type: 'search'; query: string }
  | { type: 'sort'; sortBy: SortKey }
  | { type: 'selectProject'; projectId: string }
  | { type: 'closeDetail' }
  | { type: 'lightboxPrev' }
  | { type: 'lightboxNext' }
  | { type: 'lightboxGoTo'; index: number }

const handleAction = (state: GalleryState, action: Action): GalleryState => {
  switch (action.type) {
    case 'filterTag': {
      const nextTag = state.filterTag === action.tag ? null : action.tag
      return { ...state, filterTag: nextTag }
    }
    case 'clearFilter':
      return { ...state, filterTag: null }
    case 'search':
      return { ...state, searchQuery: action.query }
    case 'sort':
      return { ...state, sortBy: action.sortBy }
    case 'selectProject':
      return { ...state, selectedProjectId: action.projectId, lightboxIndex: 0 }
    case 'closeDetail':
      return { ...state, selectedProjectId: null, lightboxIndex: 0 }
    case 'lightboxPrev': {
      const project = state.projects.find((p) => p.id === state.selectedProjectId)
      if (!project) return state
      const prevIndex = state.lightboxIndex <= 0 ? project.images.length - 1 : state.lightboxIndex - 1
      return { ...state, lightboxIndex: prevIndex }
    }
    case 'lightboxNext': {
      const project = state.projects.find((p) => p.id === state.selectedProjectId)
      if (!project) return state
      const nextIndex = state.lightboxIndex >= project.images.length - 1 ? 0 : state.lightboxIndex + 1
      return { ...state, lightboxIndex: nextIndex }
    }
    case 'lightboxGoTo':
      return { ...state, lightboxIndex: action.index }
    default:
      return state
  }
}

export { handleAction }
export type { Action }

