export type Tool = 'pen' | 'rectangle' | 'circle' | 'line' | 'eraser'

export type Point = {
  x: number
  y: number
}

export type StrokeSegment = {
  type: 'freehand'
  points: Point[]
  color: string
  size: number
}

export type ShapeSegment = {
  type: 'rectangle' | 'circle' | 'line'
  start: Point
  end: Point
  color: string
  size: number
}

export type EraserSegment = {
  type: 'eraser'
  points: Point[]
  size: number
}

export type Segment = StrokeSegment | ShapeSegment | EraserSegment

export type Layer = {
  id: string
  name: string
  visible: boolean
  segments: Segment[]
  thumbnail: string
}

export type CanvasState = {
  width: number
  height: number
  layers: Layer[]
  activeLayerId: string
  history: Layer[][]
  historyIndex: number
}

export type DrawingRecord = {
  id: string
  name: string
  createdAt: string
  updatedAt: string
  png: string
  state: CanvasState
}

