  activeTool: Tool
  color: string
  brushSize: number
}

import type { CanvasState, Layer, Segment, Point, Tool } from './types'

const generateId = (): string => crypto.randomUUID()

const createLayer = (name: string): Layer => ({
  id: generateId(),
  name,
  visible: true,
  segments: [],
  thumbnail: '',
})

export const createCanvasState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Layer 1')
  return {
    width,
    height,
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    history: [[baseLayer]],
    historyIndex: 0,
  }
}

const cloneLayers = (layers: Layer[]): Layer[] =>
  layers.map((l) => ({
    ...l,
    segments: l.segments.map((s) => ({ ...s })),
  }))

const pushHistory = (state: CanvasState): CanvasState => {
  const trimmed = state.history.slice(0, state.historyIndex + 1)
  const snapshot = cloneLayers(state.layers)
  return {
    ...state,
    history: [...trimmed, snapshot],
    historyIndex: trimmed.length,
  }
}

export const undo = (state: CanvasState): CanvasState => {
  if (state.historyIndex <= 0) return state
  const newIndex = state.historyIndex - 1
  return {
    ...state,
    layers: cloneLayers(state.history[newIndex]),
    historyIndex: newIndex,
  }
}

export const redo = (state: CanvasState): CanvasState => {
  if (state.historyIndex >= state.history.length - 1) return state
  const newIndex = state.historyIndex + 1
  return {
    ...state,
    layers: cloneLayers(state.history[newIndex]),
    historyIndex: newIndex,
  }
}

export const addLayer = (state: CanvasState): CanvasState => {
  const layer = createLayer(`Layer ${state.layers.length + 1}`)
  const newState = {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  }
  return pushHistory(newState)
}

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state
  const filtered = state.layers.filter((l) => l.id !== layerId)
  const newState = {
    ...state,
    layers: filtered,
    activeLayerId:
      state.activeLayerId === layerId ? filtered[filtered.length - 1].id : state.activeLayerId,
  }
  return pushHistory(newState)
}

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, visible: !l.visible } : l)),
})

export const setActiveLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  activeLayerId: layerId,
})

export const addSegmentToActiveLayer = (state: CanvasState, segment: Segment): CanvasState => {
  const newState = {
    ...state,
    layers: state.layers.map((l) =>
      l.id === state.activeLayerId ? { ...l, segments: [...l.segments, segment] } : l
    ),
  }
  return pushHistory(newState)
}

export const clearCanvas = (state: CanvasState): CanvasState => {
  const newState = {
    ...state,
    layers: state.layers.map((l) => ({ ...l, segments: [] })),
  }
  return pushHistory(newState)
}

export const buildFreehandSegment = (points: Point[], color: string, size: number): Segment => ({
  type: 'freehand',
  points: [...points],
  color,
  size,
})

export const buildShapeSegment = (
  shapeType: 'rectangle' | 'circle' | 'line',
  start: Point,
  end: Point,
  color: string,
  size: number
): Segment => ({
  type: shapeType,
  start,
  end,
  color,
  size,
})

export const buildEraserSegment = (points: Point[], size: number): Segment => ({
  type: 'eraser',
  points: [...points],
  size,
})

export const updateLayerThumbnail = (
  state: CanvasState,
  layerId: string,
  thumbnail: string
): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, thumbnail } : l)),
})

import type { DrawingRecord, CanvasState } from './types'

const DATA_PATH = './data/drawings.jsonl'

const generateId = (): string => crypto.randomUUID()

export const saveDrawing = async (
  name: string,
  pngBase64: string,
  state: CanvasState
): Promise<DrawingRecord> => {
  const now = new Date().toISOString()
  const record: DrawingRecord = {
    id: generateId(),
    name,
    createdAt: now,
    updatedAt: now,
    png: pngBase64,
    state,
  }

  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  const existing = exists ? await file.text() : ''
  const line = JSON.stringify(record) + '\n'
  await Bun.write(DATA_PATH, existing + line)

  return record
}

export const updateDrawing = async (
  id: string,
  pngBase64: string,
  state: CanvasState
): Promise<DrawingRecord | null> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return null

  const text = await file.text()
  const lines = text.trim().split('\n').filter(Boolean)
  let updated: DrawingRecord | null = null

  const newLines = lines.map((line) => {
    const record: DrawingRecord = JSON.parse(line)
    if (record.id === id) {
      record.updatedAt = new Date().toISOString()
      record.png = pngBase64
      record.state = state
      updated = record
    }
    return JSON.stringify(record)
  })

  await Bun.write(DATA_PATH, newLines.join('\n') + '\n')
  return updated
}

export const listDrawings = async (): Promise<Omit<DrawingRecord, 'png' | 'state'>[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => {
      const { id, name, createdAt, updatedAt } = JSON.parse(line) as DrawingRecord
      return { id, name, createdAt, updatedAt }
    })
}

export const loadDrawing = async (id: string): Promise<DrawingRecord | null> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return null

  const text = await file.text()
  const lines = text.trim().split('\n').filter(Boolean)

  for (const line of lines) {
    const record: DrawingRecord = JSON.parse(line)
    if (record.id === id) return record
  }

  return null
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return false

  const text = await file.text()
  const lines = text.trim().split('\n').filter(Boolean)
  const filtered = lines.filter((line) => {
    const record: DrawingRecord = JSON.parse(line)
    return record.id !== id
  })

  if (filtered.length === lines.length) return false
  await Bun.write(DATA_PATH, filtered.join('\n') + (filtered.length ? '\n' : ''))
  return true
}

