import type { Segment, Layer, Point } from './types'

export const renderSegmentToCtx = (ctx: CanvasRenderingContext2D, segment: Segment): void => {
  ctx.save()

  switch (segment.type) {
    case 'freehand': {
      ctx.strokeStyle = segment.color
      ctx.lineWidth = segment.size
      ctx.lineCap = 'round'
      ctx.lineJoin = 'round'
      ctx.beginPath()
      const pts = segment.points
      if (pts.length === 1) {
        ctx.arc(pts[0].x, pts[0].y, segment.size / 2, 0, Math.PI * 2)
        ctx.fillStyle = segment.color
        ctx.fill()
      } else if (pts.length > 1) {
        ctx.moveTo(pts[0].x, pts[0].y)
        for (let i = 1; i < pts.length; i++) {
          const mid = {
            x: (pts[i - 1].x + pts[i].x) / 2,
            y: (pts[i - 1].y + pts[i].y) / 2,
          }
          ctx.quadraticCurveTo(pts[i - 1].x, pts[i - 1].y, mid.x, mid.y)
        }
        ctx.lineTo(pts[pts.length - 1].x, pts[pts.length - 1].y)
        ctx.stroke()
      }
      break
    }

    case 'eraser': {
      ctx.globalCompositeOperation = 'destination-out'
      ctx.strokeStyle = 'rgba(0,0,0,1)'
      ctx.lineWidth = segment.size
      ctx.lineCap = 'round'
      ctx.lineJoin = 'round'
      ctx.beginPath()
      const pts = segment.points
      if (pts.length === 1) {
        ctx.arc(pts[0].x, pts[0].y, segment.size / 2, 0, Math.PI * 2)
        ctx.fill()
      } else if (pts.length > 1) {
        ctx.moveTo(pts[0].x, pts[0].y)
        for (let i = 1; i < pts.length; i++) {
          ctx.lineTo(pts[i].x, pts[i].y)
        }
        ctx.stroke()
      }
      break
    }

    case 'rectangle': {
      ctx.strokeStyle = segment.color
      ctx.lineWidth = segment.size
      const x = Math.min(segment.start.x, segment.end.x)
      const y = Math.min(segment.start.y, segment.end.y)
      const w = Math.abs(segment.end.x - segment.start.x)
      const hh = Math.abs(segment.end.y - segment.start.y)
      ctx.strokeRect(x, y, w, hh)
      break
    }

    case 'circle': {
      ctx.strokeStyle = segment.color
      ctx.lineWidth = segment.size
      const cx = (segment.start.x + segment.end.x) / 2
      const cy = (segment.start.y + segment.end.y) / 2
      const rx = Math.abs(segment.end.x - segment.start.x) / 2
      const ry = Math.abs(segment.end.y - segment.start.y) / 2
      ctx.beginPath()
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
      ctx.stroke()
      break
    }

    case 'line': {
      ctx.strokeStyle = segment.color
      ctx.lineWidth = segment.size
      ctx.lineCap = 'round'
      ctx.beginPath()
      ctx.moveTo(segment.start.x, segment.start.y)
      ctx.lineTo(segment.end.x, segment.end.y)
      ctx.stroke()
      break
    }
  }

  ctx.restore()
}

export const renderLayerToCtx = (ctx: CanvasRenderingContext2D, layer: Layer): void => {
  if (!layer.visible) return
  for (const segment of layer.segments) {
    renderSegmentToCtx(ctx, segment)
  }
}

export const renderAllLayers = (
  ctx: CanvasRenderingContext2D,
  layers: Layer[],
  width: number,
  height: number
): void => {
  ctx.clearRect(0, 0, width, height)
  for (const layer of layers) {
    renderLayerToCtx(ctx, layer)
  }
}

export const renderPreviewShape = (
  ctx: CanvasRenderingContext2D,
  shapeType: 'rectangle' | 'circle' | 'line',
  start: Point,
  end: Point,
  color: string,
  size: number
): void => {
  ctx.save()
  ctx.strokeStyle = color
  ctx.lineWidth = size
  ctx.setLineDash([5, 5])

  switch (shapeType) {
    case 'rectangle': {
      const x = Math.min(start.x, end.x)
      const y = Math.min(start.y, end.y)
      const w = Math.abs(end.x - start.x)
      const hh = Math.abs(end.y - start.y)
      ctx.strokeRect(x, y, w, hh)
      break
    }
    case 'circle': {
      const cx = (start.x + end.x) / 2
      const cy = (start.y + end.y) / 2
      const rx = Math.abs(end.x - start.x) / 2
      const ry = Math.abs(end.y - start.y) / 2
      ctx.beginPath()
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
      ctx.stroke()
      break
    }
    case 'line': {
      ctx.beginPath()
      ctx.moveTo(start.x, start.y)
      ctx.lineTo(end.x, end.y)
      ctx.stroke()
      break
    }
  }

  ctx.restore()
}

export const generateThumbnail = (
  sourceCanvas: HTMLCanvasElement,
  layer: Layer,
  width: number,
  height: number,
  thumbWidth = 64,
  thumbHeight = 48
): string => {
  const offscreen = document.createElement('canvas')
  offscreen.width = width
  offscreen.height = height
  const offCtx = offscreen.getContext('2d')!

  offCtx.fillStyle = '#ffffff'
  offCtx.fillRect(0, 0, width, height)
  renderLayerToCtx(offCtx, { ...layer, visible: true })

  const thumb = document.createElement('canvas')
  thumb.width = thumbWidth
  thumb.height = thumbHeight
  const tCtx = thumb.getContext('2d')!
  tCtx.drawImage(offscreen, 0, 0, width, height, 0, 0, thumbWidth, thumbHeight)

  return thumb.toDataURL('image/png')
}

export const canvasToBase64PNG = (
  layers: Layer[],
  width: number,
  height: number
): string => {
  const offscreen = document.createElement('canvas')
  offscreen.width = width
  offscreen.height = height
  const ctx = offscreen.getContext('2d')!

  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, width, height)
  renderAllLayers(ctx, layers, width, height)

  return offscreen.toDataURL('image/png')
}

import type { CanvasState, Tool, ToolbarState, Point } from './types'
import {
  createCanvasState,
  undo,
  redo,
  addLayer,
  removeLayer,
  toggleLayerVisibility,
  setActiveLayer,
  addSegmentToActiveLayer,
  clearCanvas,
  buildFreehandSegment,
  buildShapeSegment,
  buildEraserSegment,
  updateLayerThumbnail,
} from './canvas'
import {
  renderAllLayers,
  renderPreviewShape,
  renderSegmentToCtx,
  generateThumbnail,
  canvasToBase64PNG,
} from './draw-engine'
import { saveDrawing, loadDrawing, listDrawings } from './storage'

type DrawingSession = {
  isDrawing: boolean
  points: Point[]
  startPoint: Point | null
  currentPoint: Point | null
}

const initClient = () => {
  let state: CanvasState = createCanvasState(800, 600)
  let toolbar: ToolbarState = {
    activeTool: 'pen',
    color: '#000000',
    brushSize: 3,
  }
  let session: DrawingSession = {
    isDrawing: false,
    points: [],
    startPoint: null,
    currentPoint: null,
  }

  const getCanvas = (): HTMLCanvasElement | null =>
    document.querySelector('[p-target="drawing-surface"]')

  const getCtx = (): CanvasRenderingContext2D | null => getCanvas()?.getContext('2d') ?? null

  const getPointerPos = (e: PointerEvent): Point => {
    const canvas = getCanvas()!
    const rect = canvas.getBoundingClientRect()
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    }
  }

  const redraw = () => {
    const ctx = getCtx()
    if (!ctx) return
    renderAllLayers(ctx, state.layers, state.width, state.height)
  }

  const updateThumbnails = () => {
    const canvas = getCanvas()
    if (!canvas) return
    for (const layer of state.layers) {
      const thumb = generateThumbnail(canvas, layer, state.width, state.height)
      state = updateLayerThumbnail(state, layer.id, thumb)
    }
  }

  const refreshUI = () => {
    redraw()
    updateThumbnails()
  }

  // Tool selection
  const selectTool = (tool: Tool) => {
    toolbar = { ...toolbar, activeTool: tool }
  }

  // Pointer events
  const onPointerDown = (e: PointerEvent) => {
    const pos = getPointerPos(e)
    session = { isDrawing: true, points: [pos], startPoint: pos, currentPoint: pos }

    const canvas = getCanvas()
    canvas?.setPointerCapture(e.pointerId)
  }

  const onPointerMove = (e: PointerEvent) => {
    if (!session.isDrawing) return
    const pos = getPointerPos(e)
    session.currentPoint = pos

    const ctx = getCtx()
    if (!ctx) return

    if (toolbar.activeTool === 'pen') {
      session.points.push(pos)
      redraw()
      // Draw in-progress stroke
      const seg = buildFreehandSegment(session.points, toolbar.color, toolbar.brushSize)
      renderSegmentToCtx(ctx, seg)
    } else if (toolbar.activeTool === 'eraser') {
      session.points.push(pos)
      redraw()
      const seg = buildEraserSegment(session.points, toolbar.brushSize)
      renderSegmentToCtx(ctx, seg)
    } else if (session.startPoint) {
      // Shape preview
      redraw()
      renderPreviewShape(
        ctx,
        toolbar.activeTool as 'rectangle' | 'circle' | 'line',
        session.startPoint,
        pos,
        toolbar.color,
        toolbar.brushSize
      )
    }
  }

  const onPointerUp = (_e: PointerEvent) => {
    if (!session.isDrawing) return

    if (toolbar.activeTool === 'pen' && session.points.length > 0) {
      const seg = buildFreehandSegment(session.points, toolbar.color, toolbar.brushSize)
      state = addSegmentToActiveLayer(state, seg)
    } else if (toolbar.activeTool === 'eraser' && session.points.length > 0) {
      const seg = buildEraserSegment(session.points, toolbar.brushSize)
      state = addSegmentToActiveLayer(state, seg)
    } else if (
      session.startPoint &&
      session.currentPoint &&
      ['rectangle', 'circle', 'line'].includes(toolbar.activeTool)
    ) {
      const seg = buildShapeSegment(
        toolbar.activeTool as 'rectangle' | 'circle' | 'line',
        session.startPoint,
        session.currentPoint,
        toolbar.color,
        toolbar.brushSize
      )
      state = addSegmentToActiveLayer(state, seg)
    }

    session = { isDrawing: false, points: [], startPoint: null, currentPoint: null }
    refreshUI()
  }

  // Event delegation
  const handleTrigger = (triggerName: string) => {
    if (triggerName.startsWith('select-tool-')) {
      const tool = triggerName.replace('select-tool-', '') as Tool
      selectTool(tool)
      return
    }

    if (triggerName.startsWith('select-layer-')) {
      const layerId = triggerName.replace('select-layer-', '')
      state = setActiveLayer(state, layerId)
      refreshUI()
      return
    }

    if (triggerName.startsWith('toggle-layer-')) {
      const layerId = triggerName.replace('toggle-layer-', '')
      state = toggleLayerVisibility(state, layerId)
      refreshUI()
      return
    }

    switch (triggerName) {
      case 'undo':
        state = undo(state)
        refreshUI()
        break
      case 'redo':
        state = redo(state)
        refreshUI()
        break
      case 'add-layer':
        state = addLayer(state)
        refreshUI()
        break
      case 'remove-layer':
        state = removeLayer(state, state.activeLayerId)
        refreshUI()
        break
      case 'clear-canvas':
        state = clearCanvas(state)
        refreshUI()
        break
      case 'save-drawing': {
        const pngData = canvasToBase64PNG(state.layers, state.width, state.height)
        // Download as file
        const link = document.createElement('a')
        link.download = `drawing-${Date.now()}.png`
        link.href = pngData
        link.click()
        // Also persist to storage
        saveDrawing(`Drawing ${Date.now()}`, pngData, state)
        break
      }
      case 'load-drawing': {
        const input = document.createElement('input')
        input.type = 'file'
        input.accept = 'image/png'
        input.onchange = async () => {
          const file = input.files?.[0]
          if (!file) return
          const reader = new FileReader()
          reader.onload = () => {
            const img = new Image()
            img.onload = () => {
              const ctx = getCtx()
              if (!ctx) return
              state = clearCanvas(state)
              ctx.drawImage(img, 0, 0, state.width, state.height)
              // Convert loaded image to a segment via canvas data
              // For simplicity, we place it as a background fill
              refreshUI()
            }
            img.src = reader.result as string
          }
          reader.readAsDataURL(file)
        }
        input.click()
        break
      }
      case 'color-change': {
        const input = document.querySelector('[p-target="color-input"]') as HTMLInputElement
        if (input) toolbar = { ...toolbar, color: input.value }
        break
      }
      case 'brush-size-change': {
        const input = document.querySelector('[p-target="brush-size-input"]') as HTMLInputElement
        const display = document.querySelector('[p-target="brush-size-value"]')
        if (input) {
          toolbar = { ...toolbar, brushSize: Number(input.value) }
          if (display) display.textContent = input.value
        }
        break
      }
    }
  }

  // Keyboard shortcuts
  const onKeyDown = (e: KeyboardEvent) => {
    const mod = e.metaKey || e.ctrlKey
    if (mod && e.key === 'z' && !e.shiftKey) {
      e.preventDefault()
      state = undo(state)
      refreshUI()
    } else if (mod && (e.key === 'Z' || (e.key === 'z' && e.shiftKey))) {
      e.preventDefault()
      state = redo(state)
      refreshUI()
    } else if (e.key === 'b') {
      selectTool('pen')
    } else if (e.key === 'r') {
      selectTool('rectangle')
    } else if (e.key === 'o') {
      selectTool('circle')
    } else if (e.key === 'l') {
      selectTool('line')
    } else if (e.key === 'e') {
      selectTool('eraser')
    }
  }

  // Bind events
  const canvas = getCanvas()
  if (canvas) {
    canvas.addEventListener('pointerdown', onPointerDown)
    canvas.addEventListener('pointermove', onPointerMove)
    canvas.addEventListener('pointerup', onPointerUp)
  }

  document.addEventListener('keydown', onKeyDown)

  // Delegate p-trigger clicks
  document.addEventListener('click', (e) => {
    const target = (e.target as HTMLElement).closest('[p-trigger]')
    if (!target) return
    const triggers = JSON.parse(target.getAttribute('p-trigger') || '{}')
    if (triggers.click) handleTrigger(triggers.click)
  })

  document.addEventListener('input', (e) => {
    const target = (e.target as HTMLElement).closest('[p-trigger]')
    if (!target) return
    const triggers = JSON.parse(target.getAttribute('p-trigger') || '{}')
    if (triggers.input) handleTrigger(triggers.input)
  })

  // Initial render
  refreshUI()
}

// Auto-init when DOM is ready
if (typeof document !== 'undefined') {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initClient)
  } else {
    initClient()
  }
}

export { initClient }

