}

const savePlaylists = async (playlists: Playlist[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(playlists, null, 2))
}

const getState = async (): Promise<AppState> => {
  const playlists = await loadPlaylists()
  return {
    playlists,
    playback: { ...defaultPlayback },
    activePlaylistId: playlists[0]?.id ?? null,
  }
}

const createPlaylist = async (name: string): Promise<Playlist> => {
  const playlists = await loadPlaylists()
  const playlist: Playlist = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    songs: [],
  }
  playlists.push(playlist)
  await savePlaylists(playlists)
  return playlist
}

const deletePlaylist = async (playlistId: string): Promise<void> => {
  const playlists = await loadPlaylists()
  const filtered = playlists.filter((p) => p.id !== playlistId)
  await savePlaylists(filtered)
}

const renamePlaylist = async (playlistId: string, name: string): Promise<void> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (playlist) {
    playlist.name = name
    await savePlaylists(playlists)
  }
}

const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>
): Promise<Song | null> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const newSong: Song = { id: generateId(), ...song }
  playlist.songs.push(newSong)
  await savePlaylists(playlists)
  return newSong
}

const removeSong = async (playlistId: string, songId: string): Promise<void> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (playlist) {
    playlist.songs = playlist.songs.filter((s) => s.id !== songId)
    await savePlaylists(playlists)
  }
}

const reorderSong = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number
): Promise<void> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return
  if (toIndex < 0 || toIndex >= playlist.songs.length) return
  const [song] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, song)
  await savePlaylists(playlists)
}

const generateShuffleOrder = (length: number): number[] => {
  const order = Array.from({ length }, (_, i) => i)
  for (let i = order.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[order[i], order[j]] = [order[j], order[i]]
  }
  return order
}

export const store = {
  getState,
  loadPlaylists,
  savePlaylists,
  createPlaylist,
  deletePlaylist,
  renamePlaylist,
  addSong,
  removeSong,
  reorderSong,
  generateShuffleOrder,
}

