const styleToStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${typeof v === 'number' && prop !== 'z-index' && prop !== 'opacity' && prop !== 'flex' && prop !== 'font-weight' && prop !== 'line-height' ? `${v}px` : v}`
    })
    .join(';')

