export { formatDuration }

import { store } from './store'
import type { PlaybackState, RepeatMode, Playlist } from './types'

type HandlerContext = {
  playback: PlaybackState
  activePlaylistId: string | null
  rerender: () => Promise<string>
}

const parseDuration = (str: string): number => {
  const [min, sec] = str.split(':').map(Number)
  return min * 60 + sec
}

const handlePlaylistCreate = async (ctx: HandlerContext): Promise<{ html: string; ctx: HandlerContext }> => {
  const name = `New Playlist`
  const playlist = await store.createPlaylist(name)
  ctx.activePlaylistId = playlist.id
  return { html: await ctx.rerender(), ctx }
}

const handlePlaylistSelect = async (
  playlistId: string,
  ctx: HandlerContext
): Promise<{ html: string; ctx: HandlerContext }> => {
  ctx.activePlaylistId = playlistId
  return { html: await ctx.rerender(), ctx }
}

const handlePlaylistDelete = async (
  playlistId: string,
  ctx: HandlerContext
): Promise<{ html: string; ctx: HandlerContext }> => {
  await store.deletePlaylist(playlistId)
  if (ctx.activePlaylistId === playlistId) {
    const playlists = await store.loadPlaylists()
    ctx.activePlaylistId = playlists[0]?.id ?? null
  }
  if (ctx.playback.playlistId === playlistId) {
    ctx.playback = {
      ...ctx.playback,
      playlistId: null,
      songIndex: 0,
      isPlaying: false,
      currentTime: 0,
    }
  }
  return { html: await ctx.rerender(), ctx }
}

const handleSongAdd = async (
  playlistId: string,
  data: { title: string; artist: string; album: string; duration: string; albumArtUrl: string },
  ctx: HandlerContext
): Promise<{ html: string; ctx: HandlerContext }> => {
  await store.addSong(playlistId, {
    title: data.title,
    artist: data.artist,
    album: data.album || 'Unknown Album',
    duration: parseDuration(data.duration),
    albumArtUrl: data.albumArtUrl || '',
  })
  return { html: await ctx.rerender(), ctx }
}

const handleSongRemove = async (
  playlistId: string,
  songId: string,
  ctx: HandlerContext
): Promise<{ html: string; ctx: HandlerContext }> => {
  const playlists = await store.loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (playlist && ctx.playback.playlistId === playlistId) {
    const removedIndex = playlist.songs.findIndex((s) => s.id === songId)
    if (removedIndex === ctx.playback.songIndex) {
      ctx.playback.isPlaying = false
      ctx.playback.currentTime = 0
    } else if (removedIndex < ctx.playback.songIndex) {
      ctx.playback.songIndex = Math.max(0, ctx.playback.songIndex - 1)
    }
  }
  await store.removeSong(playlistId, songId)
  return { html: await ctx.rerender(), ctx }
}

const handleSongReorder = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number,
  ctx: HandlerContext
): Promise<{ html: string; ctx: HandlerContext }> => {
  await store.reorderSong(playlistId, fromIndex, toIndex)
  if (ctx.playback.playlistId === playlistId) {
    if (ctx.playback.songIndex === fromIndex) {
      ctx.playback.songIndex = toIndex
    } else if (fromIndex < ctx.playback.songIndex && toIndex >= ctx.playback.songIndex) {
      ctx.playback.songIndex--
    } else if (fromIndex > ctx.playback.songIndex && toIndex <= ctx.playback.songIndex) {
      ctx.playback.songIndex++
    }
  }
  return { html: await ctx.rerender(), ctx }
}

const handleSongPlay = async (
  playlistId: string,
  songIndex: number,
  ctx: HandlerContext
): Promise<{ html: string; ctx: HandlerContext }> => {
  const playlists = await store.loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist || songIndex < 0 || songIndex >= playlist.songs.length) {
    return { html: await ctx.rerender(), ctx }
  }
  ctx.playback = {
    ...ctx.playback,
    playlistId,
    songIndex,
    isPlaying: true,
    currentTime: 0,
  }
  if (ctx.playback.shuffle) {
    ctx.playback.shuffleOrder = store.generateShuffleOrder(playlist.songs.length)
  }
  return { html: await ctx.rerender(), ctx }
}

const handlePlaybackToggle = (ctx: HandlerContext): { ctx: HandlerContext } => {
  if (ctx.playback.playlistId) {
    ctx.playback.isPlaying = !ctx.playback.isPlaying
  }
  return { ctx }
}

const getNextSongIndex = (playback: PlaybackState, playlistLength: number): number | null => {
  if (playback.repeat === 'one') return playback.songIndex
  if (playback.shuffle && playback.shuffleOrder.length > 0) {
    const currentShufflePos = playback.shuffleOrder.indexOf(playback.songIndex)
    const nextShufflePos = currentShufflePos + 1
    if (nextShufflePos < playback.shuffleOrder.length) {
      return playback.shuffleOrder[nextShufflePos]
    }
    if (playback.repeat === 'all') return playback.shuffleOrder[0]
    return null
  }
  const next = playback.songIndex + 1
  if (next < playlistLength) return next
  if (playback.repeat === 'all') return 0
  return null
}

const getPrevSongIndex = (playback: PlaybackState, playlistLength: number): number | null => {
  if (playback.shuffle && playback.shuffleOrder.length > 0) {
    const currentShufflePos = playback.shuffleOrder.indexOf(playback.songIndex)
    const prevShufflePos = currentShufflePos - 1
    if (prevShufflePos >= 0) return playback.shuffleOrder[prevShufflePos]
    if (playback.repeat === 'all') return playback.shuffleOrder[playback.shuffleOrder.length - 1]
    return null
  }
  const prev = playback.songIndex - 1
  if (prev >= 0) return prev
  if (playback.repeat === 'all') return playlistLength - 1
  return null
}

const handlePlaybackNext = async (ctx: HandlerContext): Promise<{ html: string; ctx: HandlerContext }> => {
  if (!ctx.playback.playlistId) return { html: await ctx.rerender(), ctx }
  const playlists = await store.loadPlaylists()
  const playlist = playlists.find((p) => p.id === ctx.playback.playlistId)
  if (!playlist) return { html: await ctx.rerender(), ctx }
  const nextIndex = getNextSongIndex(ctx.playback, playlist.songs.length)
  if (nextIndex !== null) {
    ctx.playback.songIndex = nextIndex
    ctx.playback.currentTime = 0
  } else {
    ctx.playback.isPlaying = false
    ctx.playback.currentTime = 0
  }
  return { html: await ctx.rerender(), ctx }
}

const handlePlaybackPrev = async (ctx: HandlerContext): Promise<{ html: string; ctx: HandlerContext }> => {
  if (!ctx.playback.playlistId) return { html: await ctx.rerender(), ctx }
  if (ctx.playback.currentTime > 3) {
    ctx.playback.currentTime = 0
    return { html: await ctx.rerender(), ctx }
  }
  const playlists = await store.loadPlaylists()
  const playlist = playlists.find((p) => p.id === ctx.playback.playlistId)
  if (!playlist) return { html: await ctx.rerender(), ctx }
  const prevIndex = getPrevSongIndex(ctx.playback, playlist.songs.length)
  if (prevIndex !== null) {
    ctx.playback.songIndex = prevIndex
    ctx.playback.currentTime = 0
  }
  return { html: await ctx.rerender(), ctx }
}

const handlePlaybackShuffle = async (ctx: HandlerContext): Promise<{ html: string; ctx: HandlerContext }> => {
  ctx.playback.shuffle = !ctx.playback.shuffle
  if (ctx.playback.shuffle && ctx.playback.playlistId) {
    const playlists = await store.loadPlaylists()
    const playlist = playlists.find((p) => p.id === ctx.playback.playlistId)
    if (playlist) {
      ctx.playback.shuffleOrder = store.generateShuffleOrder(playlist.songs.length)
    }
  } else {
    ctx.playback.shuffleOrder = []
  }
  return { html: await ctx.rerender(), ctx }
}

const handlePlaybackRepeat = async (ctx: HandlerContext): Promise<{ html: string; ctx: HandlerContext }> => {
  const modes: RepeatMode[] = ['off', 'all', 'one']
  const currentIdx = modes.indexOf(ctx.playback.repeat)
  ctx.playback.repeat = modes[(currentIdx + 1) % modes.length]
  return { html: await ctx.rerender(), ctx }
}

const handlePlaybackSeek = async (
  pct: number,
  ctx: HandlerContext
): Promise<{ html: string; ctx: HandlerContext }> => {
  if (!ctx.playback.playlistId) return { html: await ctx.rerender(), ctx }
  const playlists = await store.loadPlaylists()
  const playlist = playlists.find((p) => p.id === ctx.playback.playlistId)
  if (!playlist) return { html: await ctx.rerender(), ctx }
  const song = playlist.songs[ctx.playback.songIndex]
  if (song) {
    ctx.playback.currentTime = Math.floor(song.duration * (pct / 100))
  }
  return { html: await ctx.rerender(), ctx }
}

export const handlers = {
  handlePlaylistCreate,
  handlePlaylistSelect,
  handlePlaylistDelete,
  handleSongAdd,
  handleSongRemove,
  handleSongReorder,
  handleSongPlay,
  handlePlaybackToggle,
  handlePlaybackNext,
  handlePlaybackPrev,
  handlePlaybackShuffle,
  handlePlaybackRepeat,
  handlePlaybackSeek,
  getNextSongIndex,
  getPrevSongIndex,
}

import { createSSR } from 'plaited'
import { store } from './store'
import { renderApp } from './render'
import { handlers } from './handlers'
import type { PlaybackState, RepeatMode } from './types'

const playback: PlaybackState = {
  playlistId: null,
  songIndex: 0,
  isPlaying: false,
  currentTime: 0,
  shuffle: false,
  repeat: 'off',
  shuffleOrder: [],
}

let activePlaylistId: string | null = null

const init = async () => {
  const playlists = await store.loadPlaylists()
  activePlaylistId = playlists[0]?.id ?? null
}

const rerender = async (): Promise<string> => {
  const playlists = await store.loadPlaylists()
  const ssr = createSSR()
  const vdom = renderApp(playlists, activePlaylistId, playback)
  return ssr(vdom)
}

const getContext = () => ({
  playback,
  activePlaylistId,
  rerender,
})

const syncContext = (ctx: { playback: PlaybackState; activePlaylistId: string | null }) => {
  Object.assign(playback, ctx.playback)
  activePlaylistId = ctx.activePlaylistId
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (req.method === 'GET' && url.pathname === '/') {
      await init()
      const html = await rerender()
      return new Response(pageShell(html), {
        headers: { 'content-type': 'text/html; charset=utf-8' },
      })
    }

    if (req.method === 'POST' && url.pathname === '/api/action') {
      const body = await req.json() as { action: string; [key: string]: unknown }
      const ctx = getContext()
      let result: { html?: string; ctx: typeof ctx }

      switch (body.action) {
        case 'playlist-create':
          result = await handlers.handlePlaylistCreate(ctx)
          break
        case 'playlist-select':
          result = await handlers.handlePlaylistSelect(body.playlistId as string, ctx)
          break
        case 'playlist-delete':
          result = await handlers.handlePlaylistDelete(body.playlistId as string, ctx)
          break
        case 'song-add':
          result = await handlers.handleSongAdd(body.playlistId as string, body.data as {
            title: string; artist: string; album: string; duration: string; albumArtUrl: string
          }, ctx)
          break
        case 'song-remove':
          result = await handlers.handleSongRemove(body.playlistId as string, body.songId as string, ctx)
          break
        case 'song-reorder':
          result = await handlers.handleSongReorder(
            body.playlistId as string,
            body.fromIndex as number,
            body.toIndex as number,
            ctx
          )
          break
        case 'song-play':
          result = await handlers.handleSongPlay(body.playlistId as string, body.songIndex as number, ctx)
          break
        case 'playback-toggle':
          result = { ...handlers.handlePlaybackToggle(ctx), html: await rerender() }
          break
        case 'playback-next':
          result = await handlers.handlePlaybackNext(ctx)
          break
        case 'playback-prev':
          result = await handlers.handlePlaybackPrev(ctx)
          break
        case 'playback-shuffle':
          result = await handlers.handlePlaybackShuffle(ctx)
          break
        case 'playback-repeat':
          result = await handlers.handlePlaybackRepeat(ctx)
          break
        case 'playback-seek':
          result = await handlers.handlePlaybackSeek(body.pct as number, ctx)
          break
        default:
          return new Response(JSON.stringify({ error: 'Unknown action' }), { status: 400 })
      }

      syncContext(result.ctx)
      const html = result.html ?? await rerender()
      return new Response(JSON.stringify({ html }), {
        headers: { 'content-type': 'application/json' },
      })
    }

    return new Response('Not found', { status: 404 })
  },
})

const pageShell = (content: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Playlist Manager</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #121212; color: #e0e0e0; }
    button:hover { opacity: 0.85; }
    input:focus { border-color: #1db954 !important; }
    [draggable]:hover { background: #252525; }
    .drag-over { background: #1a3a2a !important; border-top: 2px solid #1db954; }
  </style>
</head>
<body>
  <div id="app">${content}</div>
  <script>
    const $ = (sel) => document.querySelector(sel);
    const app = $('#app');

    let dragFromIndex = null;
    let dragPlaylistId = null;
    let playbackTimer = null;
    let localPlayback = {
      isPlaying: false,
      currentTime: 0,
      duration: 0,
    };

    const sendAction = async (action, data = {}) => {
      const res = await fetch('/api/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, ...data }),
      });
      const json = await res.json();
      if (json.html) {
        app.innerHTML = json.html;
      }
    };

    const startPlaybackTimer = () => {
      stopPlaybackTimer();
      playbackTimer = setInterval(() => {
        if (localPlayback.isPlaying) {
          localPlayback.currentTime++;
          if (localPlayback.duration > 0 && localPlayback.currentTime >= localPlayback.duration) {
            sendAction('playback-next');
          }
          updateProgressDisplay();
        }
      }, 1000);
    };

    const stopPlaybackTimer = () => {
      if (playbackTimer) {
        clearInterval(playbackTimer);
        playbackTimer = null;
      }
    };

    const updateProgressDisplay = () => {
      const bar = document.querySelector('[p-target="progress-bar"]');
      if (bar) {
        const fill = bar.firstElementChild;
        if (fill && localPlayback.duration > 0) {
          const pct = (localPlayback.currentTime / localPlayback.duration) * 100;
          fill.style.width = pct + '%';
        }
      }
      const times = document.querySelectorAll('[p-target="now-playing"] .progress-time');
    };

    app.addEventListener('click', (e) => {
      const btn = e.target.closest('[p-trigger]');
      if (!btn) return;
      const triggers = JSON.parse(btn.getAttribute('p-trigger'));

      if (triggers.click === 'playlist-create') {
        const name = prompt('Playlist name:');
        if (name) sendAction('playlist-create', { name });
      } else if (triggers.click === 'playlist-select') {
        sendAction('playlist-select', { playlistId: btn.dataset.playlistId });
      } else if (triggers.click === 'playlist-delete') {
        if (confirm('Delete this playlist?')) {
          sendAction('playlist-delete', { playlistId: btn.dataset.playlistId });
        }
      } else if (triggers.click === 'song-remove') {
        sendAction('song-remove', {
          playlistId: btn.dataset.playlistId,
          songId: btn.dataset.songId,
        });
      } else if (triggers.click === 'playback-toggle') {
        localPlayback.isPlaying = !localPlayback.isPlaying;
        if (localPlayback.isPlaying) startPlaybackTimer();
        else stopPlaybackTimer();
        sendAction('playback-toggle');
      } else if (triggers.click === 'playback-next') {
        localPlayback.currentTime = 0;
        sendAction('playback-next');
      } else if (triggers.click === 'playback-prev') {
        localPlayback.currentTime = 0;
        sendAction('playback-prev');
      } else if (triggers.click === 'playback-shuffle') {
        sendAction('playback-shuffle');
      } else if (triggers.click === 'playback-repeat') {
        sendAction('playback-repeat');
      } else if (triggers.click === 'playback-seek') {
        const rect = btn.getBoundingClientRect();
        const pct = ((e.clientX - rect.left) / rect.width) * 100;
        sendAction('playback-seek', { pct });
      }
    });

    app.addEventListener('dblclick', (e) => {
      const row = e.target.closest('[p-trigger]');
      if (!row) return;
      const triggers = JSON.parse(row.getAttribute('p-trigger'));
      if (triggers.dblclick === 'song-play') {
        const index = parseInt(row.dataset.index);
        const playlistId = row.dataset.playlistId;
        localPlayback.isPlaying = true;
        localPlayback.currentTime = 0;
        startPlaybackTimer();
        sendAction('song-play', { playlistId, songIndex: index });
      }
    });

    app.addEventListener('submit', (e) => {
      e.preventDefault();
      const form = e.target.closest('[p-trigger]');
      if (!form) return;
      const triggers = JSON.parse(form.getAttribute('p-trigger'));
      if (triggers.submit === 'song-add') {
        const fd = new FormData(form);
        sendAction('song-add', {
          playlistId: form.dataset.playlistId,
          data: {
            title: fd.get('title'),
            artist: fd.get('artist'),
            album: fd.get('album'),
            duration: fd.get('duration'),
            albumArtUrl: fd.get('albumArtUrl'),
          },
        });
        form.reset();
      }
    });

    app.addEventListener('dragstart', (e) => {
      const row = e.target.closest('[draggable]');
      if (!row) return;
      dragFromIndex = parseInt(row.dataset.index);
      dragPlaylistId = row.dataset.playlistId;
      e.target.style.opacity = '0.4';
    });

    app.addEventListener('dragover', (e) => {
      e.preventDefault();
      const row = e.target.closest('[draggable]');
      if (row) {
        document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
        row.classList.add('drag-over');
      }
    });

    app.addEventListener('drop', (e) => {
      e.preventDefault();
      document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
      const row = e.target.closest('[draggable]');
      if (!row || dragFromIndex === null) return;
      const toIndex = parseInt(row.dataset.index);
      if (dragFromIndex !== toIndex) {
        sendAction('song-reorder', {
          playlistId: dragPlaylistId,
          fromIndex: dragFromIndex,
          toIndex,
        });
      }
      dragFromIndex = null;
      dragPlaylistId = null;
    });

    app.addEventListener('dragend', (e) => {
      e.target.style.opacity = '1';
      document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
      dragFromIndex = null;
    });
  </script>
</body>
</html>`

