export type DatasetStats = {
  name: string
  values: number[]
  count: number
  mean: number
  median: number
  mode: number[]
  stdDev: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
}

const sortAsc = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const computeMean = (values: number[]): number =>
  values.reduce((sum, v) => sum + v, 0) / values.length

const computeMedian = (sorted: number[]): number => {
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid]
}

const computeMode = (values: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of values) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return []
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return modes.sort((a, b) => a - b)
}

const computeQuartile = (sorted: number[], q: 0.25 | 0.75): number => {
  const pos = q * (sorted.length - 1)
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sorted[lo]
  return sorted[lo] + (pos - lo) * (sorted[hi] - sorted[lo])
}

const computeVariance = (values: number[], mean: number): number =>
  values.reduce((sum, v) => sum + (v - mean) ** 2, 0) / values.length

export const parseInput = (raw: string): number[] => {
  const trimmed = raw.trim()
  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    return parsed.map(Number).filter((n) => !Number.isNaN(n))
  }
  return trimmed
    .split(',')
    .map((s) => Number(s.trim()))
    .filter((n) => !Number.isNaN(n) && s(s => s.trim() !== ''))
}

export const computeStats = (name: string, values: number[]): DatasetStats => {
  if (values.length === 0) {
    throw new Error('Dataset must contain at least one numeric value')
  }
  const sorted = sortAsc(values)
  const mean = computeMean(sorted)
  const variance = computeVariance(sorted, mean)
  const q1 = computeQuartile(sorted, 0.25)
  const q3 = computeQuartile(sorted, 0.75)

  return {
    name,
    values: sorted,
    count: sorted.length,
    mean,
    median: computeMedian(sorted),
    mode: computeMode(sorted),
    stdDev: Math.sqrt(variance),
    variance,
    min: sorted[0],
    max: sorted[sorted.length - 1],
    range: sorted[sorted.length - 1] - sorted[0],
    q1,
    q3,
    iqr: q3 - q1,
  }
}

