import { h, Fragment } from 'plaited'
import type { DatasetStats } from './stats.ts'

const COLORS = ['#4e79a7', '#f28e2b', '#e15759', '#76b7b2', '#59a14f', '#edc948', '#b07aa1', '#ff9da7']

const colorFor = (i: number): string => COLORS[i % COLORS.length]

const round = (n: number, decimals = 4): string => {
  const factor = 10 ** decimals
  return String(Math.round(n * factor) / factor)
}

const STAT_LABELS: { key: keyof DatasetStats; label: string }[] = [
  { key: 'count', label: 'Count' },
  { key: 'mean', label: 'Mean' },
  { key: 'median', label: 'Median' },
  { key: 'mode', label: 'Mode' },
  { key: 'stdDev', label: 'Std Dev' },
  { key: 'variance', label: 'Variance' },
  { key: 'min', label: 'Min' },
  { key: 'max', label: 'Max' },
  { key: 'range', label: 'Range' },
  { key: 'q1', label: 'Q1' },
  { key: 'q3', label: 'Q3' },
  { key: 'iqr', label: 'IQR' },
]

const formatStatValue = (stat: DatasetStats, key: keyof DatasetStats): string => {
  const val = stat[key]
  if (key === 'mode') {
    const modes = val as number[]
    return modes.length === 0 ? 'None' : modes.map((m) => round(m)).join(', ')
  }
  if (key === 'values' || key === 'name') return String(val)
  return round(val as number)
}

// --- Summary Table ---

export const renderSummaryTable = (datasets: DatasetStats[]) => {
  const headerCells = [
    h('th', { style: { padding: '8px 12px', borderBottom: '2px solid #ccc', textAlign: 'left' as const } }, 'Statistic'),
    ...datasets.map((ds, i) =>
      h('th', {
        style: {
          padding: '8px 12px',
          borderBottom: `2px solid ${colorFor(i)}`,
          textAlign: 'right' as const,
          color: colorFor(i),
        },
      }, ds.name),
    ),
  ]

  const rows = STAT_LABELS.map(({ key, label }, rowIdx) =>
    h('tr', {
      style: { backgroundColor: rowIdx % 2 === 0 ? '#f9f9f9' : '#fff' },
    },
      h('td', { style: { padding: '6px 12px', fontWeight: 'bold' } }, label),
      ...datasets.map((ds) =>
        h('td', { style: { padding: '6px 12px', textAlign: 'right' as const, fontVariantNumeric: 'tabular-nums' } },
          formatStatValue(ds, key),
        ),
      ),
    ),
  )

  return h('table', {
    style: {
      width: '100%',
      borderCollapse: 'collapse' as const,
      fontFamily: 'system-ui, sans-serif',
      fontSize: '14px',
      marginBottom: '24px',
    },
  },
    h('thead', {}, h('tr', {}, ...headerCells)),
    h('tbody', {}, ...rows),
  )
}

// --- Box Plot (SVG) ---

const BOX_PLOT = { width: 600, height: 120, padX: 60, padY: 20, boxH: 40 }

const renderSingleBoxPlot = (
  ds: DatasetStats,
  globalMin: number,
  globalMax: number,
  yOffset: number,
  color: string,
) => {
  const { padX, width } = BOX_PLOT
  const plotW = width - padX * 2
  const scale = (v: number) => padX + ((v - globalMin) / (globalMax - globalMin || 1)) * plotW

  const x1 = scale(ds.min)
  const xQ1 = scale(ds.q1)
  const xMed = scale(ds.median)
  const xQ3 = scale(ds.q3)
  const x2 = scale(ds.max)
  const cy = yOffset + BOX_PLOT.boxH / 2

  const whiskerH = BOX_PLOT.boxH * 0.4

  // Detect outliers (beyond 1.5*IQR from quartiles)
  const lowerFence = ds.q1 - 1.5 * ds.iqr
  const upperFence = ds.q3 + 1.5 * ds.iqr
  const outliers = ds.values.filter((v) => v < lowerFence || v > upperFence)
  const whiskerMin = Math.max(ds.min, lowerFence)
  const whiskerMax = Math.min(ds.max, upperFence)
  const xWMin = scale(whiskerMin)
  const xWMax = scale(whiskerMax)

  return h(Fragment, {},
    // Dataset label
    h('text', {
      x: String(padX - 8),
      y: String(cy + 4),
      'text-anchor': 'end',
      'font-size': '12',
      fill: color,
    }, ds.name),
    // Left whisker line
    h('line', { x1: String(xWMin), y1: String(cy), x2: String(xQ1), y2: String(cy), stroke: color, 'stroke-width': '2' }),
    // Left whisker cap
    h('line', { x1: String(xWMin), y1: String(cy - whiskerH / 2), x2: String(xWMin), y2: String(cy + whiskerH / 2), stroke: color, 'stroke-width': '2' }),
    // Box
    h('rect', {
      x: String(xQ1),
      y: String(yOffset),
      width: String(xQ3 - xQ1),
      height: String(BOX_PLOT.boxH),
      fill: `${color}33`,
      stroke: color,
      'stroke-width': '2',
    }),
    // Median line
    h('line', { x1: String(xMed), y1: String(yOffset), x2: String(xMed), y2: String(yOffset + BOX_PLOT.boxH), stroke: color, 'stroke-width': '3' }),
    // Right whisker line
    h('line', { x1: String(xQ3), y1: String(cy), x2: String(xWMax), y2: String(cy), stroke: color, 'stroke-width': '2' }),
    // Right whisker cap
    h('line', { x1: String(xWMax), y1: String(cy - whiskerH / 2), x2: String(xWMax), y2: String(cy + whiskerH / 2), stroke: color, 'stroke-width': '2' }),
    // Outliers
    ...outliers.map((v) =>
      h('circle', { cx: String(scale(v)), cy: String(cy), r: '4', fill: 'none', stroke: color, 'stroke-width': '1.5' }),
    ),
  )
}

const renderBoxPlotAxis = (globalMin: number, globalMax: number, svgHeight: number) => {
  const { padX, width } = BOX_PLOT
  const plotW = width - padX * 2
  const y = svgHeight - 14
  const tickCount = 6
  const ticks: { val: number; x: number }[] = []
  for (let i = 0; i <= tickCount; i++) {
    const val = globalMin + (i / tickCount) * (globalMax - globalMin)
    const x = padX + (i / tickCount) * plotW
    ticks.push({ val, x })
  }
  return h(Fragment, {},
    h('line', { x1: String(padX), y1: String(y - 4), x2: String(padX + plotW), y2: String(y - 4), stroke: '#999', 'stroke-width': '1' }),
    ...ticks.map((t) =>
      h(Fragment, {},
        h('line', { x1: String(t.x), y1: String(y - 8), x2: String(t.x), y2: String(y - 2), stroke: '#999', 'stroke-width': '1' }),
        h('text', { x: String(t.x), y: String(y + 10), 'text-anchor': 'middle', 'font-size': '10', fill: '#666' }, round(t.val, 2)),
      ),
    ),
  )
}

export const renderBoxPlots = (datasets: DatasetStats[]) => {
  const allValues = datasets.flatMap((ds) => ds.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const margin = (globalMax - globalMin) * 0.05 || 1
  const plotMin = globalMin - margin
  const plotMax = globalMax + margin

  const rowHeight = BOX_PLOT.boxH + BOX_PLOT.padY
  const svgHeight = datasets.length * rowHeight + 30

  return h('div', { style: { marginBottom: '24px' } },
    h('h3', { style: { fontFamily: 'system-ui, sans-serif', marginBottom: '8px' } }, 'Box Plot'),
    h('svg', {
      viewBox: `0 0 ${BOX_PLOT.width} ${svgHeight}`,
      width: String(BOX_PLOT.width),
      height: String(svgHeight),
      style: { background: '#fff', border: '1px solid #eee', borderRadius: '4px' },
    },
      ...datasets.map((ds, i) =>
        renderSingleBoxPlot(ds, plotMin, plotMax, i * rowHeight + 10, colorFor(i)),
      ),
      renderBoxPlotAxis(plotMin, plotMax, svgHeight),
    ),
  )
}

// --- Histogram (SVG) ---

const HIST = { width: 600, height: 260, padX: 50, padTop: 20, padBot: 40 }

const computeBins = (values: number[], binCount: number) => {
  const min = Math.min(...values)
  const max = Math.max(...values)
  const binWidth = (max - min) / binCount || 1
  const bins: { lo: number; hi: number; count: number }[] = []
  for (let i = 0; i < binCount; i++) {
    bins.push({ lo: min + i * binWidth, hi: min + (i + 1) * binWidth, count: 0 })
  }
  for (const v of values) {
    let idx = Math.floor((v - min) / binWidth)
    if (idx >= binCount) idx = binCount - 1
    if (idx < 0) idx = 0
    bins[idx].count++
  }
  return bins
}

const chooseBinCount = (n: number): number => Math.max(5, Math.min(30, Math.ceil(Math.sqrt(n))))

export const renderHistograms = (datasets: DatasetStats[]) => {
  const { width, height, padX, padTop, padBot } = HIST
  const plotW = width - padX * 2
  const plotH = height - padTop - padBot

  const allBins = datasets.map((ds) => {
    const binCount = chooseBinCount(ds.count)
    return { ds, bins: computeBins(ds.values, binCount) }
  })
  const maxCount = Math.max(...allBins.flatMap((b) => b.bins.map((bin) => bin.count)))
  const globalMin = Math.min(...datasets.flatMap((ds) => ds.values))
  const globalMax = Math.max(...datasets.flatMap((ds) => ds.values))
  const dataRange = globalMax - globalMin || 1

  const scaleX = (v: number) => padX + ((v - globalMin) / dataRange) * plotW
  const scaleY = (count: number) => padTop + plotH - (count / (maxCount || 1)) * plotH

  return h('div', { style: { marginBottom: '24px' } },
    h('h3', { style: { fontFamily: 'system-ui, sans-serif', marginBottom: '8px' } }, 'Histogram'),
    h('svg', {
      viewBox: `0 0 ${width} ${height}`,
      width: String(width),
      height: String(height),
      style: { background: '#fff', border: '1px solid #eee', borderRadius: '4px' },
    },
      // Y-axis
      h('line', { x1: String(padX), y1: String(padTop), x2: String(padX), y2: String(padTop + plotH), stroke: '#999', 'stroke-width': '1' }),
      // X-axis
      h('line', { x1: String(padX), y1: String(padTop + plotH), x2: String(padX + plotW), y2: String(padTop + plotH), stroke: '#999', 'stroke-width': '1' }),
      // Y tick labels
      ...[0, 0.25, 0.5, 0.75, 1].map((frac) => {
        const val = Math.round(maxCount * frac)
        const y = scaleY(val)
        return h(Fragment, {},
          h('line', { x1: String(padX - 4), y1: String(y), x2: String(padX), y2: String(y), stroke: '#999', 'stroke-width': '1' }),
          h('text', { x: String(padX - 8), y: String(y + 4), 'text-anchor': 'end', 'font-size': '10', fill: '#666' }, String(val)),
        )
      }),
      // X tick labels
      ...[0, 0.25, 0.5, 0.75, 1].map((frac) => {
        const val = globalMin + frac * dataRange
        const x = scaleX(val)
        return h('text', { x: String(x), y: String(padTop + plotH + 16), 'text-anchor': 'middle', 'font-size': '10', fill: '#666' }, round(val, 2))
      }),
      // Bars for each dataset, stacked horizontally with slight offset
      ...allBins.flatMap(({ ds, bins }, dsIdx) =>
        bins.map((bin) => {
          const barX = scaleX(bin.lo)
          const barW = scaleX(bin.hi) - scaleX(bin.lo)
          const barH = (bin.count / (maxCount || 1)) * plotH
          const barY = padTop + plotH - barH
          return h('rect', {
            x: String(barX + dsIdx * 1),
            y: String(barY),
            width: String(Math.max(barW - datasets.length, 1)),
            height: String(barH),
            fill: `${colorFor(dsIdx)}88`,
            stroke: colorFor(dsIdx),
            'stroke-width': '1',
          })
        }),
      ),
      // Legend
      ...datasets.map((ds, i) =>
        h(Fragment, {},
          h('rect', { x: String(padX + 10 + i * 120), y: String(padTop), width: '12', height: '12', fill: `${colorFor(i)}88`, stroke: colorFor(i) }),
          h('text', { x: String(padX + 26 + i * 120), y: String(padTop + 10), 'font-size': '11', fill: '#333' }, ds.name),
        ),
      ),
    ),
  )
}

