import { createSSR } from 'plaited'
import { parseInput, computeStats } from './stats.ts'
import { renderPage } from './render.ts'
import type { DatasetStats } from './stats.ts'

const DATA_PATH = './data/datasets.json'

type StoredData = {
  datasets: Record<string, number[]>
}

const loadDatasets = async (): Promise<StoredData> => {
  try {
    const file = Bun.file(DATA_PATH)
    const text = await file.text()
    return JSON.parse(text) as StoredData
  } catch {
    return { datasets: {} }
  }
}

const saveDatasets = async (data: StoredData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

const getStatsList = (stored: StoredData): DatasetStats[] =>
  Object.entries(stored.datasets).map(([name, values]) => computeStats(name, values))

const renderHTML = (body: string): Response =>
  new Response(
    `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Statistics Calculator</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; }
    body { margin: 0; background: #fafafa; color: #222; }
  </style>
</head>
<body>${body}</body>
</html>`,
    { headers: { 'Content-Type': 'text/html; charset=utf-8' } },
  )

const handleAdd = async (req: Request): Promise<Response> => {
  const form = await req.formData()
  const name = (form.get('name') as string)?.trim()
  const rawData = (form.get('data') as string)?.trim()

  if (!name || !rawData) {
    const stored = await loadDatasets()
    const stats = getStatsList(stored)
    const ssr = createSSR()
    const body = ssr(renderPage(stats, 'Please provide both a dataset name and data.'))
    return renderHTML(body)
  }

  try {
    const values = parseInput(rawData)
    if (values.length === 0) throw new Error('No valid numbers found in input.')
    const stored = await loadDatasets()
    stored.datasets[name] = values
    await saveDatasets(stored)
    return Response.redirect('/', 303)
  } catch (err) {
    const stored = await loadDatasets()
    const stats = getStatsList(stored)
    const ssr = createSSR()
    const message = err instanceof Error ? err.message : 'Invalid input.'
    const body = ssr(renderPage(stats, message))
    return renderHTML(body)
  }
}

const handleClear = async (): Promise<Response> => {
  await saveDatasets({ datasets: {} })
  return Response.redirect('/', 303)
}

const handleRemove = async (name: string): Promise<Response> => {
  const stored = await loadDatasets()
  delete stored.datasets[name]
  await saveDatasets(stored)
  return Response.redirect('/', 303)
}

const handleIndex = async (): Promise<Response> => {
  const stored = await loadDatasets()
  const stats = getStatsList(stored)
  const ssr = createSSR()
  const body = ssr(renderPage(stats))
  return renderHTML(body)
}

export default {
  port: 3000,
  async fetch(req: Request): Promise<Response> {
    const url = new URL(req.url)

    if (req.method === 'POST' && url.pathname === '/add') {
      return handleAdd(req)
    }
    if (url.pathname === '/clear') {
      return handleClear()
    }
    if (url.pathname.startsWith('/remove/')) {
      const name = decodeURIComponent(url.pathname.slice('/remove/'.length))
      return handleRemove(name)
    }
    return handleIndex()
  },
}

{
  "name": "@node/recipe-manager",
  "version": "1.0.0",
  "modnet": {
    "contentType": "produce",
    "structure": "collection",
    "mechanics": ["sort", "filter"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import type { Recipe, RecipeInput, FilterParams } from './types'

const DATA_PATH = new URL('./data/recipes.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

const readAllRecipes = async (): Promise<Recipe[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Recipe)
}

const writeAllRecipes = async (recipes: Recipe[]): Promise<void> => {
  const content = recipes.map((r) => JSON.stringify(r)).join('\n')
  await Bun.write(DATA_PATH, content + (recipes.length > 0 ? '\n' : ''))
}

export const getRecipes = async (filters?: FilterParams): Promise<Recipe[]> => {
  let recipes = await readAllRecipes()

  if (filters?.search) {
    const query = filters.search.toLowerCase()
    recipes = recipes.filter(
      (r) =>
        r.title.toLowerCase().includes(query) ||
        r.ingredients.some((i) => i.name.toLowerCase().includes(query))
    )
  }

  if (filters?.tags && filters.tags.length > 0) {
    recipes = recipes.filter((r) =>
      filters.tags!.every((tag) => r.tags.includes(tag))
    )
  }

  return recipes.sort(
    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
  )
}

export const getRecipeById = async (id: string): Promise<Recipe | undefined> => {
  const recipes = await readAllRecipes()
  return recipes.find((r) => r.id === id)
}

export const createRecipe = async (input: RecipeInput): Promise<Recipe> => {
  const recipes = await readAllRecipes()
  const now = new Date().toISOString()
  const recipe: Recipe = {
    ...input,
    id: generateId(),
    createdAt: now,
    updatedAt: now,
  }
  recipes.push(recipe)
  await writeAllRecipes(recipes)
  return recipe
}

export const updateRecipe = async (
  id: string,
  input: Partial<RecipeInput>
): Promise<Recipe | undefined> => {
  const recipes = await readAllRecipes()
  const index = recipes.findIndex((r) => r.id === id)
  if (index === -1) return undefined
  const updated: Recipe = {
    ...recipes[index],
    ...input,
    id,
    createdAt: recipes[index].createdAt,
    updatedAt: new Date().toISOString(),
  }
  recipes[index] = updated
  await writeAllRecipes(recipes)
  return updated
}

export const deleteRecipe = async (id: string): Promise<boolean> => {
  const recipes = await readAllRecipes()
  const index = recipes.findIndex((r) => r.id === id)
  if (index === -1) return false
  recipes.splice(index, 1)
  await writeAllRecipes(recipes)
  return true
}

import type { RecipeInput, Ingredient, FilterParams } from './types'
import { getRecipes, getRecipeById, createRecipe, updateRecipe, deleteRecipe } from './data'
import { renderRecipeList, renderRecipeDetail, renderRecipeForm } from './views'

const parseIngredients = (formData: FormData): Ingredient[] => {
  const ingredients: Ingredient[] = []
  let i = 0
  while (formData.has(`ingredients[${i}].name`)) {
    const name = formData.get(`ingredients[${i}].name`) as string
    if (name.trim()) {
      ingredients.push({
        amount: parseFloat((formData.get(`ingredients[${i}].amount`) as string) || '0'),
        unit: (formData.get(`ingredients[${i}].unit`) as string) || '',
        name: name.trim(),
      })
    }
    i++
  }
  return ingredients
}

const parseSteps = (formData: FormData): string[] => {
  const steps: string[] = []
  let i = 0
  while (formData.has(`steps[${i}]`)) {
    const step = (formData.get(`steps[${i}]`) as string).trim()
    if (step) steps.push(step)
    i++
  }
  return steps
}

const parseTags = (formData: FormData): string[] => {
  return formData.getAll('tags') as string[]
}

const parseRecipeInput = (formData: FormData): RecipeInput => ({
  title: (formData.get('title') as string).trim(),
  ingredients: parseIngredients(formData),
  steps: parseSteps(formData),
  tags: parseTags(formData),
  prepTime: parseInt((formData.get('prepTime') as string) || '0', 10),
  cookTime: parseInt((formData.get('cookTime') as string) || '0', 10),
})

const htmlResponse = (body: string, status = 200): Response =>
  new Response(
    `<!DOCTYPE html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Recipe Manager</title><style>*{box-sizing:border-box}body{margin:0}</style></head><body>${body}</body></html>`,
    {
      status,
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    }
  )

const redirect = (location: string): Response =>
  new Response(null, { status: 302, headers: { Location: location } })

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // API routes (JSON)
  if (path.startsWith('/api/recipes')) {
    return handleApiRequest(req, url, path, method)
  }

  // HTML routes
  if (path === '/' || path === '/recipes') {
    if (method === 'GET') {
      const filters: FilterParams = {
        search: url.searchParams.get('search') || undefined,
        tags: url.searchParams.getAll('tags').filter(Boolean),
      }
      const recipes = await getRecipes(filters)
      return htmlResponse(renderRecipeList(recipes, filters))
    }
    if (method === 'POST') {
      const formData = await req.formData()
      const input = parseRecipeInput(formData)
      await createRecipe(input)
      return redirect('/recipes')
    }
  }

  if (path === '/recipes/new' && method === 'GET') {
    return htmlResponse(renderRecipeForm())
  }

  const recipeIdMatch = path.match(/^\/recipes\/([^/]+)$/)
  if (recipeIdMatch) {
    const id = recipeIdMatch[1]

    if (method === 'GET') {
      const recipe = await getRecipeById(id)
      if (!recipe) return htmlResponse('<p>Recipe not found</p>', 404)
      return htmlResponse(renderRecipeDetail(recipe))
    }

    if (method === 'POST') {
      const formData = await req.formData()
      const methodOverride = formData.get('_method') as string
      if (methodOverride === 'PUT') {
        const input = parseRecipeInput(formData)
        const updated = await updateRecipe(id, input)
        if (!updated) return htmlResponse('<p>Recipe not found</p>', 404)
        return redirect(`/recipes/${id}`)
      }
      if (methodOverride === 'DELETE') {
        await deleteRecipe(id)
        return redirect('/recipes')
      }
    }

    if (method === 'DELETE') {
      const deleted = await deleteRecipe(id)
      if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
      return redirect('/recipes')
    }
  }

  const editMatch = path.match(/^\/recipes\/([^/]+)\/edit$/)
  if (editMatch && method === 'GET') {
    const recipe = await getRecipeById(editMatch[1])
    if (!recipe) return htmlResponse('<p>Recipe not found</p>', 404)
    return htmlResponse(renderRecipeForm(recipe))
  }

  return htmlResponse('<p>Not found</p>', 404)
}

const handleApiRequest = async (
  req: Request,
  url: URL,
  path: string,
  method: string
): Promise<Response> => {
  if (path === '/api/recipes') {
    if (method === 'GET') {
      const filters: FilterParams = {
        search: url.searchParams.get('search') || undefined,
        tags: url.searchParams.getAll('tags').filter(Boolean),
      }
      const recipes = await getRecipes(filters)
      return jsonResponse(recipes)
    }
    if (method === 'POST') {
      const body = (await req.json()) as RecipeInput
      const recipe = await createRecipe(body)
      return jsonResponse(recipe, 201)
    }
  }

  const idMatch = path.match(/^\/api\/recipes\/([^/]+)$/)
  if (idMatch) {
    const id = idMatch[1]
    if (method === 'GET') {
      const recipe = await getRecipeById(id)
      if (!recipe) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(recipe)
    }
    if (method === 'PUT') {
      const body = (await req.json()) as Partial<RecipeInput>
      const updated = await updateRecipe(id, body)
      if (!updated) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(updated)
    }
    if (method === 'DELETE') {
      const deleted = await deleteRecipe(id)
      if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ success: true })
    }
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

