import type { Habit, Completion, HabitStore } from './types'

const HABITS_PATH = './data/habits.json'
const COMPLETIONS_PATH = './data/completions.json'

const readJSON = async <T>(path: string, fallback: T): Promise<T> => {
  const file = Bun.file(path)
  if (await file.exists()) {
    return file.json() as Promise<T>
  }
  return fallback
}

const writeJSON = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2))
}

export const loadStore = async (): Promise<HabitStore> => {
  const [habits, completions] = await Promise.all([
    readJSON<Habit[]>(HABITS_PATH, []),
    readJSON<Completion[]>(COMPLETIONS_PATH, []),
  ])
  return { habits, completions }
}

export const saveHabits = async (habits: Habit[]): Promise<void> => {
  await writeJSON(HABITS_PATH, habits)
}

export const saveCompletions = async (completions: Completion[]): Promise<void> => {
  await writeJSON(COMPLETIONS_PATH, completions)
}

import type { Habit, Completion, Frequency, TodayHabitView, WeeklyHabitView, DayStatus } from './types'
import { loadStore, saveHabits, saveCompletions } from './store'

const generateId = (): string => crypto.randomUUID()

const toDateString = (d: Date): string => d.toISOString().slice(0, 10)

const getToday = (): string => toDateString(new Date())

const getWeekDates = (): string[] => {
  const today = new Date()
  const dayOfWeek = today.getDay()
  const monday = new Date(today)
  monday.setDate(today.getDate() - ((dayOfWeek + 6) % 7))
  return Array.from({ length: 7 }, (_, i) => {
    const d = new Date(monday)
    d.setDate(monday.getDate() + i)
    return toDateString(d)
  })
}

const DAY_LABELS = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']

export const addHabit = async (name: string, frequency: Frequency): Promise<Habit> => {
  const store = await loadStore()
  const habit: Habit = {
    id: generateId(),
    name,
    frequency,
    createdAt: new Date().toISOString(),
  }
  store.habits.push(habit)
  await saveHabits(store.habits)
  return habit
}

export const removeHabit = async (habitId: string): Promise<void> => {
  const store = await loadStore()
  const habits = store.habits.filter((h) => h.id !== habitId)
  const completions = store.completions.filter((c) => c.habitId !== habitId)
  await Promise.all([saveHabits(habits), saveCompletions(completions)])
}

export const toggleCompletion = async (habitId: string, date?: string): Promise<boolean> => {
  const store = await loadStore()
  const targetDate = date ?? getToday()
  const existing = store.completions.findIndex(
    (c) => c.habitId === habitId && c.date === targetDate,
  )
  if (existing >= 0) {
    store.completions.splice(existing, 1)
    await saveCompletions(store.completions)
    return false
  }
  store.completions.push({ habitId, date: targetDate })
  await saveCompletions(store.completions)
  return true
}

export const getTodayView = async (): Promise<TodayHabitView[]> => {
  const store = await loadStore()
  const today = getToday()
  return store.habits.map((habit) => ({
    habit,
    completed: store.completions.some(
      (c) => c.habitId === habit.id && c.date === today,
    ),
  }))
}

export const getWeeklyView = async (): Promise<{ habits: WeeklyHabitView[]; overallRate: number }> => {
  const store = await loadStore()
  const weekDates = getWeekDates()
  const today = getToday()

  const habitViews: WeeklyHabitView[] = store.habits.map((habit) => {
    const days: DayStatus[] = weekDates.map((date, i) => ({
      date,
      dayLabel: DAY_LABELS[i],
      completed: store.completions.some(
        (c) => c.habitId === habit.id && c.date === date,
      ),
    }))

    const relevantDays = habit.frequency === 'daily'
      ? days.filter((d) => d.date <= today)
      : days

    const completedCount = relevantDays.filter((d) => d.completed).length
    const totalExpected = habit.frequency === 'daily'
      ? relevantDays.length
      : 1
    const completionRate = totalExpected > 0
      ? Math.round((completedCount / totalExpected) * 100)
      : 0

    return { habit, days, completionRate }
  })

  const totalRate = habitViews.length > 0
    ? Math.round(habitViews.reduce((sum, h) => sum + h.completionRate, 0) / habitViews.length)
    : 0

  return { habits: habitViews, overallRate: totalRate }
}

