import type { View, Frequency } from './types'
import { addHabit, removeHabit, toggleCompletion, getTodayView, getWeeklyView } from './habits'
import { renderToHTML } from './render'

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const method = req.method

  if (method === 'POST' && url.pathname === '/habits') {
    const body = await req.json() as { name: string; frequency: Frequency }
    const habit = await addHabit(body.name, body.frequency)
    return Response.json(habit, { status: 201 })
  }

  if (method === 'DELETE' && url.pathname.startsWith('/habits/')) {
    const habitId = url.pathname.slice('/habits/'.length)
    await removeHabit(habitId)
    return new Response(null, { status: 204 })
  }

  if (method === 'POST' && url.pathname === '/toggle') {
    const body = await req.json() as { habitId: string; date?: string }
    const completed = await toggleCompletion(body.habitId, body.date)
    return Response.json({ completed })
  }

  if (method === 'GET' && url.pathname === '/api/today') {
    const items = await getTodayView()
    return Response.json(items)
  }

  if (method === 'GET' && url.pathname === '/api/weekly') {
    const data = await getWeeklyView()
    return Response.json(data)
  }

  const view: View = url.searchParams.get('view') === 'weekly' ? 'weekly' : 'today'
  const [todayItems, weeklyData] = await Promise.all([getTodayView(), getWeeklyView()])
  const html = renderToHTML(view, todayItems, weeklyData)

  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

export default {
  port: 3000,
  fetch: handleRequest,
}

