import type { Holding } from './types'

const HOLDINGS_PATH = './data/holdings.json'

export const loadHoldings = async (): Promise<Holding[]> => {
  const file = Bun.file(HOLDINGS_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as Holding[]
}

export const saveHoldings = async (holdings: Holding[]): Promise<void> => {
  await Bun.write(HOLDINGS_PATH, JSON.stringify(holdings, null, 2))
}

export const addHolding = async (symbol: string, amount: number, purchasePrice: number): Promise<Holding> => {
  const holdings = await loadHoldings()
  const id = crypto.randomUUID()
  const holding: Holding = {
    id,
    symbol: symbol.toUpperCase(),
    amount,
    purchasePrice,
  }
  holdings.push(holding)
  await saveHoldings(holdings)
  return holding
}

export const removeHolding = async (id: string): Promise<boolean> => {
  const holdings = await loadHoldings()
  const idx = holdings.findIndex((h) => h.id === id)
  if (idx === -1) return false
  holdings.splice(idx, 1)
  await saveHoldings(holdings)
  return true
}

export const updateHolding = async (
  id: string,
  updates: Partial<Pick<Holding, 'amount' | 'purchasePrice'>>
): Promise<Holding | null> => {
  const holdings = await loadHoldings()
  const holding = holdings.find((h) => h.id === id)
  if (!holding) return null
  if (updates.amount !== undefined) holding.amount = updates.amount
  if (updates.purchasePrice !== undefined) holding.purchasePrice = updates.purchasePrice
  await saveHoldings(holdings)
  return holding
}

import type { PriceMap } from './types'

const PRICES_PATH = './data/prices.json'

export const loadPrices = async (): Promise<PriceMap> => {
  const file = Bun.file(PRICES_PATH)
  if (!(await file.exists())) return {}
  const text = await file.text()
  return JSON.parse(text) as PriceMap
}

export const savePrices = async (prices: PriceMap): Promise<void> => {
  await Bun.write(PRICES_PATH, JSON.stringify(prices, null, 2))
}

export const updatePrice = async (symbol: string, price: number): Promise<void> => {
  const prices = await loadPrices()
  prices[symbol.toUpperCase()] = price
  await savePrices(prices)
}

export const getPrice = async (symbol: string): Promise<number | null> => {
  const prices = await loadPrices()
  return prices[symbol.toUpperCase()] ?? null
}

export const updatePricesBulk = async (updates: Record<string, number>): Promise<void> => {
  const prices = await loadPrices()
  for (const [symbol, price] of Object.entries(updates)) {
    prices[symbol.toUpperCase()] = price
  }
  await savePrices(prices)
}

import { loadHoldings } from './holdings'
import { loadPrices } from './prices'
import type { PortfolioEntry, PortfolioSummary } from './types'

export const getPortfolioSummary = async (): Promise<PortfolioSummary> => {
  const holdings = await loadHoldings()
  const prices = await loadPrices()

  const entries: PortfolioEntry[] = holdings.map((holding) => {
    const currentPrice = prices[holding.symbol] ?? holding.purchasePrice
    const currentValue = holding.amount * currentPrice
    const costBasis = holding.amount * holding.purchasePrice
    const gainLoss = currentValue - costBasis
    const gainLossPercent = costBasis > 0 ? (gainLoss / costBasis) * 100 : 0

    return {
      holding,
      currentPrice,
      currentValue,
      costBasis,
      gainLoss,
      gainLossPercent,
      allocationPercent: 0,
    }
  })

  const totalValue = entries.reduce((sum, e) => sum + e.currentValue, 0)
  const totalCost = entries.reduce((sum, e) => sum + e.costBasis, 0)
  const totalGainLoss = totalValue - totalCost
  const totalGainLossPercent = totalCost > 0 ? (totalGainLoss / totalCost) * 100 : 0

  for (const entry of entries) {
    entry.allocationPercent = totalValue > 0 ? (entry.currentValue / totalValue) * 100 : 0
  }

  return {
    entries,
    totalValue,
    totalCost,
    totalGainLoss,
    totalGainLossPercent,
  }
}

import { addHolding, removeHolding, updateHolding, loadHoldings } from './holdings'
import { updatePrice, updatePricesBulk } from './prices'
import { getPortfolioSummary } from './portfolio'
import { renderPortfolio, renderAddForm, renderUpdatePriceForm } from './ui'

type RouteAction =
  | 'view'
  | 'add-form'
  | 'add'
  | 'remove'
  | 'update-holding'
  | 'update-price'
  | 'update-prices-form'
  | 'update-prices'

type RequestParams = {
  action: RouteAction
  symbol?: string
  amount?: number
  purchasePrice?: number
  id?: string
  price?: number
  prices?: Record<string, number>
}

export const handleRequest = async (params: RequestParams): Promise<string> => {
  const { action } = params

  switch (action) {
    case 'view': {
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }

    case 'add-form': {
      return renderAddForm()
    }

    case 'add': {
      const { symbol, amount, purchasePrice } = params
      if (!symbol || amount === undefined || purchasePrice === undefined) {
        return '<div style="color:#ef4444">Missing required fields: symbol, amount, purchasePrice</div>'
      }
      if (amount <= 0 || purchasePrice <= 0) {
        return '<div style="color:#ef4444">Amount and purchase price must be positive</div>'
      }
      const holding = await addHolding(symbol, amount, purchasePrice)
      await updatePrice(symbol, purchasePrice)
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }

    case 'remove': {
      const { id } = params
      if (!id) {
        return '<div style="color:#ef4444">Missing required field: id</div>'
      }
      const removed = await removeHolding(id)
      if (!removed) {
        return '<div style="color:#ef4444">Holding not found</div>'
      }
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }

    case 'update-holding': {
      const { id, amount, purchasePrice } = params
      if (!id) {
        return '<div style="color:#ef4444">Missing required field: id</div>'
      }
      const updated = await updateHolding(id, { amount, purchasePrice })
      if (!updated) {
        return '<div style="color:#ef4444">Holding not found</div>'
      }
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }

    case 'update-price': {
      const { symbol, price } = params
      if (!symbol || price === undefined) {
        return '<div style="color:#ef4444">Missing required fields: symbol, price</div>'
      }
      if (price <= 0) {
        return '<div style="color:#ef4444">Price must be positive</div>'
      }
      await updatePrice(symbol, price)
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }

    case 'update-prices-form': {
      const holdings = await loadHoldings()
      const symbols = [...new Set(holdings.map((h) => h.symbol))]
      return renderUpdatePriceForm(symbols)
    }

    case 'update-prices': {
      const { prices } = params
      if (!prices || Object.keys(prices).length === 0) {
        return '<div style="color:#ef4444">No prices provided</div>'
      }
      const validPrices: Record<string, number> = {}
      for (const [sym, val] of Object.entries(prices)) {
        if (val > 0) validPrices[sym] = val
      }
      if (Object.keys(validPrices).length > 0) {
        await updatePricesBulk(validPrices)
      }
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }

    default: {
      const summary = await getPortfolioSummary()
      return renderPortfolio(summary)
    }
  }
}

