export type Snippet = {
  id: string
  title: string
  language: string
  tags: string[]
  code: string
  createdAt: string
}

export type SnippetInput = {
  title: string
  language: string
  tags: string[]
  code: string
}

export type FilterParams = {
  language?: string
  tag?: string
}

import type { Snippet, SnippetInput, FilterParams } from './types'

const DATA_PATH = `${import.meta.dir}/data/snippets.json`

const readSnippets = async (): Promise<Snippet[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeSnippets = async (snippets: Snippet[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(snippets, null, 2))
}

export const addSnippet = async (input: SnippetInput): Promise<Snippet> => {
  const snippets = await readSnippets()
  const snippet: Snippet = {
    id: crypto.randomUUID(),
    title: input.title.trim(),
    language: input.language.trim().toLowerCase(),
    tags: input.tags.map((t) => t.trim().toLowerCase()).filter(Boolean),
    code: input.code,
    createdAt: new Date().toISOString(),
  }
  snippets.unshift(snippet)
  await writeSnippets(snippets)
  return snippet
}

export const deleteSnippet = async (id: string): Promise<boolean> => {
  const snippets = await readSnippets()
  const idx = snippets.findIndex((s) => s.id === id)
  if (idx === -1) return false
  snippets.splice(idx, 1)
  await writeSnippets(snippets)
  return true
}

export const getSnippets = async (filters?: FilterParams): Promise<Snippet[]> => {
  let snippets = await readSnippets()
  if (filters?.language) {
    const lang = filters.language.toLowerCase()
    snippets = snippets.filter((s) => s.language === lang)
  }
  if (filters?.tag) {
    const tag = filters.tag.toLowerCase()
    snippets = snippets.filter((s) => s.tags.includes(tag))
  }
  return snippets
}

export const getAllLanguages = async (): Promise<string[]> => {
  const snippets = await readSnippets()
  return [...new Set(snippets.map((s) => s.language))].sort()
}

export const getAllTags = async (): Promise<string[]> => {
  const snippets = await readSnippets()
  return [...new Set(snippets.flatMap((s) => s.tags))].sort()
}

