export const renderToHTML = (
  snippets: Snippet[],
  languages: string[],
  tags: string[],
  activeLanguage?: string,
  activeTag?: string,
): string => {
  const ssr = createSSR()
  const content = renderPage(snippets, languages, tags, activeLanguage, activeTag)
  const body = ssr(content)

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Code Snippets</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #18181b; }
    pre code { white-space: pre; }
  </style>
</head>
<body>${body}
<script>
  document.addEventListener('click', async (e) => {
    const target = e.target;
    const trigger = target.getAttribute('p-trigger');
    if (!trigger) return;
    const action = trigger.split(':')[1];

    if (action === 'copyCode') {
      const code = decodeURIComponent(target.getAttribute('data-code'));
      await navigator.clipboard.writeText(code);
      const prev = target.textContent;
      target.textContent = 'Copied!';
      setTimeout(() => { target.textContent = prev; }, 1500);
    }

    if (action === 'addSnippet') {
      const title = document.querySelector('[p-target="title"]').value;
      const language = document.querySelector('[p-target="language"]').value;
      const tagsVal = document.querySelector('[p-target="tags"]').value;
      const code = document.querySelector('[p-target="code"]').value;
      if (!title || !code) return alert('Title and code are required');
      const resp = await fetch('/api/snippets', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, language, tags: tagsVal }),
      });
      if (resp.ok) location.reload();
    }

    if (action === 'deleteSnippet') {
      const id = target.getAttribute('data-id');
      if (!confirm('Delete this snippet?')) return;
      const resp = await fetch('/api/snippets/' + id, { method: 'DELETE' });
      if (resp.ok) location.reload();
    }

    if (action === 'filterTag') {
      const tag = target.getAttribute('data-tag');
      const url = new URL(location.href);
      url.searchParams.set('tag', url.searchParams.get('tag') === tag ? '' : tag);
      location.href = url.toString();
    }

    if (action === 'clearFilters') {
      const url = new URL(location.href);
      url.searchParams.delete('language');
      url.searchParams.delete('tag');
      location.href = url.toString();
    }
  });

  document.addEventListener('change', (e) => {
    const target = e.target;
    const trigger = target.getAttribute('p-trigger');
    if (!trigger) return;
    const action = trigger.split(':')[1];

    if (action === 'filterLanguage') {
      const url = new URL(location.href);
      if (target.value) url.searchParams.set('language', target.value);
      else url.searchParams.delete('language');
      location.href = url.toString();
    }
  });
</script>
</body>
</html>`
}

import { addSnippet, deleteSnippet, getSnippets, getAllLanguages, getAllTags } from './store'
import { renderToHTML } from './render'

const PORT = Number(process.env.PORT) || 3000

const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  return JSON.parse(text)
}

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname, searchParams } = url

    // API: Create snippet
    if (pathname === '/api/snippets' && req.method === 'POST') {
      const body = await parseBody(req)
      const tags = (body.tags ?? '')
        .split(',')
        .map((t: string) => t.trim())
        .filter(Boolean)
      const snippet = await addSnippet({
        title: body.title ?? '',
        language: body.language ?? '',
        tags,
        code: body.code ?? '',
      })
      return Response.json(snippet, { status: 201 })
    }

    // API: Delete snippet
    const deleteMatch = pathname.match(/^\/api\/snippets\/(.+)$/)
    if (deleteMatch && req.method === 'DELETE') {
      const ok = await deleteSnippet(deleteMatch[1])
      return ok
        ? new Response(null, { status: 204 })
        : Response.json({ error: 'Not found' }, { status: 404 })
    }

    // API: List snippets (JSON)
    if (pathname === '/api/snippets' && req.method === 'GET') {
      const language = searchParams.get('language') || undefined
      const tag = searchParams.get('tag') || undefined
      const snippets = await getSnippets({ language, tag })
      return Response.json(snippets)
    }

    // HTML page
    if (pathname === '/' || pathname === '/index.html') {
      const language = searchParams.get('language') || undefined
      const tag = searchParams.get('tag') || undefined
      const [snippets, languages, tags] = await Promise.all([
        getSnippets({ language, tag }),
        getAllLanguages(),
        getAllTags(),
      ])
      const html = renderToHTML(snippets, languages, tags, language, tag)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Code Snippets server running at http://localhost:${server.port}`)

