import type { Quiz } from './types'

const DATA_PATH = `${import.meta.dir}/data/quizzes.json`

const loadQuizzes = async (): Promise<Quiz[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return JSON.parse(text) as Quiz[]
}

const saveQuizzes = async (quizzes: Quiz[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(quizzes, null, 2))
}

export const getAllQuizzes = async (): Promise<Quiz[]> => {
  return loadQuizzes()
}

export const getQuizById = async (id: string): Promise<Quiz | undefined> => {
  const quizzes = await loadQuizzes()
  return quizzes.find((q) => q.id === id)
}

export const createQuiz = async (quiz: Quiz): Promise<Quiz> => {
  const quizzes = await loadQuizzes()
  quizzes.push(quiz)
  await saveQuizzes(quizzes)
  return quiz
}

export const deleteQuiz = async (id: string): Promise<boolean> => {
  const quizzes = await loadQuizzes()
  const idx = quizzes.findIndex((q) => q.id === id)
  if (idx === -1) return false
  quizzes.splice(idx, 1)
  await saveQuizzes(quizzes)
  return true
}

