    border: `6px solid ${pct >= 70 ? '#16a34a' : pct >= 40 ? '#eab308' : '#dc2626'}`,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '32px',
    fontWeight: '700',
    color: pct >= 70 ? '#16a34a' : pct >= 40 ? '#eab308' : '#dc2626',
    margin: '0 auto 20px',
  }),
}

const layout = (title: string, ...children: unknown[]) =>
  h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, title),
    ),
    h('body', { style: styles.page }, ...children),
  )

export const renderQuizList = (quizzes: Quiz[]): string => {
  const { body } = createSSR()
  const content = layout('Quiz Builder',
    h('h1', { style: styles.heading }, 'Quiz Builder'),
    h('div', { style: styles.flex },
      h('a', { href: '/create', style: styles.btn }, '+ New Quiz'),
    ),
    h('div', { style: styles.spacer },
      quizzes.length === 0
        ? h('p', { style: styles.muted }, 'No quizzes yet. Create one to get started!')
        : h(Fragment, {},
            ...quizzes.map((quiz) =>
              h('div', { style: styles.card },
                h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
                  h('div', {},
                    h('h3', { style: { margin: '0 0 4px', fontSize: '16px' } }, quiz.title),
