    error ? h('div', { style: { ...styles.incorrect, marginBottom: '16px' } }, error) : null,
    h('form', { method: 'POST', action: '/quizzes' },
      h('label', { style: styles.label }, 'Quiz Title'),
      h('input', { type: 'text', name: 'title', required: true, style: styles.input, placeholder: 'Enter quiz title...' }),
      h('div', { style: { display: 'flex', gap: '12px', alignItems: 'center', margin: '12px 0' } },
        h('span', { style: { fontSize: '14px', fontWeight: '600' } }, `Questions: ${count}`),
