export const renderTakeQuestion = (quiz: Quiz, questionIndex: number, selectedAnswers: Record<string, string>): string => {
  const { body } = createSSR()
  const question = quiz.questions[questionIndex]
  const total = quiz.questions.length
  const progress = ((questionIndex) / total) * 100
  const isLast = questionIndex === total - 1
  const previousAnswer = selectedAnswers[question.id]

  const content = layout(`${quiz.title} — Question ${questionIndex + 1}`,
    h('a', { href: '/', style: { ...styles.btnSecondary, marginBottom: '16px', display: 'inline-block' } }, 'Back to quizzes'),
    h('h1', { style: styles.heading }, quiz.title),
    h('div', { style: styles.progressBar },
      h('div', { style: styles.progressFill(progress) }),
    ),
    h('p', { style: styles.muted }, `Question ${questionIndex + 1} of ${total}`),
    h('form', { method: 'POST', action: `/quizzes/${quiz.id}/answer` },
      h('input', { type: 'hidden', name: 'questionIndex', value: String(questionIndex) }),
      h('input', { type: 'hidden', name: 'answers', value: JSON.stringify(selectedAnswers) }),
      h('div', { style: styles.card },
        h('h2', { style: { fontSize: '18px', marginBottom: '16px' } }, question.text),
        h('div', { style: styles.radioGroup },
          ...question.options.map((opt) =>
            h('label', { style: styles.radioOption },
              h('input', {
                type: 'radio',
                name: 'selected',
                value: opt.label,
                required: true,
                ...(previousAnswer === opt.label ? { checked: true } : {}),
              }),
              h('span', {}, `${opt.label}. ${opt.text}`),
            ),
          ),
        ),
      ),
      h('div', { style: { ...styles.flex, ...styles.spacer } },
        questionIndex > 0
          ? h('a', {
              href: `/quizzes/${quiz.id}/take?q=${questionIndex - 1}&answers=${encodeURIComponent(JSON.stringify(selectedAnswers))}`,
              style: styles.btnSecondary,
            }, 'Previous')
          : null,
        h('button', { type: 'submit', style: styles.btn }, isLast ? 'Finish & See Results' : 'Next'),
      ),
    ),
  )
  return body(content)
}

export const renderScore = (result: ScoreResult): string => {
  const { body } = createSSR()
  const content = layout(`Results — ${result.quizTitle}`,
    h('a', { href: '/', style: { ...styles.btnSecondary, marginBottom: '16px', display: 'inline-block' } }, 'Back to quizzes'),
    h('h1', { style: { ...styles.heading, textAlign: 'center' } }, 'Quiz Results'),
    h('h2', { style: { ...styles.subheading, textAlign: 'center', color: '#6b7280' } }, result.quizTitle),
    h('div', { style: styles.scoreCircle(result.percentage) },
      `${result.correctCount}/${result.totalQuestions}`,
    ),
    h('p', { style: { textAlign: 'center', fontSize: '16px', marginBottom: '24px' } },
      `You scored ${result.percentage}%`,
    ),
    h('h3', { style: styles.subheading }, 'Question Breakdown'),
    ...result.breakdown.map((qr, i) =>
      h('div', { style: qr.isCorrect ? styles.correct : styles.incorrect },
        h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
          h('strong', {}, `${i + 1}. ${qr.questionText}`),
          h('span', { style: { fontWeight: '700', fontSize: '18px' } }, qr.isCorrect ? 'Correct' : 'Wrong'),
        ),
        h('div', { style: { marginTop: '6px', fontSize: '14px' } },
          qr.isCorrect
            ? h('span', {}, `Your answer: ${qr.selectedLabel}. ${qr.selectedText}`)
            : h(Fragment, {},
                h('div', {}, `Your answer: ${qr.selectedLabel}. ${qr.selectedText}`),
                h('div', { style: { color: '#16a34a', fontWeight: '500' } }, `Correct answer: ${qr.correctLabel}. ${qr.correctText}`),
              ),
        ),
      ),
    ),
    h('div', { style: { ...styles.spacer, textAlign: 'center' } },
      h('a', { href: '/', style: styles.btn }, 'Back to Quizzes'),
    ),
  )
  return body(content)
}

import type { Quiz, Question, Option, ScoreResult, QuestionResult } from './types'
import { getAllQuizzes, getQuizById, createQuiz, deleteQuiz } from './store'
import { renderQuizList, renderCreateForm, renderTakeQuestion, renderScore } from './render'

const html = (body: string, status = 200) =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (url: string) =>
  new Response(null, { status: 302, headers: { Location: url } })

const generateId = () => crypto.randomUUID().slice(0, 8)

const parseFormData = async (req: Request) => {
  const formData = await req.formData()
  const get = (key: string) => formData.get(key)?.toString() ?? ''
  return { formData, get }
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // GET / — quiz list
  if (method === 'GET' && path === '/') {
    const quizzes = await getAllQuizzes()
    return html(renderQuizList(quizzes))
  }

  // GET /create — show create form
  if (method === 'GET' && path === '/create') {
    const questionCount = parseInt(url.searchParams.get('questions') ?? '3', 10)
    return html(renderCreateForm(undefined, questionCount))
  }

  // POST /quizzes — create a quiz
  if (method === 'POST' && path === '/quizzes') {
    const { get, formData } = await parseFormData(req)
    const title = get('title').trim()
    const questionCount = parseInt(get('questionCount') || '3', 10)

    if (!title) {
      return html(renderCreateForm('Please provide a quiz title.', questionCount), 400)
    }

    const questions: Question[] = []
    for (let i = 0; i < questionCount; i++) {
      const text = get(`q_${i}_text`).trim()
      const correctLabel = get(`q_${i}_correct`)
      if (!text || !correctLabel) {
        return html(renderCreateForm(`Question ${i + 1} is incomplete.`, questionCount), 400)
      }
      const options: Option[] = ['A', 'B', 'C', 'D'].map((label) => ({
        label,
        text: get(`q_${i}_option_${label}`).trim(),
      }))
      if (options.some((o) => !o.text)) {
        return html(renderCreateForm(`Question ${i + 1} has empty options.`, questionCount), 400)
      }
      questions.push({ id: generateId(), text, options, correctLabel })
    }

    const quiz: Quiz = {
      id: generateId(),
      title,
      questions,
      createdAt: new Date().toISOString(),
    }
    await createQuiz(quiz)
    return redirect('/')
  }

  // POST /quizzes/:id/delete — delete a quiz
  const deleteMatch = path.match(/^\/quizzes\/([^/]+)\/delete$/)
  if (method === 'POST' && deleteMatch) {
    await deleteQuiz(deleteMatch[1])
    return redirect('/')
  }

  // GET /quizzes/:id/take — take quiz (question by question)
  const takeMatch = path.match(/^\/quizzes\/([^/]+)\/take$/)
  if (method === 'GET' && takeMatch) {
    const quiz = await getQuizById(takeMatch[1])
    if (!quiz) return html('<p>Quiz not found.</p>', 404)
    const qIndex = parseInt(url.searchParams.get('q') ?? '0', 10)
    const answersParam = url.searchParams.get('answers')
    const answers: Record<string, string> = answersParam ? JSON.parse(decodeURIComponent(answersParam)) : {}
    const clampedIndex = Math.max(0, Math.min(qIndex, quiz.questions.length - 1))
    return html(renderTakeQuestion(quiz, clampedIndex, answers))
  }

  // POST /quizzes/:id/answer — handle answer submission, advance or score
  const answerMatch = path.match(/^\/quizzes\/([^/]+)\/answer$/)
  if (method === 'POST' && answerMatch) {
    const quiz = await getQuizById(answerMatch[1])
    if (!quiz) return html('<p>Quiz not found.</p>', 404)

    const { get } = await parseFormData(req)
    const questionIndex = parseInt(get('questionIndex'), 10)
    const selected = get('selected')
    const previousAnswers: Record<string, string> = JSON.parse(get('answers') || '{}')

    const question = quiz.questions[questionIndex]
    if (question) {
      previousAnswers[question.id] = selected
    }

    const nextIndex = questionIndex + 1
    if (nextIndex < quiz.questions.length) {
      // Go to next question
      return redirect(
        `/quizzes/${quiz.id}/take?q=${nextIndex}&answers=${encodeURIComponent(JSON.stringify(previousAnswers))}`,
      )
    }

    // Score the quiz
    const breakdown: QuestionResult[] = quiz.questions.map((q) => {
      const selectedLabel = previousAnswers[q.id] ?? ''
      const selectedOption = q.options.find((o) => o.label === selectedLabel)
      const correctOption = q.options.find((o) => o.label === q.correctLabel)!
      return {
        questionText: q.text,
        selectedLabel,
        selectedText: selectedOption?.text ?? '(no answer)',
        correctLabel: q.correctLabel,
        correctText: correctOption.text,
        isCorrect: selectedLabel === q.correctLabel,
      }
    })

    const correctCount = breakdown.filter((b) => b.isCorrect).length
    const result: ScoreResult = {
      quizTitle: quiz.title,
      totalQuestions: quiz.questions.length,
      correctCount,
      percentage: Math.round((correctCount / quiz.questions.length) * 100),
      breakdown,
    }
    return html(renderScore(result))
  }

  // GET /quizzes/:id — view quiz detail
  const viewMatch = path.match(/^\/quizzes\/([^/]+)$/)
  if (method === 'GET' && viewMatch) {
    const quiz = await getQuizById(viewMatch[1])
    if (!quiz) return html('<p>Quiz not found.</p>', 404)
    return redirect(`/quizzes/${quiz.id}/take?q=0`)
  }

  return html('<p>Not found.</p>', 404)
}

import { handleRequest } from './routes'

const PORT = parseInt(process.env.PORT ?? '3000', 10)

Bun.serve({
  port: PORT,
  fetch: handleRequest,
})

console.log(`Quiz Builder running at http://localhost:${PORT}`)
